-- ============================================================
  -- AJUDANDO AJU - Export completo para Supabase
  -- Gerado em: 2026-03-04T11:54:49.133Z
  -- Banco: PostgreSQL (Neon) → Supabase
  -- Tabelas: users, admin_users, tourist_spots, tourist_feedback,
  --          tourist_passports, badges, tourist_badges,
  --          spot_visits, tourist_routes, session
  -- ============================================================

  SET client_encoding = 'UTF8';
  SET standard_conforming_strings = on;

  CREATE EXTENSION IF NOT EXISTS "pgcrypto";

  -- ====================
  -- TABELA: users
  -- ====================
  CREATE TABLE IF NOT EXISTS users (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    username TEXT NOT NULL UNIQUE,
    password TEXT NOT NULL
  );

  -- ====================
  -- TABELA: admin_users
  -- ====================
  CREATE TABLE IF NOT EXISTS admin_users (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    last_login TEXT
  );

  -- ====================
  -- TABELA: tourist_spots
  -- ====================
  CREATE TABLE IF NOT EXISTS tourist_spots (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    name_pt TEXT NOT NULL,
    description_pt TEXT NOT NULL,
    description_pt_2 TEXT DEFAULT '',
    description_pt_3 TEXT DEFAULT '',
    name_en TEXT NOT NULL,
    description_en TEXT NOT NULL,
    description_en_2 TEXT DEFAULT '',
    description_en_3 TEXT DEFAULT '',
    name_es TEXT NOT NULL,
    description_es TEXT NOT NULL,
    description_es_2 TEXT DEFAULT '',
    description_es_3 TEXT DEFAULT '',
    category TEXT NOT NULL,
    latitude NUMERIC(10,8) NOT NULL,
    longitude NUMERIC(11,8) NOT NULL,
    address TEXT,
    images TEXT[] DEFAULT '{}',
    image_gallery JSONB DEFAULT '[]',
    cover_image TEXT,
    video_url TEXT,
    qr_code TEXT,
    google_maps_link TEXT,
    is_active BOOLEAN DEFAULT true,
    opening_hours TEXT DEFAULT '',
    is_24_hours BOOLEAN DEFAULT false,
    is_free BOOLEAN DEFAULT true,
    entry_fee TEXT DEFAULT '',
    features JSONB DEFAULT '{}',
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
  );

  -- ====================
  -- TABELA: tourist_feedback
  -- ====================
  CREATE TABLE IF NOT EXISTS tourist_feedback (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    spot_id VARCHAR NOT NULL,
    passport_id VARCHAR,
    name TEXT NOT NULL,
    birth_date TEXT NOT NULL,
    city TEXT NOT NULL,
    state TEXT NOT NULL,
    country TEXT NOT NULL,
    visit_reason TEXT NOT NULL,
    city_opinion TEXT NOT NULL,
    stay_duration TEXT NOT NULL,
    accommodation TEXT NOT NULL,
    rating NUMERIC(2,1),
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
  );

  -- ====================
  -- TABELA: tourist_passports
  -- ====================
  CREATE TABLE IF NOT EXISTS tourist_passports (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    passport_code TEXT NOT NULL UNIQUE,
    email TEXT,
    total_points NUMERIC(10,0) DEFAULT '0',
    total_visits NUMERIC(10,0) DEFAULT '0',
    level TEXT DEFAULT 'Explorador Iniciante',
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    last_visit TEXT DEFAULT CURRENT_TIMESTAMP
  );

  -- ====================
  -- TABELA: badges
  -- ====================
  CREATE TABLE IF NOT EXISTS badges (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    name_pt TEXT NOT NULL,
    name_en TEXT NOT NULL,
    name_es TEXT NOT NULL,
    description_pt TEXT NOT NULL,
    description_en TEXT NOT NULL,
    description_es TEXT NOT NULL,
    icon TEXT NOT NULL,
    category TEXT NOT NULL,
    rarity TEXT NOT NULL,
    points NUMERIC(10,0) NOT NULL,
    requirement JSONB NOT NULL,
    is_active BOOLEAN DEFAULT true
  );

  -- ====================
  -- TABELA: tourist_badges
  -- ====================
  CREATE TABLE IF NOT EXISTS tourist_badges (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    passport_id VARCHAR NOT NULL,
    badge_id VARCHAR NOT NULL,
    earned_at TEXT DEFAULT CURRENT_TIMESTAMP
  );

  -- ====================
  -- TABELA: spot_visits
  -- ====================
  CREATE TABLE IF NOT EXISTS spot_visits (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    passport_id VARCHAR NOT NULL,
    spot_id VARCHAR NOT NULL,
    visited_at TEXT DEFAULT CURRENT_TIMESTAMP,
    feedback_id VARCHAR
  );

  -- ====================
  -- TABELA: tourist_routes
  -- ====================
  CREATE TABLE IF NOT EXISTS tourist_routes (
    id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
    name_pt TEXT NOT NULL,
    name_en TEXT NOT NULL,
    name_es TEXT NOT NULL,
    description_pt TEXT NOT NULL,
    description_en TEXT NOT NULL,
    description_es TEXT NOT NULL,
    duration TEXT NOT NULL,
    difficulty TEXT NOT NULL,
    spot_ids TEXT[] NOT NULL,
    categories TEXT[] NOT NULL,
    total_distance NUMERIC(10,2),
    is_active BOOLEAN DEFAULT true,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
  );

  -- ====================
  -- TABELA: session
  -- ====================
  CREATE TABLE IF NOT EXISTS session (
    sid VARCHAR NOT NULL COLLATE "default",
    sess JSON NOT NULL,
    expire TIMESTAMP(6) NOT NULL,
    CONSTRAINT session_pkey PRIMARY KEY (sid) NOT DEFERRABLE INITIALLY IMMEDIATE
  );
  CREATE INDEX IF NOT EXISTS IDX_session_expire ON session (expire);

