  -- ====================
  -- DADOS: tourist_spots (60 registros)
  -- ====================
  INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('0bd02122-7f93-4b4d-b8c1-7cfc510d7e92','Ponte do Imperador','Emperor''s Bridge','Puente del Emperador','Construída em 1859, durante a administração do engenheiro Manuel da Cunha Galvão, a Ponte do Imperador surgiu com a finalidade de recepcionar o Imperador Dom Pedro II em sua visita à capital sergipana. Inicialmente erguida em madeira e posicionada de frente para o Palácio do Governo, a estrutura simbolizava a importância política de Aracaju no contexto do Império.
Em 1867, já bastante deteriorada, passou por reforma que lhe conferiu acabamento em ferro, reforçando sua durabilidade. Em 1904, sob o governo estadual de Josino Menezes, foi encomendada uma nova ponte metálica, executada pelo engenheiro Heráclito de Faria Lima com participação da Casa Henry Rogers Son & Co., da Inglaterra, incorporando técnicas construtivas mais modernas.','Em 1919, dentro de um novo pensamento urbanístico e visando aproveitar a estrutura existente, o projeto de Hugo Bozzi transformou o equipamento em monumento comemorativo ao Centenário da Emancipação Política de Sergipe, conferindo-lhe caráter simbólico e celebrativo.','Ao longo de sua trajetória, a ponte recebeu diferentes denominações — como Ponte do Governador, Ponte Metálica, Ponte do Presidente e Ponte do Desembarque, refletindo as mudanças de regime político. Atualmente conhecida como Ponte do Imperador, permanece como um dos mais importantes marcos históricos e arquitetônicos do centro de Aracaju, representando a memória do período imperial e das transformações urbanas da cidade.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','The bridge was built in 1859 to welcome Emperor D. Pedro II. It underwent various renovations and today is called the Emperor''s Bridge. The landing platform was once known as Governor''s Bridge, Metal Bridge, President''s Bridge and Landing Bridge.','','','El puente fue construido en 1859 para recibir al Emperador D. Pedro II. Pasó por varias reformas y hoy se llama Puente del Emperador. La plataforma de desembarco ya fue conocida como Puente del Gobernador, Puente Metálico, Puente del Presidente y Puente del Desembarco.','','','historico',-10.90950000,-37.07200000,'Av. Ivo do Prado, Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-bc91dfee-6131-455e-8a35-a8a4ed5b050b','https://maps.google.com/?q=-10.9095,-37.0720',true,'',false,true,'','{"tipo": "Construção do século XIX, com diversas intervenções", "tombamento": "Decreto nº 29.556, de 23 de outubro de 2013"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T16:31:06.529Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('5946206d-7237-4131-9336-d246f531e72a','Centro de Cultura e Arte (CULTART)','Culture and Arts Center (CULTART)','Centro de Cultura y Arte (CULTART)','As palmeiras imperiais que compõem o eixo paisagístico entre a Ponte do Imperador e a Catedral Metropolitana de Aracaju constituem um dos mais expressivos símbolos do período monárquico na capital sergipana. O plantio dessas árvores no século XIX está associado à visita de Dom Pedro II a Sergipe, em 1860, funcionando como homenagem e marco visual da presença imperial na cidade.
Da espécie Roystonea oleracea, as palmeiras imperiais foram introduzidas no Brasil em 1809, durante o reinado de Dom João VI, e passaram a representar poder, distinção e vínculo com a monarquia. Suas sementes eram distribuídas a figuras influentes, o que contribuiu para sua disseminação em espaços públicos e propriedades de destaque.','Em Aracaju, essas árvores passaram a integrar a paisagem do centro histórico, especialmente em áreas como a Praça Almirante Barroso, reforçando o caráter simbólico e monumental do espaço urbano. Com crescimento rápido e podendo atingir até 40 metros de altura, as palmeiras destacam-se pela imponência e elegância, contribuindo para a composição arquitetônica e paisagística do entorno.','Mais do que elementos decorativos, as palmeiras imperiais em Aracaju representam marcos históricos vivos do período imperial brasileiro, mantendo na paisagem urbana a memória da relação de Sergipe com a monarquia no século XIX.
Elaboração própria, com base em informações da Prefeitura de Aracaju e fontes especializadas.','The building was inaugurated in 1917, in eclectic architectural style. It housed the Barão de Maruim School Group, then the Law School, and since 1980 has been home to the UFS Culture and Arts Center, with the Professor Luiz Alberto dos Santos Pinacoteca and the Florival Santos Art Gallery.','','','El edificio fue inaugurado en 1917, en estilo arquitectónico ecléctico. Albergó el Grupo Escolar Barão de Maruim, después la Facultad de Derecho, y desde 1980 sede el Centro de Cultura y Arte de la UFS, con la Pinacoteca profesor Luiz Alberto dos Santos y la Galería de Arte Florival Santos.','','','cultura',-10.90970000,-37.07190000,'Av. Ivo do Prado, n° 612 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-5933c83a-6e5d-4417-8a3f-82e0eacac31f','https://maps.google.com/?q=-10.9097,-37.0719',true,'',false,false,'','{"tipo": "Arquitetura institucional, primeira metade do século XX", "tombamento": "Decreto nº 4989, de 23 de abril de 1981", "propriedade": "Universidade Federal de Sergipe"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T14:19:36.926Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('bfd292e6-48f6-4485-b313-66b2fc0e39b7','Museu da Gente Sergipana','Sergipe People Museum','Museo de la Gente Sergipana','O edifício que hoje abriga o Museu da Gente Sergipana é um dos exemplares mais marcantes da arquitetura eclética em Aracaju. Construído no local onde funcionava o antigo Quartel de Polícia, o prédio foi inaugurado em 13 de agosto de 1926 e, durante quase meio século, sediou o tradicional Atheneu Pedro II, conhecido popularmente como “Atheneuzinho”, instituição de ensino que marcou gerações.
Após o período educacional, o imóvel passou a acolher diversos órgãos públicos até sua desativação, em 1996. Somente em outubro de 2009 teve início um amplo projeto de restauração, que preservou suas características arquitetônicas originais e adaptou os espaços internos para nova função cultural.','Inaugurado em 2011, o Museu da Gente Sergipana Governador Marcelo Déda consolidou-se como referência nacional em museologia interativa. Seu acervo apresenta parcela significativa do patrimônio cultural material e imaterial de Sergipe, por meio de instalações tecnológicas, ambientes sensoriais e exposições itinerantes que valorizam tradições, saberes populares, manifestações artísticas e a formação histórica do estado.','A transformação do antigo prédio público em museu reforça o processo de ressignificação do patrimônio arquitetônico de Aracaju, integrando memória, inovação e identidade cultural em um único espaço.
Elaboração própria, com base em informações do Ipatrimônio.','Inaugurated in 1926, it housed the Atheneu Pedro II. Since 2011, the Sergipe People Museum has been operating, which has several spaces whose collection presents a significant portion of Sergipe''s material and immaterial cultural heritage, through interactive installations and traveling exhibitions.','','','Inaugurado en 1926, albergó el Atheneu Pedro II. Desde 2011 funciona el Museo de la Gente Sergipana, que posee varios espacios cuyo acervo presenta una porción significativa del patrimonio cultural material e inmaterial de Sergipe, a través de instalaciones interactivas y exposiciones itinerantes.','','','cultura',-10.90960000,-37.07180000,'Av. Ivo do Prado, nº 398 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-8f128687-f27b-4c4e-b7db-3c230d52a8d7','https://maps.google.com/?q=-10.9096,-37.0718',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, primeira metade do século XX", "tombamento": "Decreto nº 6.820, de 28 de janeiro de 1985"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T17:35:53.850Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('3ab59e45-8802-47f5-bac5-ee3a19d84164','Prédio do Antigo Tribunal de Justiça (Palácio Silvio Romero)','Former Court of Justice Building (Silvio Romero Palace)','Edificio del Antiguo Tribunal de Justicia (Palacio Silvio Romero)','O edifício que atualmente abriga o Memorial do Poder Judiciário de Sergipe possui trajetória diretamente ligada à formação institucional do estado. Construído no final do século XIX, o prédio foi sede do Tribunal de Relação, considerado o primeiro órgão judiciário de Sergipe, representando marco na organização do sistema de Justiça local.
Criado na gestão do Presidente José Calazans, em 1890, e inaugurado oficialmente em 1894 pelo Presidente Oliveira Valadão, o imóvel também sediou o antigo Juizado de Menores, ampliando sua função na estrutura judiciária sergipana.','Conhecido hoje como Palácio Silvio Romero, o edifício apresenta características do estilo eclético, evidentes na composição das fachadas e nos elementos ornamentais que marcaram a arquitetura institucional do período. Sua preservação mantém viva a memória do desenvolvimento jurídico e administrativo de Sergipe.','Atualmente, o espaço funciona como memorial, reunindo acervos e registros que narram a trajetória do Judiciário estadual, consolidando-se como ponto de referência histórica no centro de Aracaju.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','The building that houses the Memorial of the Judiciary of Sergipe was formerly the seat of the Court of Appeals, the first judicial body of Sergipe. It was created during the administration of President José Calazans in 1890 and inaugurated by President Oliveira Valadão in 1894. It is currently called Silvio Romero Palace.','','','El edificio que alberga el Memorial del Poder Judicial de Sergipe antiguamente fue sede del Tribunal de Relación, primer órgano judicial de Sergipe. Fue creado en la gestión del Presidente José Calazans en 1890 e inaugurado por el Presidente Oliveira Valadão en 1894. Actualmente se llama Palacio Silvio Romero.','','','historico',-10.90990000,-37.07160000,'Praça Olímpio Campos, nº 14 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-1e263918-14ef-474d-a794-cecffe812249','https://maps.google.com/?q=-10.9099,-37.0716',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, início do século XX", "tombamento": "Decreto nº 9.991, de 26 de outubro de 1988"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T19:11:41.025Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('bbeda40f-64c7-4276-a364-593dfa54f846','Palácio Inácio Barbosa (Sede da Prefeitura)','Inácio Barbosa Palace Building (City Hall Headquarters)','Edificio del Palacio Inácio Barbosa (Sede de la Prefectura)','Localizado na Praça Olímpio Campos, no coração do Centro Histórico de Aracaju, o Palácio Inácio Barbosa é um dos mais expressivos marcos da arquitetura e da história política da capital sergipana. Construído entre 1923 e 1924, durante a gestão do presidente do Estado Maurício Graccho Cardoso, o edifício foi concebido para sediar o Governo Municipal (Intendência), consolidando-se como centro administrativo da cidade por várias décadas.
Projetado pelo arquiteto Hugo Bozzi, com participação do engenheiro Alfredo Aranha, o prédio apresenta características do estilo eclético, marcadas por elementos ornamentais, composição simétrica e imponência volumétrica, típicas das edificações públicas do início do século XX. O nome Palácio Inácio Barbosa foi oficializado pela Lei Municipal nº 54, de 18 de julho de 1951, em homenagem ao fundador da capital, Inácio Joaquim Barbosa.','Ao longo do tempo, o palácio testemunhou importantes decisões políticas e momentos marcantes da administração municipal, tornando-se símbolo do poder público local. Em reconhecimento ao seu valor histórico e arquitetônico, o imóvel foi tombado como patrimônio histórico municipal pelo Decreto nº 16.559, de 26 de junho de 1997.','Apesar de sua relevância, o edifício enfrenta atualmente desafios relacionados à conservação, havendo registros recentes de comprometimento estrutural e debates sobre projetos de restauração e possível transformação em centro cultural ou memorial. Ainda assim, o Palácio Inácio Barbosa permanece como referência fundamental da memória política sergipana e da paisagem urbana de Aracaju.
Fonte: Elaboração própria com base na Prefeitura de Aracaju (2015).','Former Headquarters of the Municipal Prefecture of Aracaju. The building was built during the administration of the state president, Dr. Mauricio Graccho Cardoso in the early 20th century and the name was given in honor of the founder of the capital. Monument linked to Sergipe''s political history.','','','Antigua Sede de la Prefectura Municipal de Aracaju. El edificio fue construido en la gestión del presidente del Estado, Dr. Mauricio Graccho Cardoso a principios del siglo XX y el nombre fue dado en homenaje al fundador de la capital. Monumento vinculado a la historia política sergipana.','','','historico',-10.90970000,-37.07160000,'Praça Olímpio Campos s/nº - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-c20c0016-e73c-43b4-b4b0-f4249ca1f951','https://maps.google.com/?q=-10.9097,-37.0716',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, início do século XX", "tombamento": "Decreto nº 16.559, de 26 de junho de 1997"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T21:01:54.413Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('1c06f017-7bca-4fed-a5ab-479143181ead','Antigo Farol de Aracaju','Old Lighthouse of Aracaju','Antiguo Faro de Aracaju','O Farol da Farolândia é um dos mais importantes marcos históricos da navegação em Sergipe, distinto do Farol da Coroa do Meio. Localizado na Praça Tenente Domingues Fontes, na zona sul de Aracaju, o monumento integra a paisagem urbana e a memória marítima da capital.
A primeira estrutura foi inaugurada em 1861, construída em madeira por solicitação de Inácio Barbosa, com a finalidade de orientar embarcações na foz do Rio Sergipe. Após ser destruída por incêndio em 1884, uma nova torre metálica foi encomendada à França e projetada por Vitor Alinquat, sendo inaugurada em 7 de setembro de 1888. Com 35,5 metros de altura, funcionava inicialmente à base de querosene, emitindo luz branca cintilante com alcance aproximado de 17 milhas náuticas.
','Durante mais de um século, o farol desempenhou papel estratégico na segurança da navegação costeira. Em 16 de julho de 1991, foi oficialmente desativado, após a entrada em operação do novo Farol da Coroa do Meio, mais moderno e adaptado às demandas contemporâneas.
Reconhecido por sua relevância histórica, o Farol da Farolândia foi tombado pelo patrimônio cultural em 1995. Após período de abandono, passou por processo de revitalização em 2009, que incluiu restauração da estrutura e requalificação da praça ao seu entorno.','Atualmente, o espaço funciona como ponto de lazer e contemplação, próximo à Universidade Tiradentes (UNIT), mantendo-se como símbolo da história marítima e da evolução urbana de Aracaju, apesar dos desafios enfrentados ao longo dos anos.
Elaboração própria, com base em informações da Prefeitura de Aracaju e registros históricos.','The old lighthouse was built at the request of the then president of the Province of Sergipe, Inácio Barbosa, in 1861, based on a wooden structure painted black. A fire determined that a new lighthouse should be erected with an iron structure acquired in England. In 2009 the Lighthouse was restored.','','','El antiguo faro fue construido a pedido del entonces presidente de la Provincia de Sergipe, Inácio Barbosa, en el año 1861, teniendo como base una estructura de madera pintada de color negro. Un incendio determinó que se erigiera un nuevo faro con estructura de hierro adquirida en Inglaterra. En 2009 el Faro fue restaurado.','','','historico',-10.96500000,-37.05200000,'Rodovia Paulo Barreto de Menezes, Conjunto Augusto Franco - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-e4a42658-eab6-4050-bfde-ef90d1492744','https://maps.google.com/?q=-10.9650,-37.0520',true,'',false,false,'','{"tipo": "Estrutura implantada pelo Ministério da Marinha na segunda metade do século XIX", "tombamento": "Decreto nº 15.295, de 21 de abril de 1995"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T19:35:49.124Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('21d173dd-87cd-4efb-8251-072d0a4f7c31','Centro Cultural de Aracaju','Former Aracaju Customs Building','Edificio de la Antigua Aduana de Aracaju','A construção da antiga Alfândega de Aracaju representa um dos marcos fundamentais no processo de consolidação da nova capital sergipana, instaurada oficialmente em 1855. Inserida no contexto estratégico da mudança da sede administrativa de São Cristóvão para Aracaju, a edificação simboliza a organização inicial das atividades comerciais, fiscais e portuárias da cidade, cuja implantação urbana esteve diretamente ligada à dinâmica do rio Sergipe.','Ao longo de sua trajetória institucional, o prédio desempenhou funções relevantes para a administração pública, abrigando a Delegacia da Receita Federal de Sergipe e consolidando-se como espaço de controle e regulamentação das atividades econômicas. Sua presença no centro histórico reafirma a importância do comércio fluvial e da estrutura alfandegária para o desenvolvimento econômico da capital nascente.','Restaurado e atualmente sob administração da Prefeitura Municipal de Aracaju, o imóvel passou a sediar o Centro Cultural Cidade de Aracaju, ressignificando sua função original. Hoje, o espaço atua como equipamento cultural voltado à promoção de exposições, atividades educativas e valorização da memória urbana, preservando a materialidade arquitetônica enquanto amplia seu papel social e cultural.
Assim, a antiga Alfândega permanece como testemunho arquitetônico e institucional dos primeiros passos da cidade, articulando passado administrativo e presente cultural em um mesmo espaço histórico.
Elaboração própria com base na Prefeitura de Aracaju (2015).','The construction of the old Customs House constitutes one of the initial steps in the creation of the city in the movement to change the capital to the city of Aracaju. The building also housed the Federal Revenue Delegation of Sergipe, today it is restored and under the Administration of the Municipal Prefecture of Aracaju, where the Cultural Center City of Aracaju operates.','','','La construcción de la antigua Aduana constituye uno de los pasos iniciales de la creación de la ciudad en el movimiento de cambio de capital hacia la ciudad de Aracaju. El edificio también albergó la Delegación de la Receita Federal de Sergipe, hoy se encuentra restaurado y bajo la Administración de la Prefectura Municipal de Aracaju, donde funciona el Centro Cultural Ciudad de Aracaju.','','','historico',-10.90890000,-37.07150000,'Praça General Valadão, nº 134 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-6a10e2ea-bd73-47b1-8aa0-dc038e541b12','https://maps.google.com/?q=-10.9089,-37.0715',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, segunda metade do século XIX, reformado no início do século XX", "tombamento": "Decreto nº 21.765, de 9 de abril de 2003"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:50:42.344Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('1974d79d-4cf8-4c75-a1e6-4ca941a142e2','Monumento aos 150 Anos de Fundação da Cidade de Aracaju','Monument to the 150th Anniversary of the Foundation of the City of Aracaju','Monumento a los 150 Años de Fundación de la Ciudad de Aracaju','Caminhar pela Nova Orla de Aracaju é percorrer um espaço em que a paisagem natural e a intervenção urbana se articulam de forma planejada. Com o mar ao fundo, o vento constante moldando os coqueiros e o horizonte aberto, o ambiente convida à contemplação e à permanência. Nesse cenário, destaca-se uma escultura vertical que se impõe com elegância e sobriedade, integrando-se ao conjunto paisagístico e simbolizando o processo de renovação urbana da região.
O monumento, inaugurado em 2006, foi projetado e executado pelo artista plástico Leo Santana como marco da requalificação da área. Concebido na primeira década do século XXI, o equipamento acompanha o ciclo de urbanização e valorização da faixa litorânea, inserindo-se como elemento representativo da nova configuração territorial da orla.','Sua forma vertical dialoga com a paisagem aberta e com a escala do espaço público, servindo de ponto de referência visual para moradores e visitantes. Ao mesmo tempo, sua implantação em área de circulação reforça a intenção de integrar a arte pública ao cotidiano urbano, ampliando a experiência estética ao longo da orla.
Inserido em um ambiente que combina paisagismo planejado, áreas de convivência e de circulação de pedestres, o monumento contribui para a leitura simbólica da Nova Orla como território de modernização e de qualificação urbana. A placa inaugural reforça seu caráter institucional, registrando o momento histórico da intervenção e consolidando o reconhecimento público do processo de transformação.','Mais do que elemento escultórico, o monumento configura-se como um marco de um ciclo de desenvolvimento da cidade, representando o diálogo entre a arte pública, o planejamento urbano e a valorização do litoral aracajuano. Sua presença amplia a dimensão simbólica do passeio pela orla, associando a experiência da paisagem natural à narrativa de evolução e de fortalecimento da identidade urbana de Aracaju.
Elaboração própria, a partir de informações institucionais da Prefeitura Municipal de Aracaju (2008), registros públicos sobre a requalificação da Orla e materiais de divulgação institucional.','Walking along Nova Orla in Aracaju offers a unique experience, where the natural landscape is harmoniously blended with urban development. With the sea in the background, gentle winds swaying the coconut trees, and an expansive horizon, the setting encourages reflection and a sense of permanence. In this environment, a vertical sculpture stands out for its elegance and simplicity, complementing the landscaped surroundings and symbolizing the region’s urban renewal.
Inaugurated in 2006, the monument was designed and created by visual artist Leo Santana as a landmark for the area’s revitalization. Conceived in the early 21st century, the structure reflects the ongoing process of urbanization and improvement of the coastal strip, establishing itself as a key feature of the orla’s new territorial configuration.','The monument’s vertical design interacts with the surrounding open landscape and the scale of the public space, establishing itself as a visual landmark for both residents and visitors. Its strategic placement within a circulation area emphasizes the aim of integrating public art into everyday urban life, enhancing the aesthetic experience along the waterfront.
Situated in an environment featuring planned landscaping, recreational areas, and pedestrian pathways, the monument enhances the symbolic interpretation of Nova Orla as a site of modernization and urban development. Additionally, the commemorative plaque reinforces its institutional significance by documenting this pivotal moment in the transformation and solidifying public acknowledgment of the changes taking place.','The monument serves not only as a sculptural feature but also as a significant milestone in Aracaju’s urban development. It embodies the relationship between public art, urban planning, and the appreciation of the city’s coastline. Its presence enriches the symbolic experience of the waterfront, linking the enjoyment of the natural landscape to the narrative of the city’s evolution and reinforcing the urban identity.
Sources: Institutional information from the Municipal Government of Aracaju (2008); public records on the requalification of the Orla; institutional promotional materials.','Recorrer la Nova Orla de Aracaju es experimentar un espacio donde el paisaje natural y la intervención urbana se integran de manera planificada. Con el mar de fondo, el viento constante moldeando los cocoteros y un horizonte abierto, el entorno invita a la contemplación y a la permanencia. En este escenario se destaca una escultura vertical que se impone con elegancia y sobriedad, integrándose al conjunto paisajístico y simbolizando el proceso de renovación urbana de la región.
El monumento, inaugurado en 2006, fue proyectado y ejecutado por el artista plástico Leo Santana como un hito de la requalificación del área. Concebido en la primera década del siglo XXI, el equipamiento acompaña el ciclo de urbanización y valorización de la franja costera, posicionándose como elemento representativo de la nueva configuración territorial de la orla.','Su forma vertical dialoga con el paisaje abierto y la escala del espacio público, funcionando como punto de referencia visual para residentes y visitantes. Al mismo tiempo, su implantación en un área de circulación refuerza la intención de integrar el arte público en la vida urbana cotidiana, ampliando la experiencia estética a lo largo del paseo marítimo.
Insertado en un entorno que combina paisajismo planificado, áreas de convivencia y circulación peatonal, el monumento contribuye a la lectura simbólica de la Nova Orla como territorio de modernización y de cualificación urbana. La placa inaugural refuerza su carácter institucional, registrando el momento histórico de la intervención y consolidando el reconocimiento público del proceso de transformación.','Más que un elemento escultórico, el monumento se configura como un hito de un ciclo de desarrollo urbano, representando el diálogo entre el arte público, la planificación urbana y la valorización del litoral aracajuano. Su presencia amplía la dimensión simbólica del recorrido por la orla, asociando la experiencia del paisaje natural con la narrativa de la evolución y el fortalecimiento de la identidad urbana de Aracaju.
Fuentes: Información institucional de la Municipalidad de Aracaju (2008); registros públicos sobre la requalificación de la Orla; materiales de divulgación institucional.','cultura',-10.97500000,-37.05650000,'Orla Marítima de Aracaju, Praia de Atalaia','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/9c996b96-1254-43f2-b25c-6728548578d2", "type": "gallery", "order": 0}, {"id": "gallery-1", "url": "/objects/uploads/82610fcc-8f65-49e4-998b-27a4686416fd", "type": "gallery", "order": 1}]'::jsonb,'/objects/uploads/7f170b30-3846-4001-9b32-5a5b5c96f0a0','','qr-507f234a-ea04-430e-b8df-9e78572de4d9','https://maps.google.com/?q=-10.9750,-37.0565',true,'',true,true,'','{"autoria": "Artista plástico Leo Santana", "tombamento": "Decreto nº 24.149, de 21 de dezembro de 2006", "inauguracao": "2006"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-03T14:22:56.084Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('804c78ab-9ee5-409b-851f-5efc2786e9cd','Capela São João Batista','São João Batista Chapel','Capilla São João Batista','Erguida na década de 1960 como parte do complexo fabril da antiga Sergipe Industrial, a Capela São João Batista constitui um dos poucos remanescentes materiais da fase industrial do bairro Industrial. Sua permanência no local representa continuidade histórica em meio às transformações urbanas que redefiniram a área nas últimas décadas.
Com a implantação do Aracaju Parque Shopping, a estrutura foi incorporada ao novo projeto arquitetônico, mantendo-se como elemento simbólico da memória coletiva do bairro. A preservação atendeu a uma reivindicação histórica ligada à família Franco e à comunidade local, garantindo que o espaço não fosse descaracterizado ou suprimido pelo processo de modernização urbana.','Reconhecida oficialmente como patrimônio cultural do Bairro Industrial, a capela foi tombada pelo Estado de Sergipe em 6 de outubro de 2015, por meio do Decreto nº 30.079. O reconhecimento institucional reforça seu valor histórico, arquitetônico e afetivo, assegurando proteção legal e conservação de suas características originais.','Após restauração criteriosa, o templo foi reaberto em outubro de 2019, retomando sua função religiosa e comunitária. Além das celebrações regulares, destaca-se a tradicional festa em honra a São João Batista, padroeiro da capela, que mobiliza fiéis, moradores e visitantes, fortalecendo vínculos entre fé, memória e pertencimento.
Inserida em um contexto contemporâneo de comércio e circulação intensa, a capela mantém-se como espaço de recolhimento espiritual e referência identitária, conectando o passado industrial da cidade às dinâmicas atuais do bairro.
Elaboração própria, com base em informações da SeCult-SE e UFS.','Chapel from the second half of the 19th century, early 20th century. Property of the Franco Family. Located in the Former Sergipe Industrial Textile Factory. Burial place of Colonel José Ferras (died in 1906) and Dr. Thomaz Rodrigues da Cruz (died in 1919).','','','Capilla de la segunda mitad del siglo XIX, principios del siglo XX. Propiedad de la Familia Franco. Ubicada en la Antigua Fábrica de Tejidos Sergipe Industrial. Lugar de sepultura del Coronel José Ferras (fallecido en 1906) y Dr. Thomaz Rodrigues da Cruz (fallecido en 1919).','','','historico',-10.95670000,-37.04230000,'Antiga Fábrica de Tecidos Sergipe Industrial, Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-c83fdfa6-09d1-4885-b98a-211651d0f018','https://maps.google.com/?q=-10.9567,-37.0423',true,'',false,false,'','{"tipo": "Construção da segunda metade do século XIX, início do século XX", "propriedade": "Família Franco"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T16:27:43.885Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('9f75dfaf-1d54-4a13-a79c-08d73c443e66','Parque dos Cajueiros','Governor Antonio Carlos Valadares Park','Parque Gobernador Antonio Carlos Valadares','Localizado na Avenida Beira-Mar, no bairro Farolândia, às margens do Rio Poxim, o Parque Governador Antônio Carlos Valadares, conhecido como Parque dos Cajueiros, é um dos principais espaços de lazer e prática esportiva de Aracaju. Integrado à paisagem ribeirinha, o parque reúne infraestrutura moderna e áreas verdes que favorecem atividades ao ar livre.','Entre os destaques estão quadras poliesportivas, pista de skate, ciclovias e áreas destinadas à caminhada, corrida, ciclismo e patinação. O espaço também conta com píer para contemplação do rio, ampliando a experiência de contato com a natureza.','Para o público infantil, o parque oferece ampla área de recreação com parquinhos de madeira, esculturas lúdicas e o conhecido “castelinho”, tornando-se opção frequente para famílias. O acesso é gratuito e o funcionamento ocorre diariamente, das 5h às 22h.
Reaberto em 2012 após processo de revitalização, o Parque dos Cajueiros consolidou-se como ponto de convivência, esporte e lazer na capital sergipana, combinando infraestrutura urbana com valorização da paisagem natural.
Elaboração própria, com base em informações do Tripadvisor e redes sociais.','Modern park with outdoor gym, walking tracks and water sports on Poxim River. Leisure area with privileged view of the river, gym equipment and spaces for physical activities and urban nature contemplation.','','','Parque moderno con gimnasio al aire libre, pistas de caminata y deportes acuáticos en el Río Poxim. Área de ocio con vista privilegiada del río, equipamientos de gimnasia y espacios para actividades físicas y contemplación de la naturaleza urbana.','','','historico',-10.93890000,-37.04560000,'Av. Beira Mar, Jardins, Aracaju - SE','{}'::text[],'[]'::jsonb,NULL,'','qr-b8829a7d-0571-4cbc-a412-9b7e91d71ef4','https://maps.google.com/?q=-10.9389,-37.0456',true,'',false,false,'','{"entrada": "Gratuita", "horarios": "6h às 20h", "atividades": ["Academia", "Caminhada", "Esportes aquáticos"]}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T21:08:42.597Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('f73e54c2-be53-4658-893e-19020de59c8a','Complexo Histórico da Praça Fausto Cardoso','Fausto Cardoso Square Historic Complex','Complejo Histórico de la Plaza Fausto Cardoso','Construída em 1857, a Praça Fausto Cardoso integra o núcleo original do projeto urbano de Aracaju, concebido em 1855 pelo engenheiro Sebastião Basílio Pirro. Inicialmente chamada de Praça do Palácio, por concentrar edifícios ligados aos poderes públicos, também recebeu as denominações de Praça do Imperador e Praça da República ao longo do tempo, refletindo as transformações políticas do país.
Em 28 de agosto de 1906, o local tornou-se cenário de um dos episódios mais marcantes da história sergipana: o assassinato do líder político Fausto Cardoso de Aguiar, fato que ficou conhecido como “a tragédia de Sergipe”. Em 1912, a praça foi oficialmente renomeada em sua homenagem e recebeu monumento com a inscrição “vou morrer defendendo a honra da minha terra”, além de abrigar, na base da estátua, seus restos mortais. A proximidade com o Palácio Olímpio Campos reforça o simbolismo político do espaço, marcado também pela rivalidade histórica com Olímpio Campos.
Ao longo do século XX, a praça consolidou-se como palco de manifestações políticas e sociais, sediando eventos como movimentos tenentistas, campanhas nacionalistas como “O Petróleo é Nosso”, comícios históricos, incluindo o de Luiz Carlos Prestes e atos das Diretas Já em 1984. Também foi espaço de desfiles cívicos até 1968 e berço do Forró Caju, iniciado em 1993.
Do ponto de vista cultural e arquitetônico, a praça abriga o coreto da década de 1930 e está cercada por importantes edificações, como a Assembleia Legislativa, o Museu Olímpio Campos e outros prédios históricos que compõem o conjunto arquitetônico do centro. Situada próxima ao Rio Sergipe, à Ponte do Imperador e ao Mercado Municipal Antônio Franco, a Praça Fausto Cardoso permanece como um dos espaços públicos mais emblemáticos da capital, reunindo memória, política e convivência urbana.
Elaboração própria, com base em informações da Assembleia Legislativa de Sergipe, Prefeitura de Aracaju e registros históricos.','Natural de Divina Pastora, Fausto Cardoso foi advogado, filósofo e deputado estadual que se destacou como liderança oposicionista no início do século XX. Insatisfeito com a política oligárquica vigente, liderou o grupo conhecido como “Pebas”, formado por profissionais liberais e setores populares que defendiam mudanças no cenário político sergipano.
Em oposição, estavam os “Cabaus”, liderados por Olímpio Campos, então senador da República, ligados à elite agrária e a setores conservadores. O conflito se intensificou quando Guilherme Campos, irmão de Olímpio e governador do estado, enfrentou o grupo de Fausto Cardoso. Em 1906, Fausto ocupou o então Palácio do Governo, atual Palácio Olímpio Campos, mas acabou assassinado em frente ao prédio após a chegada de reforços militares solicitados ao governo federal.
O episódio ficou conhecido como “a tragédia de Sergipe” e marcou profundamente a política estadual. Meses depois, no Rio de Janeiro, os filhos de Fausto Cardoso assassinaram Olímpio Campos, ampliando a rivalidade que polarizou a vida pública sergipana naquele período.
Em 1912, foi inaugurado em Aracaju o monumento em homenagem a Fausto Cardoso, esculpido pelo artista italiano Lorenzo Petrucci, o primeiro conjunto escultórico em espaço público de Sergipe, tendo seus restos mortais depositados na base da estátua, localizada na Praça Fausto Cardoso. Posteriormente, também foi erguida a estátua de Olímpio Campos na praça que passou a levar seu nome, consolidando no espaço urbano a memória dessa intensa disputa política.
Esses acontecimentos moldaram parte significativa da história republicana de Sergipe e permanecem como referências fundamentais para compreender a formação política de Aracaju.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2018).','','Historic complex including Legislative School, Olímpio Campos Palace-Museum, Palace of Justice, Legislative Assembly and Emperor''s Bridge. Center of Sergipe political power with 19th century architecture and important heritage ensemble.','','','Complejo histórico que incluye Escuela Legislativa, Palacio-Museo Olímpio Campos, Palacio de Justicia, Asamblea Legislativa y Puente del Emperador. Centro del poder político sergipano con arquitectura del siglo XIX e importante conjunto patrimonial.','','','historico',-10.90910000,-37.06770000,'Praça Fausto Cardoso, Centro, Aracaju - SE','{}'::text[],'[]'::jsonb,NULL,'','qr-bac44a93-3879-4bc5-9c40-bb723e8f3da0','https://maps.google.com/?q=-10.9091,-37.0677',true,'',false,false,'','{"tipo": "Complexo histórico", "horarios": "Segunda a sexta, 8h às 17h"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T13:32:27.790Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('adcbe8f2-a8cf-4f79-85a4-6679df322ab1','Palácio Museu Olímpio Campos','Olimpio Campos Palace Museum','Palacio Museo Olimpio Campos','O antigo Palácio do Governo, inaugurado em 1863, representa um dos marcos arquitetônicos e políticos mais significativos da história de Sergipe. Durante mais de um século até 1995, o edifício abrigou a sede administrativa do Estado, sendo palco de decisões fundamentais tanto no período imperial quanto ao longo da República. Após seu fechamento para atividades governamentais, o Palácio passou por um cuidadoso processo de restauração, que devolveu ao prédio grande parte de suas características originais. Em 2010, reabriu ao público em uma nova função: a de palácio-museu, permitindo que visitantes vivenciem de perto a memória política sergipana.','Em 1954, o edifício recebeu oficialmente o nome de Palácio Olímpio Campos, por meio da Lei nº 575, em homenagem ao influente líder político e sacerdote Olímpio de Sousa Campos (1853-1906). Sua trajetória marcante na vida pública de Sergipe justificou a distinção, perpetuando sua importância na história estadual. Trinta anos depois, em 1985, o prédio foi tombado pelo Governo do Estado através do Decreto nº 6.818, assegurando seu reconhecimento formal como patrimônio cultural e garantindo sua preservação para as futuras gerações.','Transformado em museu, o Palácio Olímpio Campos hoje abriga um valioso acervo composto por mobiliários, documentos, obras de arte e objetos ligados à história dos governantes e ao cenário político de Sergipe. Seus ambientes cuidadosamente ambientados oferecem ao público uma imersão na trajetória administrativa do Estado, revelando aspectos da vida política tanto do período imperial quanto do republicano, e consolidando o Palácio como uma referência essencial para a compreensão da identidade histórica sergipana.','The former Government Palace was inaugurated in 1863, served as the state government headquarters until 1995, and was reopened to the public as a palace-museum in 2010. It houses a rich collection of the history of rulers and imperial and republican politics in Sergipe.','','','El antiguo Palacio de Gobierno fue inaugurado en 1863, funcionó como sede del gobierno del estado hasta 1995, siendo reabierto al público como palacio-museo en 2010. Alberga una rica colección de la historia de los gobernantes y de la política imperial y republicana en Sergipe.','','','historico',-10.91289120,-37.04938230,'Praça Fausto Cardoso s/nº - Aracaju','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/689c2cf2-8c9f-49be-a488-483780b58042.png','','qr-bddd321d-95c5-487f-acb6-ddb9978cf3ea','https://share.google/uumm5fI2CF4JNaX2S',true,'Segunda a Sexta - 09h às 14h',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional", "periodo": "Segunda metade do século XIX, reformado no início do século XX", "tombamento": "Decreto nº 6.818, de 28 de janeiro de 1985"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T14:22:03.879Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('174ceafb-4014-4c0a-a0c1-b792e6ac5b74','Palácio Carvalho Neto ','Carvalho Neto Palace Building (State Public Archive)','Edificio del Palacio Carvalho Neto (Archivo Público Estatal)','Localizado no centro histórico de Aracaju, o Palácio Carvalho Neto é um dos mais expressivos exemplares da arquitetura Art Déco na capital sergipana. Construído na década de 1930 pelo engenheiro alemão Hermann O. W. Arendt von Altenesch, o edifício foi concebido originalmente para sediar a Biblioteca Pública do Estado, simbolizando o investimento governamental na difusão do conhecimento e na formação cultural da sociedade.
A denominação “Palácio Carvalho Neto” foi oficializada pela Lei Estadual nº 644, de 7 de maio de 1955, em homenagem ao advogado, professor e político Antônio Manoel de Carvalho Neto, intelectual de grande relevância na história jurídica e cultural de Sergipe. Em 1974, com a transferência da Biblioteca Pública para o bairro Treze de Julho, o prédio passou a abrigar o Arquivo Público do Estado de Sergipe (APES), função que mantém até os dias atuais.','Tombado pelo Patrimônio Cultural de Sergipe por meio do Decreto nº 12.038, de 22 de janeiro de 1991, o imóvel preserva características marcantes do estilo Art Déco, como linhas geométricas, simetria formal e sobriedade ornamental. O edifício passou por ampla restauração concluída por volta de 2019, quando foram recuperados elementos estruturais, o piso original de 1936 e promovidas adequações de acessibilidade.','O Arquivo Público do Estado de Sergipe guarda acervo documental de grande valor histórico, incluindo manuscritos do Poder Executivo, coleções de jornais e documentos que remontam ao século XVII, entre eles, uma escritura datada de 1692, considerada a peça mais antiga do conjunto. Aberto ao público e a pesquisadores, o APES funciona como centro de memória e referência para estudos sobre a formação política, administrativa e social do estado.
Assim, o Palácio Carvalho Neto consolida-se como monumento vinculado à história educacional, cultural e administrativa de Sergipe, integrando arquitetura, preservação documental e identidade histórica em um único espaço.
Elaboração própria, com base em informações do Arquivo Público do Estado de Sergipe e da Prefeitura de Aracaju.','The building called Carvalho Neto Palace was built in 1936, with the purpose of housing the State Public Library. From 1974, it became the headquarters of the State Public Archive. The construction follows the Art Deco style. A monument linked to the educational and cultural history of Sergipe.','','','El edificio denominado Palacio Carvalho Neto fue edificado en 1936, con el propósito de albergar la Biblioteca Pública del Estado. A partir de 1974, pasó a ser sede del Archivo Público Estatal. La construcción sigue el estilo Art Déco. Un monumento vinculado a la historia educativa y cultural de Sergipe.','','','historico',-10.91020000,-37.07140000,'Praça Fausto Cardoso, nº 348 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-04747f28-1324-48fe-b997-64d93d126e1d','https://maps.google.com/?q=-10.9102,-37.0714',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, primeira metade do século XX", "tombamento": "Decreto nº 12.038, de 22 de janeiro de 1991"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:52:33.467Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('869fc0d5-08df-4c7f-b0d8-9f732694b35f','Palácio Fausto Cardoso','Legislative Memorial','Memorial del Legislativo','Considerado um dos mais importantes monumentos ligados à história política sergipana, o Palácio Fausto Cardoso teve sua construção iniciada em 1868 para abrigar a Assembleia Provincial. As obras, marcadas por interrupções, foram concluídas em 1874, consolidando o edifício como sede do poder legislativo no período imperial.
No início do século XX, o prédio ainda preservava traços marcantes da arquitetura neoclássica, estilo que conferia imponência e sobriedade às construções públicas da época. Ao longo das décadas, além de sediar a Assembleia Legislativa, o imóvel também acolheu diferentes repartições estaduais.','Com o crescimento da estrutura administrativa do governo, o espaço tornou-se insuficiente para atender às novas demandas, levando à transferência da Assembleia para outra sede em 1987. Posteriormente, o edifício foi requalificado e passou a abrigar a Escola do Legislativo Deputado João de Seixas Dória e o Memorial do Legislativo Deputada Quintina Diniz, preservando sua função institucional ligada à formação política e à memória legislativa.','Integrante do conjunto arquitetônico histórico do centro de Aracaju, o prédio permanece como testemunho material das transformações políticas e administrativas de Sergipe desde o século XIX.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','One of the most important monuments linked to Sergipe''s political history. Construction began in 1868, it housed the Provincial Assembly. Currently houses the Legislative School and the Legislative Memorial. It is a construction from the second half of the 19th century.','','','Uno de los monumentos más importantes vinculados a la historia política sergipana. La construcción comenzó en 1868, albergó la Asamblea Provincial. Actualmente alberga la Escuela del Legislativo y el Memorial del Legislativo. Es una construcción de la segunda mitad del siglo XIX.','','','historico',-10.91010000,-37.07150000,'Praça Fausto Cardoso s/nº - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-4dde18e2-e5bb-49a3-a538-b02e01fad4b9','https://maps.google.com/?q=-10.9101,-37.0715',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional", "tombamento": "Decreto nº 8.313, de 18 de fevereiro de 1987"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T21:02:40.331Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('4ecd4c89-76f3-4695-bfee-ee295fb93a9d','Cemitério dos Náufragos','The Castaways Cemetery','Cementerio de los Náufragos','Em meio à vegetação litorânea e ao cenário natural da região, encontra-se o Cemitério dos Náufragos, um dos espaços históricos mais simbólicos de Aracaju, diretamente ligado a um dos episódios mais marcantes da história brasileira durante a Segunda Guerra Mundial.
O local surgiu em 1942, após o torpedeamento dos navios mercantes brasileiros Baependy, Araraquara e Aníbal Benévolo pelo submarino alemão U-507, comandado por Harro Schacht. Os ataques ocorreram entre os dias 15 e 16 de agosto daquele ano e resultaram em centenas de mortes no litoral sergipano, gerando grande comoção nacional e contribuindo para a entrada oficial do Brasil na guerra contra os países do Eixo. Muitos corpos chegaram às praias de Sergipe e, diante da dificuldade de identificação e do grande número de vítimas, foi criado um espaço específico para o sepultamento daqueles que não puderam ser reconhecidos, dando origem ao Cemitério dos Náufragos.','Classificado como patrimônio histórico estadual, o cemitério é tombado pelo Decreto nº 2.571, de 20 de junho de 1973, e registrado como exemplar de arquitetura funerária do século XX. O espaço representa não apenas um local de sepultamento, mas também um memorial coletivo que preserva a memória das vítimas e de um período em que o litoral brasileiro se tornou cenário direto do conflito mundial.
','Visitar o Cemitério dos Náufragos é entrar em contato com uma dimensão mais profunda da história de Aracaju e do Brasil, marcada pela dor, pela memória e pela resiliência. O local funciona como espaço de reflexão sobre os impactos da guerra na vida civil e a importância de preservar a memória histórica como forma de aprendizado coletivo. Por seu valor histórico e simbólico, o cemitério integra o conjunto de bens culturais que ajudam a narrar a trajetória da cidade e reforçam a importância da preservação do patrimônio para as gerações futuras.
Elaboração própria, com base em informações institucionais e históricas (Patrimônio; Marinha do Brasil; literatura acadêmica sobre o período da Segunda Guerra Mundial no litoral nordestino).','Amid the coastal vegetation and the region’s natural landscape lies the Cemitério dos Náufragos (Castaways Cemetery), one of the most symbolically significant historical sites in Aracaju, directly associated with one of the most impactful episodes in Brazilian history during the Second World War.
The site originated in 1942, following the torpedo attacks on the Brazilian merchant ships Baependy, Araraquara, and Aníbal Benévolo by the German submarine U-507, commanded by Harro Schacht. The attacks took place between August 15 and 16 of that year and resulted in hundreds of deaths along the coast of Sergipe, provoking widespread national outrage and contributing decisively to Brazil’s official entry into the war against the Axis powers. Many bodies washed ashore on Sergipe’s beaches, and due to the difficulty of identification and the large number of victims, a specific burial ground was established for those who could not be identified, giving rise to what became known as the Castaways Cemetery.','Classified as a state historical heritage site, the cemetery was listed by State Decree No. 2,571, dated June 20, 1973, and is registered as an example of 20th-century funerary architecture. The site represents not only a burial ground but also a collective memorial that preserves the memory of the victims and of a period when the Brazilian coastline became a direct theater of global conflict.','Visiting the Shipwrecked Cemetery offers contact with a deeper dimension of Aracaju’s and Brazil’s history, marked by loss, memory, and resilience. The site functions as a place for reflection on the civilian impacts of war and on the importance of preserving historical memory as a form of collective learning. Due to its historical and symbolic value, the cemetery is part of the cultural heritage that helps narrate the city’s trajectory and reinforces the importance of safeguarding heritage for future generations.
Elaborated by the author, based on institutional and historical information (Heritage; Brazilian Navy; academic literature on the Second World War period on the northeast coast).','En medio de la vegetación costera y del paisaje natural de la región se encuentra el Cementerio de los Náufragos, uno de los espacios históricos más simbólicos de Aracaju, directamente vinculado a uno de los episodios más impactantes de la historia brasileña durante la Segunda Guerra Mundial.
El lugar surgió en 1942, tras el torpedeo de los buques mercantes brasileños Baependy, Araraquara y Aníbal Benévolo por el submarino alemán U-507, comandado por Harro Schacht. Los ataques tuvieron lugar entre el 15 y el 16 de agosto de ese año y causaron cientos de muertes en la costa de Sergipe, lo que generó una gran conmoción nacional y contribuyó a la entrada oficial de Brasil en la guerra contra los países del Eje. Muchos cadáveres llegaron a las playas de Sergipe y, ante la dificultad de identificación y el gran número de víctimas, se creó un espacio específico para el entierro de aquellos que no pudieron ser reconocidos, dando origen al Cementerio de los Náufragos.','Clasificado como patrimonio histórico estadual, el cementerio fue protegido por el Decreto nº 2.571, de 20 de junio de 1973, y está registrado como ejemplo de arquitectura funeraria del siglo XX. El espacio representa no solo un lugar de sepultura, sino también un memorial colectivo que preserva la memoria de las víctimas y de un período en que el litoral brasileño se convirtió en escenario directo del conflicto mundial.','Visitar el Cementerio de los Náufragos permite acceder a una dimensión más profunda de la historia de Aracaju y de Brasil, marcada por el dolor, la memoria y la resiliencia. El sitio funciona como espacio de reflexión sobre los impactos de la guerra en la población civil y sobre la importancia de preservar la memoria histórica como forma de aprendizaje colectivo. Por su valor histórico y simbólico, el cementerio integra el conjunto de bienes culturales que ayudan a contar la trayectoria de la ciudad y refuerzan la importancia de la preservación del patrimonio para las generaciones futuras.
Elaborado por el autor, basado en información institucional e histórica (Patrimonio; Armada Brasileña; literatura académica sobre el período de la Segunda Guerra Mundial en la costa noreste).','historico',-10.94720000,-37.07310000,'Rodovia dos Náufragos, Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-4bfbebce-2b08-4c17-8e06-052ee204db71','https://maps.google.com/?q=-10.9472,-37.0731',true,'',true,true,'','{"tipo": "Arquitetura funerária, século XX", "tombamento": "Decreto nº 2.571, de 20 de junho de 1973"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-02T15:01:41.965Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('bb21f821-6529-42ce-a8cf-3d39cfba72a4','Conjunto de Esculturas de Vultos Históricos','Set of Sculptures of Historical Figures ','Conjunto de Esculturas de Personajes Históricos ','Percorrer a Orla Marítima de Aracaju é vivenciar um espaço onde mar, cidade e cultura se articulam de forma integrada. Entre áreas de convivência, ciclovias e equipamentos de lazer, o visitante encontra manifestações que ultrapassam a dimensão recreativa e incorporam memória e identidade ao cotidiano urbano. Nesse contexto, destaca-se o Conjunto de Esculturas de Vultos Históricos, instalado no Espaço de Convivência Cultural da orla, concebido como um ambiente de valorização da educação, da história e da cultura sergipana.
Inaugurado em dezembro de 2006, o conjunto reúne esculturas em bronze de personalidades de reconhecida relevância para a formação intelectual, política e cultural de Sergipe. Estão representados Tobias Barreto, Sílvio Romero, Manoel Joaquim Bomfim, Maurício Graccho Cardoso, Gumercindo Bessa, Gilberto Amado, José Calazans, Jackson de Figueiredo, João Ribeiro e Horácio Hora, nomes que contribuíram significativamente para o pensamento crítico, a literatura, a historiografia, a política e as artes no estado.','As obras são de autoria do artista plástico Otto Domovich, que, por meio da escultura figurativa em bronze, buscou traduzir a importância histórica desses personagens e conferir permanência simbólica à sua presença no espaço público. A opção pelo bronze, material tradicionalmente associado à monumentalidade e à memória coletiva, reforça o caráter institucional e educativo do conjunto.
Inserido em um dos principais cartões-postais da capital, o conjunto escultórico amplia a dimensão cultural da experiência turística na orla. Mais do que elemento ornamental, constitui um instrumento de educação patrimonial, estimulando o reconhecimento da trajetória intelectual sergipana e promovendo o diálogo entre passado e presente em um ambiente de circulação cotidiana.','Dessa forma, o Conjunto de Esculturas de Vultos Históricos consolida-se como referência em arte pública e na valorização identitária, integrando lazer, turismo e memória histórica em um mesmo território urbano. Sua presença fortalece a narrativa cultural de Aracaju e contribui para diversificar os conteúdos simbólicos associados à Orla Marítima.
Elaboração própria, com base em informações institucionais da Prefeitura de Aracaju (2015).','Walking along the Seafront of Aracaju means experiencing a space where the sea, the city, and culture are closely interconnected. Among leisure areas, bike paths, and public facilities, visitors encounter elements that go beyond recreation and incorporate memory and identity into everyday urban life. In this setting stands the Set of Sculptures of Historical Figures, installed in the Cultural Coexistence Area of the seafront, conceived as a space dedicated to valuing education, history, and Sergipe’s cultural heritage.
Inaugurated in December 2006, the ensemble comprises bronze sculptures depicting personalities of recognized importance to the intellectual, political, and cultural development of Sergipe. The figures represented include Tobias Barreto, Sílvio Romero, Manoel Joaquim Bomfim, Maurício Graccho Cardoso, Gumercindo Bessa, Gilberto Amado, José Calazans, Jackson de Figueiredo, João Ribeiro, and Horácio Hora — individuals who made significant contributions to critical thought, literature, historiography, politics, and the arts in the state.','The works were created by visual artist Otto Domovich, who, through figurative bronze sculptures, sought to translate the historical significance of these figures and ensure their symbolic permanence in public space. The choice of bronze, traditionally associated with monumentality and collective memory, reinforces the ensemble''s institutional and educational character.
Located in one of the city’s main landmarks, the sculptural complex enhances the cultural dimension of the tourist experience along the seafront. More than an ornamental feature, it serves as an instrument of heritage education, encouraging recognition of Sergipe’s intellectual trajectory and fostering dialogue between past and present within a space of everyday circulation.','The Set of Sculptures of Historical Figures serves as a key reference in public art and the preservation of identity. It effectively combines leisure, tourism, and historical memory within the same urban space. Its presence enhances the cultural narrative of Aracaju and diversifies the symbolic significance of the Seafront.
Based on institutional information from the City of Aracaju (2015).','Recorrer la Orla Marítima de Aracaju significa experimentar un espacio donde el mar, la ciudad y la cultura se articulan de manera integrada. Entre áreas de convivencia, ciclovías y equipamientos de ocio, el visitante encuentra elementos que trascienden la dimensión recreativa e incorporan memoria e identidad a la vida urbana cotidiana. En este contexto, se destaca el Conjunto de Esculturas de Personajes Históricos, instalado en el Espacio de Convivencia Cultural de la orla, concebido como un ámbito para la valorización de la educación, la historia y la cultura sergipana.
Inaugurado en diciembre de 2006, el conjunto está compuesto por esculturas de bronce que representan a personalidades de reconocida relevancia para la formación intelectual, política y cultural de Sergipe. Entre ellas se encuentran Tobias Barreto, Sílvio Romero, Manoel Joaquim Bomfim, Maurício Graccho Cardoso, Gumercindo Bessa, Gilberto Amado, José Calazans, Jackson de Figueiredo, João Ribeiro y Horácio Hora, quienes realizaron aportes significativos al pensamiento crítico, la literatura, la historiografía, la política y las artes en el estado.','Las obras son de autoría del artista plástico Otto Domovich, quien, mediante la escultura figurativa en bronce, buscó materializar la importancia histórica de estos personajes y garantizar su permanencia simbólica en el espacio público. La elección del bronce, tradicionalmente asociada a la monumentalidad y a la memoria colectiva, refuerza el carácter institucional y educativo del conjunto.
Ubicado en uno de los principales puntos turísticos de la capital, el conjunto escultórico amplía la dimensión cultural de la experiencia en la orla. Más que un elemento ornamental, funciona como un instrumento de educación patrimonial, promoviendo el reconocimiento de la trayectoria intelectual de Sergipe y estimulando el diálogo entre pasado y presente en un espacio de circulación cotidiana.','De este modo, el Conjunto de Esculturas de Personajes Históricos se consolida como referencia de arte público y de valorización identitaria, integrando ocio, turismo y memoria histórica en un mismo territorio urbano. Su presencia fortalece la narrativa cultural de Aracaju y contribuye a diversificar los contenidos simbólicos asociados a la Orla Marítima.
Elaboración propia, basada en información institucional de la Prefeitura de Aracaju (2015).','cultura',-10.97550000,-37.05550000,'Av. Santos Dumont - Atalaia, Aracaju - SE, 49035-730','{}'::text[],'[]'::jsonb,NULL,'','qr-9a9a4e01-bcd0-4bee-8212-2bc99ebf889c','https://maps.app.goo.gl/XyDFKXEd2FvPLGF78',true,'',true,true,'','{"tipo": "Esculturas em bronze", "autoria": "Artista plástico Otto Domovich", "tombamento": "Decreto nº 24.147, de 21 de dezembro de 2006"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-02T12:30:12.351Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('0b9c246c-0898-4b2b-97d8-184a91c06bf4','Prédio da Secretaria de Estado da Segurança Pública ','State Public Security Secretariat Building (Former General Valadão School Group)','Edificio de la Secretaría de Seguridad Pública del Estado (Antiguo Grupo Escolar General Valadão)','Inaugurado em 1º de novembro de 1918, na Praça Tobias Barreto, o antigo Grupo Escolar General Valadão representa um marco da política educacional sergipana no início do século XX. Criado pelo Decreto nº 675, de 26 de agosto de 1918, o edifício foi concebido para abrigar uma das instituições de ensino graduado da capital, homenageando o então presidente do Estado, Manoel Presciliano de Oliveira Valadão. Doado ao Governo de Sergipe, o prédio simbolizava o investimento público na modernização do ensino e na formação cidadã.
Com a reorganização do sistema educacional, em 1924 o grupo escolar foi transferido para a Rua da Vitória (atual Avenida Carlos Burlamaqui). A partir daí, o edifício passou a assumir novas funções, sediando a Faculdade Livre de Direito Tobias Barreto entre 1924 e 1926, além de servir temporariamente como alojamento para estudantes de outras instituições de ensino.','Desde 1926, o imóvel foi progressivamente incorporado à estrutura da segurança pública estadual, tornando-se sede da Diretoria de Segurança Pública, depois Departamento de Segurança Pública e, a partir da década de 1960, da atual Secretaria de Estado da Segurança Pública de Sergipe (SSP-SE). Durante o regime militar, o prédio ganhou contornos ainda mais sensíveis de sua história, tendo seus porões utilizados como carceragens para presos políticos, fato que reforça seu valor como espaço de memória.','Reconhecido por sua relevância histórica, arquitetônica e institucional, o edifício integra o conjunto de patrimônios mapeados no centro histórico de Aracaju. Entre 2009 e 2010, passou por processo de restauração, que preservou suas características originais e garantiu a continuidade de seu uso administrativo.
Hoje, o antigo Grupo Escolar General Valadão constitui exemplo emblemático das transformações do espaço público em Aracaju, refletindo a passagem de um equipamento educacional para um centro estratégico da administração e da segurança do Estado.
Elaboração própria, com base em informações da Prefeitura de Aracaju e registros do Ipatrimônio.','It was built for educational purposes. Its inauguration is dated September 1, 1918 to house the ''General Valadão School Group''. In 1924, it began to house the Tobias Barreto Free Law School. Currently the building houses the State Public Security Secretariat.','','','Fue edificado para fines educativos. Su inauguración data del 1 de septiembre de 1918 para albergar el ''Grupo Escolar General Valadão''. En 1924, pasó a albergar la Facultad Libre de Derecho Tobias Barreto. Actualmente el edificio alberga la Secretaría de Seguridad Pública del Estado.','','','historico',-10.90450000,-37.05980000,'Praça Tobias Barreto, nº 20 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-635bbe0f-f3ae-42a3-b3ee-08d7e838be99','https://maps.google.com/?q=-10.9045,-37.0598',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, início do século XX", "tombamento": "Decreto nº 6.821, de 28 de janeiro de 1985"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T21:03:16.683Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('00b96692-4715-4290-9610-4d8ad5362a53','Centro de Turismo e Comercialização Artesanal','Tourism and Handicraft Trading Center','Centro de Turismo y Comercialización Artesanal','Localizado na região central de Aracaju, entre a Praça Olímpio Campos e o calçadão da Rua Laranjeiras, o Centro de Turismo é um dos principais espaços dedicados à valorização do artesanato e da cultura sergipana. O equipamento reúne 29 boxes comerciais, onde artesãos e lojistas expõem e comercializam peças que traduzem a identidade local, além de abrigar um centro de informações turísticas e o Memorial do Artista Sergipano.','Administrado pela Empresa Sergipana de Turismo (Emsetur), vinculada à Secretaria de Estado do Turismo, o espaço desempenha papel estratégico no fomento ao setor turístico e na dinamização da economia criativa. O artesanato exposto contempla produções de mais de 30 artistas, com trabalhos que vão da renda e bordado às esculturas e peças em madeira, barro e tecido, expressando a chamada “sergipanidade”.','Além de sua função cultural e comercial, o prédio possui relevância arquitetônica e histórica. Trata-se de edificação do início do século XX, com fachada tombada pelo Patrimônio Histórico do Estado, integrando o conjunto urbano tradicional do centro da capital.
O Centro de Turismo consolida-se, assim, como ponto de encontro entre memória, arte e atividade econômica, sendo parada estratégica para visitantes que desejam conhecer e levar consigo elementos autênticos da cultura sergipana.
Elaboração própria, com base em informações do Turismo Sergipe (2024).','Located near the Cathedral of Aracaju, the building was inaugurated in 1911 to house the Normal School for girls. In 1976, it was restored and the Tourism Center was inaugurated. It houses rooms for the commercialization of Sergipe handicrafts, especially lace.','','','Ubicado cerca de la Catedral de Aracaju, el edificio fue inaugurado en 1911 para funcionar como Escuela Normal para niñas. En 1976, fue restaurado e inaugurado el Centro de Turismo. Alberga salas para la comercialización de artesanías sergipanas, especialmente encajes.','','','cultura',-10.90980000,-37.07170000,'Praça Olímpio Campos - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-2c9c28c0-4ee0-4bfd-9aff-796f7a653d75','https://maps.google.com/?q=-10.9098,-37.0717',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, primeira metade do século XX", "tombamento": "Decreto nº 6.129, de 06 de janeiro de 1984"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T14:43:35.076Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('24287a45-95ab-4131-a42a-7fc26ebc43bf','Instituto Histórico e Geográfico de Sergipe (IHGS)','Historical and Geographical Institute of Sergipe Building (IHGS)','Edificio del Instituto Histórico y Geográfico de Sergipe (IHGS)','Criado em 6 de agosto de 1912, o Instituto Histórico e Geográfico de Sergipe consolidou-se como uma das mais importantes entidades dedicadas à preservação da memória e à construção da identidade cultural do estado. Durante muitos anos, foi conhecido como “Casa de Sergipe”, denominação que expressa seu papel simbólico como guardião da história, da produção intelectual e dos registros documentais sergipanos.','O prédio que atualmente abriga o IHGSE possui relevância adicional por ter sediado a antiga Rádio Difusora de Sergipe, a primeira emissora radiofônica do estado. Essa dupla vocação, histórica e comunicacional, reforça a importância do imóvel como espaço de difusão cultural e de valorização da memória coletiva.','Ao longo de sua trajetória, o Instituto tem reunido acervos documentais, bibliográficos e iconográficos que contribuem para pesquisas acadêmicas e para o fortalecimento da historiografia local, mantendo-se como referência no estudo da formação social, política e cultural de Sergipe.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','Created on August 6, 1912, the Institute was called for a long time ''Casa de Sergipe'', being an important entity involved in building the cultural identity of the State. The building that currently houses the IHGSE was the headquarters of the old Radio Difusora de Sergipe, the first radio station in Sergipe.','','','Creado el 6 de agosto de 1912, el Instituto fue llamado por mucho tiempo ''Casa de Sergipe'', siendo una importante entidad involucrada en la construcción de la identidad cultural del Estado. El edificio que actualmente alberga el IHGSE fue sede de la antigua Radio Difusora de Sergipe, la primera emisora de radio de Sergipe.','','','historico',-10.90080000,-37.06470000,'Rua Itabaianinha, nº 41 - Centro Histórico de Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-cd0f5cf2-54df-4397-8873-032e1defb991','https://maps.google.com/?q=-10.9008,-37.0647',true,'',false,false,'','{"tipo": "Edificação do início do século XX", "tombamento": "Decreto nº 24.383, de 09 de maio de 2007"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:53:38.717Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('294d16bb-a059-4eb2-af7d-f79ecc213640','Escultura do Caranguejo Gigante','Giant Crab Monument','Monumento del Cangrejo Gigante','Ao chegar à Orla de Atalaia no final da tarde, a paisagem se transforma gradualmente. O vento traz o cheiro do mar, o sol pinta o céu de tons alaranjados e, logo adiante, moradores e turistas ocupam bares e restaurantes iluminados por luzes, por conversas e por música. Esse é o ambiente da Passarela do Caranguejo, reconhecida como o principal corredor gastronômico de Aracaju e como um dos espaços mais representativos da vida noturna da capital.
A consolidação da passarela está diretamente ligada à tradição pesqueira local e ao processo de qualificação urbana da orla da Praia de Atalaia. Ao longo das últimas décadas, o trecho da Avenida Santos Dumont estruturou-se como polo gastronômico, reunindo dezenas de estabelecimentos que oferecem desde pratos típicos da culinária sergipana — com destaque para o caranguejo — até opções da gastronomia nacional e internacional. A diversidade de oferta acompanha o crescimento do fluxo turístico na região e dialoga com o perfil multifuncional da orla.','Em períodos comemorativos, especialmente durante o Réveillon, o local ganha ainda mais centralidade. A programação cultural promovida na orla atrai grande público e reforça a Passarela do Caranguejo como um ponto estratégico de convivência, circulação e consumo, integrando lazer, gastronomia e eventos em um mesmo território.
A identidade do espaço é marcada pelo monumento do Caranguejo Gigante, instalado em 2014. Produzida em fibra de vidro, a escultura mede aproximadamente 7 metros de comprimento por 2,30 metros de altura e foi criada pelo artesão sergipano Ary Marques Tavares. Mais do que um elemento decorativo, o monumento materializa um símbolo da cultura alimentar e da economia local ligada ao manguezal. Tornou-se referência visual da passarela e um ponto frequente para registros fotográficos.','Visitar a Passarela do Caranguejo significa experimentar um espaço onde turismo, cultura e gastronomia se articulam de forma orgânica. Música ao vivo, culinária regional e circulação constante compõem uma experiência que conecta tradição e dinâmica urbana contemporânea. Nesse cenário, a passarela reafirma seu papel como eixo estruturante da Orla de Atalaia e como expressão concreta da identidade costeira de Aracaju.
Elaboração própria, com base em informações setoriais e em conteúdos produzidos por Matheus Moura (Sergipe Trade Tour).','Arriving at the Orla de Atalaia in the late afternoon, the atmosphere shifts gradually. The wind carries the scent of the sea, the sun washes the sky in shades of orange, and just ahead, residents and visitors fill bars and restaurants lit by conversation, music, and warm lights. This is the setting of Passarela do Caranguejo, recognized as Aracaju’s main gastronomic corridor and one of the most distinctive areas of the city’s evening life.
Its consolidation is closely linked to the region’s fishing heritage and to the broader urban development of the Atalaia beachfront. Over recent decades, this stretch of Avenida Santos Dumont has evolved into a structured dining hub, bringing together dozens of establishments. Menus range from traditional Sergipe cuisine, with crab as the undisputed highlight, to Brazilian and international dishes. The variety reflects both the growth of tourism along the waterfront and the area’s multifunctional character.','During major celebrations, especially New Year’s Eve, the corridor gains additional prominence. Cultural programming organized along the waterfront attracts large crowds, reinforcing Passarela do Caranguejo as a central meeting point where leisure, gastronomy, and public events converge within the same coastal setting.
The monument defines the space’s visual identity of Caranguejo Gigante (Giant Crab Monument), installed in 2014. Crafted in fiberglass, the sculpture measures approximately 7 meters in length and 2.30 meters in height and was created by Sergipe artisan Ary Marques Tavares. More than a decorative feature, it represents a key symbol of local culinary culture and the mangrove-based economy. It has become a landmark and a frequent stop for photographs.','Visiting Passarela do Caranguejo means experiencing a place where tourism, culture, and gastronomy intersect naturally. Live music, regional flavors, and steady pedestrian movement create an atmosphere that balances tradition and contemporary urban life. Within this framework, the corridor stands as one of the structural anchors of the Orla de Atalaia and as a clear expression of Aracaju’s coastal identity.
Prepared based on sectoral information and content produced by Matheus Moura (Sergipe Trade Tour).','Al llegar a la Orla de Atalaia al final de la tarde, el ambiente cambia gradualmente. El viento trae el olor del mar, el sol tiñe el cielo de tonos anaranjados y, unos metros más adelante, residentes y visitantes ocupan bares y restaurantes iluminados por luces, conversaciones y música. Ese es el escenario de la Passarela do Caranguejo, reconocida como el principal corredor gastronómico de Aracaju y uno de los espacios más representativos de la vida nocturna de la ciudad.
Su consolidación está vinculada a la tradición pesquera local y al proceso de desarrollo urbano del frente marítimo de Atalaia. Con el paso de los años, el tramo de la Avenida Santos Dumont se consolidó como un polo gastronómico, concentrando decenas de establecimientos. La oferta abarca desde la cocina típica sergipana, con el cangrejo como protagonista, hasta propuestas nacionales e internacionales, lo que refleja la dinámica turística y el carácter multifuncional de la zona costera.','En fechas conmemorativas, especialmente durante la celebración de Año Nuevo, el sector adquiere mayor relevancia. La programación cultural realizada en la orla convoca a un público numeroso y refuerza la Passarela do Caranguejo como punto estratégico de encuentro, donde ocio, gastronomía y eventos públicos se articulan en un mismo espacio urbano.
La identidad visual del lugar está marcada por el monumento al Caranguejo Gigante (Monumento al Cangrejo Gigante), inaugurado en 2014. Elaborada en fibra de vidrio, la escultura mide aproximadamente 7 metros de largo por 2,30 metros de altura y fue creada por el artesano sergipano Ary Marques Tavares. Más que un elemento ornamental, simboliza la cultura culinaria local y la relación histórica con el manglar. Hoy funciona como referencia espacial y como parada habitual para fotografías.','Recorrer la Passarela do Caranguejo es vivir en un entorno donde turismo, cultura y gastronomía se integran de manera espontánea. Música en vivo, sabores regionales y movimiento constante configuran una experiencia que combina tradición y dinámica urbana contemporánea. En este contexto, el corredor se consolida como uno de los ejes estructurantes de la Orla de Atalaia y como expresión clara de la identidad costera de Aracaju.
Elaborado con base en información sectorial y en contenidos producidos por Matheus Moura (Sergipe Trade Tour).','cultura',-10.99195120,-37.05092750,'Av. Santos Dumont, 5600 - Atalaia, Aracaju - SE, 49035-240','{}'::text[],'[{"id": "inline-0", "url": "/uploads/tourist-images/57dd2e2e-4bac-44bc-bf27-b5cd764dedda.jpg", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/uploads/tourist-images/e87cda60-be9c-484c-9975-b4d0767c6315.jpg", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "inline-2", "url": "/uploads/tourist-images/49ef9ba8-3cb8-4582-9ccf-100f156456f8.jpg", "type": "inline", "order": 2, "inlinePosition": 3}, {"id": "gallery-0", "url": "/uploads/tourist-images/62bc84c7-4fa4-481a-a311-88c58c6d71ac.jpg", "type": "gallery", "order": 3}, {"id": "gallery-1", "url": "/uploads/tourist-images/cb216770-9733-4e27-92c9-3c3546b375fe.jpg", "type": "gallery", "order": 4}, {"id": "gallery-2", "url": "/uploads/tourist-images/3dc4c4f5-71f8-462d-9bcc-d0b234f603ea.jpg", "type": "gallery", "order": 5}, {"id": "gallery-3", "url": "/uploads/tourist-images/c5e98736-fb56-4482-9303-a6e78de824c4.jpg", "type": "gallery", "order": 6}]'::jsonb,'/uploads/tourist-images/680aeef0-2215-4631-9c65-b2447f7ac1d8.jpg','https://pub-872633efa2d545638be12ea86363c2ca.r2.dev/BEM%20VINDO%20ARACAJU%20(1)%20(2).mp4','qr-61a7e7c0-7c5d-471b-90dd-942c04da67e5','https://share.google/280smkxYokwxYCx5n',true,'',true,true,'','{"parking": true, "freeEntry": true, "photoSpot": true, "openingHours": "24 horas", "weekendEvents": true}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-01T20:17:51.973Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('95787d46-a16f-4f2d-ad4f-247f70be3bf7','Imóveis situados na Av. Otoniel Dória (500, 506, 511, 520, 524 e 534)','Buildings located on Otoniel Dória Avenue (500, 506, 511, 520, 524 and 534)','Inmuebles situados en la Av. Otoniel Dória (500, 506, 511, 520, 524 y 534)','Edificado nas primeiras décadas do século XX, o conjunto arquitetônico localizado no entorno do Mercado Municipal de Aracaju constitui importante exemplar da arquitetura civil urbana voltada às atividades comerciais. Os imóveis foram concebidos para abrigar casas de comércio, armazéns e estabelecimentos que impulsionaram a dinâmica econômica da capital no período de consolidação do centro histórico.','Com características marcantes do estilo eclético, como ornamentações em fachadas, varandas, platibandas e elementos decorativos que combinam referências clássicas e modernas, o conjunto reflete o momento de expansão urbana e fortalecimento das atividades mercantis na primeira metade do século XX.','A proximidade com o Mercado Municipal Antônio Franco reforça o valor histórico da área, que se consolidou como polo de abastecimento e circulação de mercadorias. Além de seu papel econômico, o conjunto contribui para a identidade visual do centro de Aracaju, preservando traços arquitetônicos que ajudam a compreender a evolução urbana da cidade.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','The architectural ensemble was built in the first decades of the last century, for commercial purposes. Urban civil architecture buildings from the first half of the 20th century, near the municipal market of Aracaju that have characteristics of the eclectic style.','','','El conjunto arquitectónico fue edificado en las primeras décadas del siglo pasado, para fines comerciales. Inmuebles de arquitectura civil urbana de la primera mitad del siglo XX, cerca del mercado municipal de Aracaju que poseen características del estilo ecléctico.','','','historico',-10.91500000,-37.05670000,'Av. Otoniel Dória, 500-534 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-74ce0251-3a6f-4972-ba56-a42337621db1','https://maps.google.com/?q=-10.9150,-37.0567',true,'',false,false,'','{"tipo": "Arquitetura civil urbana da primeira metade do século XX", "tombamento": "Decreto nº 8.314, de 18 de fevereiro de 1987"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-11T19:01:46.925Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('3baf185d-ee03-4763-a53a-e928271e43bd','Mural do Artista Plástico Jenner Augusto','Panels and Murals by Plastic Artist Jenner Augusto','Paneles y Murales del Artista Plástico Jenner Augusto','Espalhados por áreas de grande circulação do centro histórico, como a Praça Fausto Cardoso e o tradicional Cacique Chá, os painéis artísticos que compõem a paisagem urbana de Aracaju integram a memória visual da cidade. Muitas vezes despercebidas na rotina apressada, essas obras permanecem como registros silenciosos da identidade econômica e cultural sergipana.
Um dos exemplos mais emblemáticos é o painel de azulejos que decora a fachada do Edifício Walter Franco, situado na esquina da Praça Fausto Cardoso com o calçadão da Rua João Pessoa. Construído em 1956 para sediar repartições governamentais, razão pela qual ficou conhecido como “Palácio das Secretarias”, o prédio incorpora em sua fachada uma narrativa visual ligada às atividades produtivas do estado.','O painel, executado em cerâmica pelo artista alemão Udo Knoff, aborda temas econômicos como a pesca e a produção agrícola, destacando elementos simbólicos como o caju, fruto associado à origem do nome da capital. A composição une arte e função pública, reforçando o diálogo entre arquitetura e expressão cultural na paisagem urbana.','Assim, essas intervenções artísticas não apenas ornamentam edifícios históricos, mas também preservam, em forma visual, aspectos da história econômica e social de Aracaju, consolidando-se como parte integrante do patrimônio cultural da cidade.
Elaboração própria, com base em informações de Lugares de Memória (2020).','His large tile mural, measuring 3m high by 4m wide, was painted in 1957, and is still displayed on the wall of the Walter Franco building. The Mural is displayed on public roads, and represents agricultural products that marked the Sergipe economy, such as: fish, coconut, cashew, sugarcane and corn.','','','Su gran mural en azulejos, de 3m de altura por 4m de ancho, fue pintado en 1957, y aún está expuesto en la pared del edificio Walter Franco. El Mural está expuesto en vía pública, y en él están representados productos agrícolas que marcaron la economía sergipana, tales como: el pescado, el coco, el anacardo, la caña y el maíz.','','','cultura',-10.90870000,-37.07030000,'Edifício Walter Franco - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-689a6a60-adb4-472a-b501-ac22757a3645','https://maps.google.com/?q=-10.9087,-37.0703',true,'',false,false,'','{"tipo": "Produção artística do século XX", "tombamento": "Decreto nº 9.990, de 26 de outubro de 1988"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:53:13.444Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('7e5a78a1-63e6-444b-ad02-a1bc27cb7ec1','Sede da Delegacia do Ministério da Fazenda ','Ministry of Finance Delegation Building (First Palace of the Province)','Edificio de la Delegación del Ministerio de Hacienda (Primer Palacio de la Provincia)','Localizado na Praça Fausto Cardoso, nº 272, no centro histórico de Aracaju, o edifício que hoje abriga a Superintendência de Administração do Ministério da Fazenda em Sergipe (SAMF-SE) integra o núcleo original da capital sergipana, estruturado após a transferência da sede administrativa de São Cristóvão para Aracaju, em 1855.
Erguido na segunda metade do século XIX, o prédio é um dos primeiros exemplares da arquitetura civil pública da nova capital. Ao longo de sua trajetória, desempenhou funções estratégicas para a administração provincial e republicana. Inicialmente, abrigou o Palacete da Presidência da Província e serviu como residência oficial do Imperador Dom Pedro II durante sua visita a Sergipe, consolidando seu valor simbólico no cenário político da época.','Posteriormente, o imóvel sediou a Alfândega, a Procuradoria Geral da Fazenda e a Delegacia do Ministério da Fazenda, mantendo-se sempre vinculado à gestão fiscal e administrativa do Estado. Sua localização privilegiada, próxima à antiga orla do rio Sergipe, reforçava sua importância estratégica no contexto urbano e institucional da cidade nascente.','De estilo característico da arquitetura civil urbana do século XIX, o edifício destaca-se pela sobriedade das linhas e pela imponência volumétrica, elementos que traduzem a função pública e a autoridade institucional que representava. Tombado como patrimônio histórico, permanece como testemunho material da consolidação administrativa de Aracaju e da formação do aparato estatal em Sergipe.
Elaboração própria com base em informações da Prefeitura de Aracaju (2015) e Ipatrimônio.','The public building where the Ministry of Finance Administration Superintendency in Sergipe currently operates has housed various public administrations, including the Palace of the Presidency of the Province and the official residence of Emperor D. Pedro II, during his visit to the State. It is one of the first public buildings built in Aracaju, after the capital was moved.','','','El edificio público donde actualmente funciona la Superintendencia de Administración del Ministerio de Hacienda en Sergipe ya albergó diversas administraciones públicas, entre ellas el Palacete de la Presidencia de la Provincia y la residencia oficial del Emperador D. Pedro II, en su visita al Estado. Es uno de los primeros edificios públicos construidos en Aracaju, después del cambio de la capital.','','','historico',-10.91030000,-37.07130000,'Praça Fausto Cardoso, nº 272 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-ca8bfe29-a99e-48f9-86d5-4f2a9b66c54b','https://maps.google.com/?q=-10.9103,-37.0713',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, segunda metade do século XIX", "tombamento": "Decreto nº 15.989, de 24 de julho de 1996"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:52:08.550Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('c2ac0c10-a77c-4645-b127-79e54bc6a2ef','Sede da Câmara Municipal de Aracaju','Former State Treasury Building (City Council)','Edificio del Antiguo Tesoro del Estado (Cámara Municipal)','Inaugurado em 1872 como sede do tradicional Atheneu Sergipense, o edifício integra o conjunto de construções emblemáticas do centro histórico de Aracaju. Concebido inicialmente para fins educacionais, o prédio simbolizou o avanço da instrução pública na capital sergipana ainda no período imperial.
Entre 1913 e 1914, passou por ampla reforma e ampliação, com a construção de um pavimento superior, momento em que deixou de abrigar o colégio e passou a sediar a Biblioteca Pública do Estado. Essa adaptação marcou nova fase na trajetória do imóvel, reforçando sua vocação cultural e administrativa.','Na década de 1930, outra intervenção arquitetônica modificou significativamente sua fachada, adequando-a às tendências estéticas do período. Posteriormente, o prédio passou a abrigar a Diretoria do Tesouro do Estado, consolidando-se como espaço de gestão pública.','Atualmente, o imóvel funciona como sede da Câmara Municipal de Aracaju, mantendo sua relevância institucional e histórica. Ao longo de mais de um século, o edifício assumiu diferentes funções, educacional, cultural e administrativa, refletindo as transformações políticas e urbanas da capital sergipana.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','Building inaugurated in 1872, as headquarters of the Atheneu Sergipense college. In 1913/14 there was a major renovation and expansion. Another renovation, in the 1930s, significantly altered the building''s facade, which from then on housed the State Treasury Directorate and, currently, the City Council.','','','Edificio inaugurado en 1872, como sede del colegio Atheneu Sergipense. En 1913/14 ocurrió una gran reforma y ampliación. Otra reforma, en la década de 1930, alteró significativamente la fachada del edificio, que a partir de entonces albergó la Dirección del Tesoro del Estado y, actualmente, la Cámara Municipal.','','','historico',-10.90980000,-37.07150000,'Praça Olímpio Campos, nº 74 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-f669257a-681a-4237-8c86-db106591daed','https://maps.google.com/?q=-10.9098,-37.0715',true,'',false,false,'','{"tipo": "Arquitetura civil urbana de caráter institucional, segunda metade do século XIX", "tombamento": "Decreto nº 12.039, de 22 de janeiro de 1991"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T20:56:34.097Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('2e098621-2035-46c2-b44d-f52cc0e61633','Sede da OAB Sergipe','OAB Building (Ivo do Prado Avenue, nº 1.072)','Edificio de la OAB (Av. Ivo do Prado, nº 1.072)','O Palacete Rollemberg começou a ser construído em 1917, durante a administração de Faro Rollemberg e Amélia Rollemberg, filhos do Barão de Japaratuba e do Barão de Estância. Projetado por Adolfo Rollemberg, o edifício apresenta características marcantes da arquitetura eclética com influências do Art Nouveau, estilo que valorizava ornamentos, curvas elegantes e riqueza de detalhes na fachada.
Embora idealizador do projeto, Adolfo Rollemberg faleceu antes da conclusão da obra e não chegou a usufruir da residência. O imóvel permaneceu por décadas sob posse da família Rollemberg, passando por sucessivas gerações até chegar aos descendentes Raul Fernando Barreto Rollemberg e Antônio Gonçalo Barreto Rollemberg.','Reconhecido como uma das construções mais emblemáticas da paisagem urbana de Aracaju, o palacete foi tombado como patrimônio histórico durante o governo de Antônio Carlos Valadares, assegurando sua preservação. Em 2007, passou por processo de restauração que recuperou elementos originais e adaptou o espaço para nova função institucional.','Atualmente, o edifício abriga a sede da Ordem dos Advogados do Brasil - Seccional Sergipe (OAB/SE), mantendo sua relevância histórica, arquitetônica e simbólica no centro da capital sergipana.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).','The building began to be built in 1917, at the time of Faro Rollemberg and Amélia Rollemberg. Designed by Adolfo Rollemberg, its style follows the traditional techniques of eclectic architecture and Art Nouveau. The monument is one of the most important references in Aracaju''s urban landscape. In 2007 it was restored and today houses the OAB (SE) Headquarters.','','','El edificio comenzó a construirse en 1917, en la época de Faro Rollemberg y Amélia Rollemberg. Diseñado por Adolfo Rollemberg, su estilo sigue las técnicas tradicionales de la arquitectura ecléctica y del Art Nouveau. El monumento es una de las referencias más importantes del paisaje urbano de Aracaju. En 2007 fue restaurado y hoy alberga la Sede de la OAB (SE).','','','historico',-10.90700000,-37.07350000,'Av. Ivo do Prado, nº 1.072 - Aracaju','{}'::text[],'[]'::jsonb,NULL,'','qr-78490c79-b13e-422f-9be2-9a74137c364e','https://maps.google.com/?q=-10.9070,-37.0735',true,'',false,false,'','{"tipo": "Arquitetura civil residencial urbana do início do século XX", "tombamento": "Decreto nº 11.118, de 07 de dezembro de 1989"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-02-13T21:00:23.034Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('47b939f7-b94a-4ab2-8cd6-14a71e26128c','Arcos da Orla de Atalaia','Arches of the Atalaia Waterfront','Los Arcos del Paseo Marítimo de Atalaia','Ao percorrer a Orla de Atalaia no fim da tarde, enquanto o céu altera gradualmente seus tons e a brisa do mar atravessa a avenida, a silhueta dos Arcos se destaca no horizonte. Entre ciclistas, famílias e visitantes, a estrutura marca simbolicamente a chegada ao principal corredor turístico da capital, servindo de referência imediata na paisagem urbana.
A implantação inicial ocorreu em 1994, no âmbito do Projeto Orla, iniciativa voltada à requalificação da faixa costeira e à organização do uso público do litoral de Atalaia. A intervenção integrou infraestrutura, paisagismo e ordenamento das atividades econômicas, estabelecendo as bases para a consolidação da orla como polo estruturado de lazer e turismo. Nesse processo, os Arcos passaram a representar mais do que um elemento arquitetônico: tornaram-se expressão material de uma estratégia de planejamento territorial.','O conjunto é formado por quatro estruturas em concreto, revestidas com pastilhas azuis e com mais de dez metros de altura. Segundo interpretações presentes na produção histórica local, cada arco simboliza uma etapa da consolidação da Orla como equipamento urbano estruturante. A leitura simbólica reforça a relação entre forma, memória e trajetória de desenvolvimento da cidade.
Com o tempo, o monumento consolidou-se como um ponto de encontro e um marco de orientação espacial. O entorno reúne bares, restaurantes, feiras de artesanato, ciclovias, áreas de convivência e meios de hospedagem, mantendo um fluxo constante ao longo do dia e da noite. Essa dinâmica confere aos Arcos um papel organizador da paisagem e fortalece sua função como elemento de identidade visual.','Mais do que um cartão-postal, os Arcos da Orla de Atalaia sintetizam a transformação da frente litorânea em um espaço de convivência qualificada. Ao dialogar com o mar, o movimento urbano e a vida cotidiana, o monumento evidencia como planejamento, infraestrutura e cultura local se articulam na construção da imagem contemporânea de Aracaju.
Elaboração própria, com base em informações setoriais e em conteúdos institucionais sobre a Orla de Atalaia.','Walking along the Atalaia Waterfront at sunset, as the sky gradually shifts in color and the sea breeze crosses the avenue, the silhouette of the Arches stands out against the horizon. Amid cyclists, families, and visitors, the structure marks the symbolic entrance to the city’s main tourism corridor and serves as an immediate visual reference in the urban landscape.
The first phase of construction dates back to 1994, within the scope of the Orla Project, an initiative aimed at requalifying the coastal strip and organizing public use along Atalaia Beach. The project combined infrastructure improvements, landscaping, and regulation of economic activity, laying the foundation for the Waterfront’s consolidation as a structured leisure and tourism hub. In this context, the Arches became more than an architectural feature; they emerged as a material expression of territorial planning.','The monument consists of four concrete structures clad in blue tiles, rising to over 10 meters. According to interpretations found in local historical accounts, each arch represents a stage in the consolidation of the Waterfront as a key urban facility. This symbolic reading reinforces the connection between architectural form and the city’s development trajectory.
Over time, the site has become a meeting point and spatial reference for residents and visitors alike. The surrounding area brings together restaurants, craft fairs, cycling paths, public spaces, and accommodation facilities, sustaining continuous activity throughout the day and evening. This dynamic strengthens the Arches’ role as an organizing element of the landscape and as a marker of visual identity.','More than a postcard image, the Arches of the Atalaia Waterfront synthesize the transformation of the coastal front into a structured space for social interaction and tourism. In dialogue with the sea, urban movement, and everyday life, the monument illustrates how planning, infrastructure, and local culture converge in shaping Aracaju’s contemporary image.
Prepared based on sectoral information and institutional content related to the Atalaia Waterfront.','Al recorrer el Paseo Marítimo de Atalaia al atardecer, mientras el cielo cambia lentamente de tonalidad y la brisa del mar atraviesa la avenida, la silueta de los Arcos se recorta en el horizonte. Entre ciclistas, familias y visitantes, la estructura marca simbólicamente la llegada al principal corredor turístico de la ciudad y sirve como referencia inmediata en el paisaje urbano.
La implantación inicial se remonta a 1994, en el contexto del Projeto Orla, una iniciativa orientada a la requalificación de la franja costera y a la organización del uso público en Atalaia. El proyecto integró infraestructura, paisajismo y ordenamiento de las actividades económicas, sentando las bases para la consolidación del paseo marítimo como polo estructurado de turismo y convivencia. En ese proceso, los Arcos trascendieron su dimensión arquitectónica y pasaron a ser una expresión tangible de la planificación territorial.','El conjunto está compuesto por cuatro estructuras de hormigón revestidas con mosaicos azules, cada una con más de diez metros de altura. Según interpretaciones presentes en la producción histórica local, cada arco simboliza una etapa en la consolidación del Paseo Marítimo como equipamiento urbano estratégico. Esta lectura refuerza el vínculo entre la forma arquitectónica y la trayectoria de desarrollo urbano.
Con el paso del tiempo, el monumento se convirtió en un punto de encuentro y referencia espacial para residentes y visitantes. El entorno inmediato reúne restaurantes, ferias de artesanía, ciclovías, espacios de estancia y establecimientos de hospedaje, manteniendo actividad constante durante el día y la noche. Esta dinámica fortalece el papel de los Arcos como elemento organizador del paisaje y como marcador identitario.','Más que una imagen emblemática, los Arcos del Paseo Marítimo de Atalaia sintetizan la transformación del frente costero en un espacio estructurado para la convivencia y el turismo. En diálogo con el mar, el movimiento urbano y la vida cotidiana, el monumento evidencia cómo la planificación, la infraestructura y la cultura local convergen en la construcción de la imagen contemporánea de Aracaju.
Elaboración propia, con base en información sectorial y en contenidos institucionales sobre el Paseo Marítimo de Atalaia.','cultura',-10.97610000,-37.05420000,'Orla de Atalaia, Aracaju - SE','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/c65e4084-5b5f-4da5-9006-0aa0d82c0d16", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/bd8b291f-5a45-4bfc-af36-06c29e625d1d", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "inline-2", "url": "/objects/uploads/0ee5f30c-e62c-40b4-9291-14efb8522145", "type": "inline", "order": 2, "inlinePosition": 3}, {"id": "gallery-0", "url": "/objects/uploads/bbd8362d-b0fc-45b7-9b55-746643c3a2ed", "type": "gallery", "order": 3}, {"id": "gallery-1", "url": "/objects/uploads/8952796c-a2b5-4974-b504-f45036fb77c5", "type": "gallery", "order": 4}, {"id": "gallery-2", "url": "/objects/uploads/78028a97-3f1b-43d6-b89f-aa5e1ddcc88e", "type": "gallery", "order": 5}, {"id": "gallery-3", "url": "/objects/uploads/aa9ae96f-4baf-48e3-bcb2-0d06d6a52109", "type": "gallery", "order": 6}]'::jsonb,'/objects/uploads/6a655a8f-adb1-4dd1-8fe2-b939c9cbbabe','','qr-d3c90f50-be00-41e5-a337-600aa8a67baa','https://maps.google.com/?q=-10.9761,-37.0542',true,'',true,true,'','{"tipo": "Marco arquitetônico", "acesso": "24 horas"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-03T14:32:13.635Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('d685f00b-f82c-4a16-b3b4-f010c03b3fb8','Oceanário da Aracaju (Projeto Tamar)','Oceanarium (Tamar Project)','Oceanario (Proyecto Tamar)','As atividades do Projeto Tamar em Sergipe tiveram início no início da década de 1980, consolidando o estado como área estratégica para a conservação das tartarugas marinhas no Brasil. Em 1982, foi instalada no município de Pirambu a primeira base do projeto no país, um marco relevante para a proteção dessas espécies no litoral brasileiro. Desde então, a atuação foi ampliada e, atualmente, Sergipe conta com três bases de pesquisa e conservação: Ponta dos Mangues, Pirambu e Abaís, além de um Centro de Visitantes em Aracaju. A capital é reconhecida como a capital de desova das tartarugas, principalmente da espécie tartaruga-oliva (Lepidochelys olivacea).
No estado, a Fundação Projeto Tamar monitora aproximadamente 150 quilômetros de praias, protegendo, a cada temporada reprodutiva, cerca de 8 mil ninhos e mais de 600 mil filhotes. Estima-se que aproximadamente 80% das desovas registradas em Sergipe sejam da espécie tartaruga-oliva, considerada a menor entre as tartarugas marinhas que ocorrem no Brasil. As ações envolvem monitoramento diário das praias, identificação e proteção de ninhos, manejo de filhotes e atividades permanentes de educação ambiental junto às comunidades costeiras.','O Centro de Visitantes de Aracaju, inaugurado em 2002, foi criado com o objetivo de divulgar as ações do projeto, além de apoiar atividades de pesquisa científica, educação ambiental e inclusão social desenvolvidas na região litorânea. Popularmente conhecido como Oceanário de Aracaju, o equipamento é reconhecido como o primeiro oceanário da região Nordeste, reunindo mais de 50 espécies de animais marinhos, de água doce e de ambientes de maior profundidade.
Localizado na Praia de Atalaia, a aproximadamente 500 metros da linha do mar, o complexo ocupa área de cerca de 141 mil metros quadrados, cedida pelo Governo Federal por meio de contrato firmado entre o Serviço de Patrimônio da União e a Fundação Projeto Tamar. A área construída soma aproximadamente 1.700 metros quadrados, com projeto arquitetônico concebido em formato de tartaruga marinha quando observado em vista aérea, reforçando o caráter temático e educativo do espaço.','Dessa forma, o Projeto Tamar em Sergipe consolida-se como referência nacional em conservação marinha, integrando pesquisa científica, proteção ambiental, educação e turismo sustentável. Sua atuação contribui significativamente para a preservação da biodiversidade costeira e para o fortalecimento da consciência ambiental no estado.
Elaboração própria, com base em informações institucionais da Fundação Projeto Tamar; dados divulgados pelo Centro de Visitantes/Oceanário de Aracaju; materiais técnicos e de educação ambiental do Projeto Tamar em Sergipe.','The activities of Projeto Tamar in Sergipe began in the early 1980s, positioning the state as a key area for sea turtle conservation in Brazil. In 1982, the project established its first base in the municipality of Pirambu, marking a significant milestone in the protection of these species along the Brazilian coastline. Since then, operations have expanded, and Sergipe now hosts three research and conservation bases: Ponta dos Mangues, Pirambu, and Abaís, along with a Visitor Center in Aracaju. The capital is recognized as a major nesting hub for sea turtles, particularly for the olive ridley species (Lepidochelys olivacea).
In the state, the Fundação Projeto Tamar monitors approximately 150 kilometers of beaches, protecting around 8,000 nests and over 600,000 hatchlings each reproductive season. It is estimated that about 80% of the nesting events recorded in Sergipe involve the olive ridley turtle, the smallest sea turtle species found in Brazil. Activities include daily beach monitoring, nest identification and protection, hatchling management, and ongoing environmental education initiatives with coastal communities.','The Aracaju Visitor Center, inaugurated in 2002, was established to promote its activities and support scientific research, environmental education, and social inclusion programs in the coastal region. Commonly referred to as the Aracaju Oceanarium, it is recognized as the first oceanarium in Brazil’s Northeast region and houses over 50 species of marine, freshwater, and deep-sea animals.
Located at Atalaia Beach, approximately 500 meters from the shoreline, the complex covers an area of about 141,000 square meters. This area was granted by the Federal Government through an agreement between the Secretariat of Federal Heritage (Serviço de Patrimônio da União) and Fundação Projeto Tamar. The built structure spans roughly 1,700 square meters and is designed to resemble a sea turtle when viewed from above, reinforcing the facility’s thematic and educational purpose.','In this context, Projeto Tamar in Sergipe has consolidated itself as a national reference in marine conservation, integrating scientific research, environmental protection, education, and sustainable tourism. Its work contributes significantly to the preservation of coastal biodiversity and to strengthening environmental awareness in the state.
Prepared based on institutional information from Fundação Projeto Tamar; data published by the Aracaju Visitor Center/Oceanarium; and technical and environmental education materials from Projeto Tamar in Sergipe.','Las actividades del Proyecto Tamar en Sergipe comenzaron a principios de la década de 1980, consolidando al estado como un área estratégica para la conservación de las tortugas marinas en Brasil. En 1982, se instaló en el municipio de Pirambu la primera base del proyecto en el país, un hito relevante para la protección de estas especies en el litoral brasileño. Desde entonces, su actuación se ha ampliado y actualmente Sergipe cuenta con tres bases de investigación y conservación: Ponta dos Mangues, Pirambu y Abaís, además de un Centro de Visitantes en Aracaju. La capital es reconocida como un importante polo de anidación, especialmente de la tortuga olivácea (Lepidochelys olivacea).
En el estado, la Fundación Proyecto Tamar monitorea aproximadamente 150 kilómetros de playas, protegiendo, en cada temporada reproductiva, cerca de 8.000 nidos y más de 600.000 crías. Se estima que alrededor del 80% de las anidaciones registradas en Sergipe corresponden a la tortuga olivácea, considerada la más pequeña entre las tortugas marinas que habitan en Brasil. Las acciones incluyen el monitoreo diario de las playas, la identificación y protección de nidos, el manejo de crías y actividades permanentes de educación ambiental junto a las comunidades costeras.','El Centro de Visitantes de Aracaju, inaugurado en 2002, fue creado con el objetivo de divulgar las acciones del proyecto, así como de apoyar actividades de investigación científica, educación ambiental e inclusión social desarrolladas en la región litoral. Conocido popularmente como el Oceanario de Aracaju, el equipamiento es reconocido como el primer oceanario de la región Nordeste de Brasil, que reúne más de 50 especies de animales marinos, de agua dulce y de ambientes de mayor profundidad.
Ubicado en la Playa de Atalaia, a aproximadamente 500 metros de la línea del mar, el complejo ocupa un área de cerca de 141.000 metros cuadrados, cedida por el Gobierno Federal mediante un contrato firmado entre el Servicio de Patrimonio de la Unión y la Fundación Proyecto Tamar. El área construida suma aproximadamente 1.700 metros cuadrados, con un proyecto arquitectónico concebido en forma de tortuga marina cuando se observa desde una perspectiva aérea, lo que refuerza el carácter temático y educativo del espacio.','De este modo, el Proyecto Tamar en Sergipe se consolida como referencia nacional en conservación marina, integrando investigación científica, protección ambiental, educación y turismo sostenible. Su actuación contribuye significativamente a la preservación de la biodiversidad costera y al fortalecimiento de la conciencia ambiental en el estado.
Elaboración propia, con base en información institucional de la Fundación Proyecto Tamar; datos divulgados por el Centro de Visitantes/Oceanario de Aracaju; y en materiales técnicos y de educación ambiental del Proyecto Tamar en Sergipe.','cultura',-10.94670000,-37.07280000,'Av. Santos Dumont, Orla de Atalaia, Aracaju - SE','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/2f324a52-fd91-43b0-9d6e-79584ad38f68", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/b75c4448-6ea4-4abd-bbff-87b84edccc30", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "gallery-0", "url": "/objects/uploads/3df001d0-75f2-4ea4-aa76-d87aca4b4686", "type": "gallery", "order": 2}, {"id": "gallery-1", "url": "/objects/uploads/3beea99f-874d-4870-863d-01bacd2ff867", "type": "gallery", "order": 3}, {"id": "gallery-2", "url": "/objects/uploads/43d0f6ee-bf99-43e9-aa35-20eee21fe829", "type": "gallery", "order": 4}, {"id": "gallery-3", "url": "/objects/uploads/1f31db50-9fbd-4db6-81a8-8b2d22fe1f5d", "type": "gallery", "order": 5}]'::jsonb,'/objects/uploads/ba7eecdc-c5e0-4bb0-9b85-9e38895d79f6','','qr-a31497c7-d696-49e7-aa4e-252a058a4837','https://maps.app.goo.gl/ajQd3T9tNM2sBPUZ7',true,'Terça à domingo: 10h às 17h',false,false,'Inteira: R$44,00; Meia-entrada: R$22,00 (válida para estudantes, idosos 60+, professores, ID Jovem e crianças a partir dos 6 anos); Gratuidade para crianças de até 5 anos e pessoas com deficiência','{"entrada": "Gratuita", "horarios": "Terça a domingo, 9h às 17h", "programas": "Educacionais"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-03T14:43:11.073Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('9750a422-1274-41b5-a96b-6edb80e83f9d','Formadores da Nacionalidade','Sculpture Set "Preceptors of the Nationality"','Conjunto de Esculturas "Formadores de la Nacionalidad"','Caminhar pela Orla de Atalaia é vivenciar um dos principais espaços públicos de Aracaju, onde a paisagem litorânea, o lazer e o fluxo turístico se articulam de forma intensa. Entre equipamentos urbanos e áreas de convivência, o Espaço Formadores da Nacionalidade introduz uma dimensão histórica ao passeio, integrando arte pública, educação patrimonial e memória coletiva no cotidiano da cidade.
Inaugurado em 2006, o conjunto escultórico reúne representações de personagens associados à formação política e institucional do Brasil, entre eles Tiradentes, Dom Pedro II, Getúlio Vargas, Juscelino Kubitschek, Barão do Rio Branco, Duque de Caxias, José Bonifácio de Andrade e Silva e Princesa Isabel. Em 2012, foi incorporada a escultura de Zumbi dos Palmares, ampliando a diversidade de referências históricas contempladas no espaço. As obras são de autoria do artista plástico Leo Santana, que concebeu o projeto com a proposta de valorizar figuras vinculadas à construção política, diplomática e social do país.','O conjunto é reconhecido como patrimônio cultural, tendo sido tombado pelo Decreto nº 24.148, de 21 de dezembro de 2006, com inscrição no Livro de Tombo nº 01 – Geral, às folhas 40. O ato de tombamento assegura proteção jurídica ao bem, reforçando seu caráter simbólico e histórico e garantindo sua preservação como parte integrante do acervo cultural do município.
Inserido em um dos principais polos turísticos da capital, o espaço amplia a função da Orla de Atalaia para além do lazer e do entretenimento. Ao apresentar esculturas de personagens que marcaram diferentes períodos da história nacional, o conjunto estimula reflexão sobre os processos de formação do Estado brasileiro e sobre as múltiplas narrativas que compõem essa trajetória.','Dessa forma, o Espaço Formadores da Nacionalidade consolida-se como um equipamento cultural que articula turismo, educação e patrimônio em ambiente aberto e acessível. Sua presença contribui para qualificar a experiência urbana na orla, fortalecendo a dimensão histórica do espaço público e promovendo o contato da população e dos visitantes com referências fundamentais da história do Brasil.
Elaboração própria, com base em informações institucionais da Prefeitura de Aracaju (2015), no Decreto nº 24.148/2006 e em registros oficiais de tombamento municipal.','Walking along Atalaia Seafront offers a unique experience in one of Aracaju’s key public spaces, where the coastal landscape merges with leisure activities and vibrant tourism. This promenade features various urban facilities and recreational areas, and the Preceptors of the Nationality Space adds a historical dimension, integrating public art, heritage education, and collective memory into the city’s daily life.
Inaugurated in 2006, this sculptural ensemble showcases figures crucial to Brazil’s political and institutional history, including Tiradentes, Dom Pedro II, Getúlio Vargas, Juscelino Kubitschek, the Baron of Rio Branco, the Duke of Caxias, José Bonifácio de Andrade e Silva, and Princess Isabel. In 2012, a sculpture of Zumbi dos Palmares was incorporated, expanding the historical representation within the space. The artwork was created by visual artist Leo Santana, who designed the project to emphasize figures linked to the nation’s political, diplomatic, and social development.','The ensemble is officially recognized as cultural heritage, having been listed under Municipal Decree No. 24,148, dated December 21, 2006, and recorded in the Official Heritage Registry Book No. 01 – General, page 40. This designation provides legal protection, reinforcing the site’s symbolic and historical character and ensuring its preservation as part of the municipality’s cultural assets.
Located within one of the capital’s main tourist hubs, the space expands the function of Atalaia Waterfront beyond recreation and entertainment. By presenting sculptures of figures who shaped different periods of national history, the ensemble encourages reflection on the processes that formed the Brazilian State and on the multiple narratives that compose this trajectory.','In this context, the Preceptors of the Nationality Space stands as a cultural facility that brings together tourism, education, and heritage in an open and accessible environment. Its presence enhances the urban experience along the Waterfront, strengthening the historical dimension of public space and promoting engagement with key references in Brazil’s history.
Prepared by the author, based on Institutional information from the Municipal Government of Aracaju (2015), Municipal Decree No. 24,148/2006, and official municipal heritage listing records.','Recorrer la Orla de Atalaia es experimentar uno de los principales espacios públicos de Aracaju, donde el paisaje costero, el ocio y el flujo turístico se articulan de manera intensa. Entre equipamientos urbanos y áreas de convivencia, el Espacio Formadores de la Nacionalidad incorpora una dimensión histórica al paseo, integrando arte público, educación patrimonial y memoria colectiva en la vida cotidiana de la ciudad.
Inaugurado en 2006, el conjunto escultórico reúne representaciones de figuras asociadas a la formación política e institucional de Brasil, entre ellas Tiradentes, Dom Pedro II, Getúlio Vargas, Juscelino Kubitschek, el Barón de Rio Branco, el Duque de Caxias, José Bonifácio de Andrade e Silva y la Princesa Isabel. En 2012 se incorporó la escultura de Zumbi dos Palmares, lo que amplió la representatividad histórica del espacio. Las obras son de autoría del artista plástico Leo Santana, quien desarrolló el proyecto con el objetivo de valorizar personajes vinculados a la construcción política, diplomática y social del país.','El conjunto está reconocido como patrimonio cultural, habiendo sido protegido por el Decreto Municipal nº 24.148, de 21 de diciembre de 2006, con inscripción en el Libro de Registro nº 01 – General, hoja 40. Este acto de protección garantiza su preservación jurídica y reforza el carácter simbólico e histórico del espacio como parte del acervo cultural del municipio.
Insertado en uno de los principales polos turísticos de la capital, el espacio amplía la función de la Orla de Atalaia más allá del ocio y el entretenimiento. Al presentar esculturas de personajes que marcaron distintos períodos de la historia nacional, el conjunto estimula la reflexión sobre los procesos de formación del Estado brasileño y las múltiples narrativas que integran esa trayectoria.','De este modo, el Espacio Formadores de la Nacionalidad se consolida como equipamiento cultural que articula turismo, educación y patrimonio en un entorno abierto y accesible. Su presencia contribuye a cualificar la experiencia urbana en la orla, fortaleciendo la dimensión histórica del espacio público y promoviendo el contacto de la población y de los visitantes con referencias fundamentales de la historia de Brasil.
Elaboración propia, basada en información institucional de la Prefeitura de Aracaju (2015), en el Decreto nº 24.148/2006 y en registros oficiales de catalogación municipal.','cultura',-10.97600000,-37.05600000,'Orla Marítima de Aracaju, Praia de Atalaia','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/11b26e3b-f4b1-433e-89e7-46b578ff23d3", "type": "gallery", "order": 0}]'::jsonb,'/objects/uploads/48fc30bb-086f-4256-9142-06790ceb4b52','','qr-ed3f3650-1e15-4875-bb6f-a387ff917659','https://share.google/hA6HUzJba7lgYDJ88',true,'',true,true,'','{"tipo": "Conjunto de esculturas", "autoria": "Artista plástico Leo Santana", "tombamento": "Decreto nº 24.148, de 21 de dezembro de 2006"}'::jsonb,'2025-09-25 14:33:48.588717+00','2026-03-03T14:48:44.730Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('98c20f0f-14a3-418e-b598-a920c3f6812b','Orla Pôr do Sol','Orla Pôr do Sol (Sunset Waterfront)','Orla Pôr do Sol (Paseo Costero del Atardecer)','Ao final da tarde, às margens do Rio Vaza-Barris, a luz se transforma lentamente. O sol desce no horizonte, o céu assume tons quentes que se refletem na superfície do rio e o ritmo do entorno desacelera. Nesse cenário, a Orla Pôr do Sol se destaca como um dos espaços mais singulares de Aracaju, onde a paisagem ribeirinha, o uso público e a contemplação se articulam de maneira integrada.
Situada no bairro Mosqueiro, a orla foi estruturada como equipamento urbano voltado à valorização do ambiente natural e à oferta de lazer para moradores e visitantes. Diferentemente da Orla de Atalaia, marcada por maior adensamento e intensa dinâmica turística, a Orla Pôr do Sol apresenta um perfil associado ao turismo de contemplação e ao contato direto com a natureza, preservando características do cotidiano ribeirinho.','A infraestrutura instalada favorece a permanência e circulação qualificada. O espaço conta com quiosques, áreas para caminhada, ciclovia, píer e embarcações que realizam passeios fluviais, especialmente ao pôr do sol. Esses trajetos permitem observar a vegetação de mangue, a fauna local e a dinâmica das marés no estuário do Rio Vaza-Barris, compondo uma experiência paisagística que se consolidou como um dos principais atrativos da capital.
A partir dali, também se organizam roteiros náuticos com destino à Ilha da Croa do Goré e à Ilha dos Namorados, ampliando a integração da orla com circuitos de turismo ecológico e de base natural. Essa articulação reforça o papel do espaço como ponto de conexão entre o ambiente urbano e os ecossistemas costeiros do município.','Vivenciar a Orla Pôr do Sol significa experimentar Aracaju sob uma perspectiva mais sensível e contemplativa. O local reafirma a relação histórica da cidade com seus rios, valoriza o patrimônio ambiental e diversifica a oferta turística, contribuindo para um modelo que combina lazer, sustentabilidade e qualidade de vida no território urbano.
Elaboração própria, com base em informações institucionais e materiais de divulgação turística do Município de Aracaju.','In the late afternoon, along the banks of the Rio Vaza-Barris (Vaza-Barris River), the light changes gradually. The sun lowers toward the horizon, warm tones spread across the sky and reflect on the water, and the pace of the surroundings slows. In this setting, Orla Pôr do Sol stands out as one of Aracaju’s most distinctive public spaces, where riverside landscape, recreation, and contemplation come together in balance.
Located in Bairro Mosqueiro, the waterfront was structured as an urban facility designed to value the natural environment while offering leisure opportunities for residents and visitors. Unlike the Orla de Atalaia (Atalaia Waterfront), known for its denser urbanization and intense tourism flow, Orla Pôr do Sol is associated with a quieter profile, focused on scenic appreciation and direct contact with nature, while preserving aspects of the local riverside way of life.','Its infrastructure supports both circulation and longer stays. The area includes kiosks, walking paths, a bike lane, a pier, and boats that operate river tours, particularly at sunset. These outings allow visitors to observe mangrove vegetation, local fauna, and the tidal dynamics of the Rio Vaza-Barris estuary, creating a landscape experience that has become one of the capital’s notable attractions.
From this point, nautical routes also depart toward Ilha da Croa do Goré (Croa do Goré Island) and Ilha dos Namorados (Lovers’ Island), strengthening the integration of the waterfront with ecological and nature-based tourism circuits. This connection reinforces the site’s role as a gateway between the urban environment and the municipality’s coastal ecosystems.','Experiencing Orla Pôr do Sol offers a more contemplative perspective of Aracaju. The area highlights the city’s historical relationship with its rivers, values its natural heritage, and broadens the diversity of the tourism offer, contributing to an approach that combines leisure, sustainability, and quality of life within the urban territory.
Prepared based on institutional information and tourism materials from the Municipality of Aracaju.','Al final de la tarde, a orillas del Rio Vaza-Barris (Río Vaza-Barris), la luz cambia de manera gradual. El sol desciende por el horizonte, el cielo se tiñe de tonos cálidos que se reflejan en el agua y el ritmo del entorno se vuelve más pausado. En ese escenario, la Orla Pôr do Sol se consolida como uno de los espacios públicos más singulares de Aracaju, donde el paisaje ribereño, la recreación y la contemplación se articulan de forma equilibrada.
Ubicada en el Bairro Mosqueiro, la orla fue concebida como equipamiento urbano orientado a la valorización del entorno natural y a la oferta de ocio para residentes y visitantes. A diferencia de la Orla de Atalaia (Paseo Marítimo de Atalaia), caracterizada por mayor urbanización y flujo turístico intenso, la Orla Pôr do Sol presenta un perfil más tranquilo, asociado al turismo de contemplación y al contacto directo con la naturaleza, manteniendo rasgos del cotidiano ribereño.','La infraestructura favorece tanto la circulación como la permanencia. El espacio dispone de quioscos, senderos peatonales, ciclovía, muelle y embarcaciones que realizan paseos fluviales, especialmente al atardecer. Estos recorridos permiten observar la vegetación de manglar, la fauna local y la dinámica de las mareas en el estuario del Rio Vaza-Barris, configurando una experiencia paisajística que se ha convertido en uno de los atractivos destacados de la capital.
Desde este punto también parten rutas náuticas hacia la Ilha da Croa do Goré (Isla Croa do Goré) y la Ilha dos Namorados (Isla de los Enamorados), lo que amplía la integración de la orla con circuitos de turismo ecológico y de base natural. Esta articulación refuerza su papel como conexión entre el entorno urbano y los ecosistemas costeros del municipio.','Recorrer la Orla Pôr do Sol permite experimentar Aracaju desde una perspectiva más serena y contemplativa. El espacio reafirma la relación histórica de la ciudad con sus ríos, pone en valor su patrimonio ambiental y diversifica la oferta turística, contribuyendo a un modelo que combina ocio, sostenibilidad y calidad de vida en el territorio urbano.
Elaborado con base en información institucional y en materiales de promoción turística del Municipio de Aracaju.','praia',-11.10086040,-37.15007180,'Av. Dr. José Emídio do Nascimento, 218 - Mosqueiro, Aracaju - SE, 49008-680','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/fda86314-b32f-4435-a2e8-4f73080aed46.jpg','','qr-08c99373-e220-427a-b621-9bf9a59fa48d','https://maps.app.goo.gl/zQHuTdYSFBM9kzRv7',true,'',true,true,'','{}'::jsonb,'2025-11-25 11:59:23.481072+00','2026-03-02T12:09:49.578Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('b4ca5a0b-0fc8-481d-8675-96f50f1d2d20','Kartódromo Emerson Fittipaldi','Emerson Fittipaldi Karting Track','Kartódromo Emerson Fittipaldi','Ao caminhar pela Orla de Atalaia, entre hotéis, áreas de lazer e o fluxo constante de visitantes, o som dos motores revela uma presença pouco convencional no cenário litorâneo. Nesse contexto, o Kartódromo Emerson Fittipaldi amplia os usos da orla e reforça a inserção de Aracaju no circuito do automobilismo.
Situado na Praia de Atalaia, o equipamento é de propriedade privada e está sob administração da Associação Sergipana de Kart (ASK), criada em 1970. Ocupa aproximadamente 40.000 m² e reúne infraestrutura compatível com competições oficiais: 34 boxes fechados, 40 abertos, torre de cronometragem, sala de imprensa e iluminação para provas noturnas. A pista, com 1.360 metros de extensão e oito metros de largura, atende às exigências técnicas da modalidade.','A localização estratégica constitui um diferencial relevante. Inserido em uma zona que concentra cerca de 2.800 leitos hoteleiros, o kartódromo cria condições favoráveis para sediar eventos esportivos de maior porte, ao integrar logística, hospedagem e estrutura técnica em um mesmo território. Esse arranjo contribui para fortalecer o turismo esportivo e diversificar a matriz de oferta da capital sergipana.','Mais do que um espaço de competição, o kartódromo representa uma ampliação da experiência urbana na Orla de Atalaia. Ao lado do turismo de sol e praia, incorpora práticas esportivas e eventos ao cotidiano do litoral, demonstrando como infraestrutura, território e lazer podem coexistir de forma articulada.
Elaboração própria, com base em informações institucionais e setoriais (Kartmotor; Associação Sergipana de Kart).','Walking along the Atalaia Waterfront, amid hotels, leisure facilities, and the steady movement of visitors, the distinctive sound of engines signals a different dimension of the coastal landscape. Within this setting, the Emerson Fittipaldi Kartodrome expands the waterfront''s services and strengthens Aracaju’s connection to motorsport.
Located at Atalaia Beach, the facility is privately owned and operated by the Associação Sergipana de Kart (ASK), established in 1970. The site covers approximately 40,000 m² and provides infrastructure suitable for official competitions, including 34 enclosed pit boxes, 40 open pit boxes, a timing tower, a press room, and lighting for night races. The 1,360-meter track, eight meters wide, meets the technical standards required for the sport.','Its prime location is a valuable asset. Situated in a zone that houses approximately 2,800 hotel beds, the kartodrome provides ideal logistical conditions for hosting major sporting events by combining technical facilities and lodging in one area. This setup promotes sports tourism and helps broaden the range of tourism options available in the city.','Beyond competition, the kartodrome broadens the urban experience along the Atalaia Waterfront. Alongside sun-and-beach tourism, it introduces sporting events and motor racing into the coastal dynamic, demonstrating how infrastructure, territory, and leisure can operate in an integrated manner.
Formulated based on institutional and sectoral information (Kartmotor; Associação Sergipana de Kart).','Al recorrer el Paseo Marítimo de Atalaia, entre hoteles, espacios de ocio y el movimiento constante de visitantes, el sonido de los motores introduce una dimensión distinta al paisaje costero. En ese contexto, el Kartódromo Emerson Fittipaldi amplía los usos del frente marítimo y refuerza el vínculo de Aracaju con el automovilismo.
Situado en la Playa de Atalaia, el equipamiento es de propiedad privada y está administrado por la Associação Sergipana de Kart (ASK), creada en 1970. Ocupa alrededor de 40.000 m² y dispone de infraestructura adecuada para competiciones oficiales: 34 boxes cerrados, 40 boxes abiertos, torre de cronometraje, sala de prensa e iluminación para pruebas nocturnas. La pista, de 1.360 metros de longitud y 8 metros de ancho, cumple con los estándares técnicos de la modalidad.','Su ubicación estratégica constituye un diferencial relevante. Al integrarse en un área que concentra aproximadamente 2.800 plazas hoteleras, el kartódromo reúne condiciones logísticas favorables para albergar eventos deportivos de mayor escala, articulando la infraestructura técnica y el hospedaje en un mismo territorio. Esta configuración fortalece el turismo deportivo y contribuye a diversificar la oferta turística de la capital sergipana.','Más allá de la competencia, el espacio amplía la experiencia urbana en el Paseo Marítimo de Atalaia. Junto al turismo de sol y playa, incorpora eventos deportivos y actividades vinculadas al automovilismo, lo que demuestra cómo la infraestructura, el territorio y el ocio pueden integrarse de manera coherente.
Elaboración propia, con base en información institucional y sectorial (Kartmotor; Associação Sergipana de Kart).','',-10.98240440,-37.04264180,'Av. Santos Dumont, s/n - Atalaia, Aracaju - SE, 49037-475','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/a0158615-5b74-4768-ba06-934947bf161a", "type": "gallery", "order": 0}]'::jsonb,'/objects/uploads/8a0b62f2-29af-4e9c-93ff-c46705a387fd','','qr-982144a7-9852-456b-a4da-f065578b6f86','https://maps.app.goo.gl/iFn18UwEhy3dWPBt9',true,'Seg a sáb: 18h às 22h Domingo: 15h às 22h',false,false,'','{}'::jsonb,'2025-11-25 12:05:54.690786+00','2026-03-03T14:06:31.040Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('160065b1-4eec-4142-94e5-9ebe03f4712a','Monumento à Maçonaria','Monument to the Freemasonry ','Monumento a la Masonería','Localizado na região da Praia de Atalaia, em Aracaju, o Monumento Maçônico integra o conjunto de marcos simbólicos que compõem a orla da capital. A obra traduz, em linguagem arquitetônica, princípios associados à tradição maçônica, com ênfase na simbologia do número três, elemento estruturante de sua filosofia.
Na Maçonaria, a tríade representa equilíbrio e harmonia. O número três aparece de forma recorrente em diferentes sistemas simbólicos, como Início, Meio e Fim; Nascimento, Vida e Morte; ou ainda na tradição cristã da Santíssima Trindade. Na alquimia, a combinação de Sal, Enxofre e Mercúrio expressava princípios fundamentais de transformação. Esses referenciais ajudam a compreender a centralidade do três como ideia de unidade construída a partir da convergência de elementos distintos.','Em Sergipe, a organização maçônica estruturou-se inicialmente sob a jurisdição do Grande Oriente do Brasil. Com a posterior criação da Grande Loja Maçônica do Estado de Sergipe, consolidou-se uma nova configuração institucional no território. A coexistência dessas duas potências contribuiu para o fortalecimento da Maçonaria local, contexto que dialoga simbolicamente com o conceito da tríade representado no monumento.
A composição arquitetônica reforça essa simbologia. A estrutura apresenta forma triangular, com três lados iguais, e um dos vértices orientado para o alto, indicando a busca pelo conhecimento e pelo aperfeiçoamento moral. No conjunto visual, destacam-se o Esquadro, o Compasso e a letra “G”, referências tradicionais da iconografia maçônica, associadas à retidão, à justiça e ao Grande Arquiteto do Universo. A inscrição “Liberdade, Igualdade e Fraternidade” sintetiza valores historicamente vinculados à Ordem.','Inserido na paisagem da Orla de Atalaia, o Monumento Maçônico ultrapassa a função estética e assume um caráter representativo. Ao materializar símbolos e fundamentos filosóficos da instituição no contexto urbano, estabelece um diálogo entre o espaço público, a memória associativa e a identidade cultural presentes na capital sergipana.
Elaboração própria, com base em Novaes (2019).','Located in the Praia de Atalaia area, in Aracaju, the Monumento à Maçonaria is one of the symbolic landmarks integrated into the capital’s waterfront landscape. The structure translates principles of Masonic tradition into architectural form, emphasizing the symbolism of the number three, a foundational concept in Masonic philosophy.
In Freemasonry, the triad represents balance and harmony. The number three recurs across different symbolic systems, including Beginning, Middle, and End; Birth, Life, and Death; and, in Christian tradition, the Holy Trinity. In alchemy, Salt, Sulfur, and Mercury symbolized essential principles of transformation. These references help explain the centrality of three as an expression of unity formed through the convergence of distinct elements.','In Sergipe, the Masonic organization was initially structured under the jurisdiction of the Grande Oriente do Brasil. The later creation of the Grande Loja Maçônica do Estado de Sergipe (The Great Masonic Store of the State of Sergipe) established a new institutional framework within the state. The coexistence of these two governing bodies contributed to the consolidation of Freemasonry in the region, a historical context that symbolically echoes the triad concept represented in the monument.
Architecturally, the structure reinforces this symbolism. Designed in a triangular form with three equal sides, it features a vertex oriented upward, suggesting the pursuit of knowledge and moral improvement. Prominently displayed are the Square, the Compass, and the letter “G,” traditional elements of Masonic iconography associated with moral rectitude, justice, and the Great Architect of the Universe. The inscription “Liberdade, Igualdade e Fraternidade” (“Liberty, Equality and Fraternity”) synthesizes values historically linked to the Masonic Order.','In Sergipe, the Masonic organization initially operated under the jurisdiction of the Grande Oriente do Brasil. The later creation of the Grande Loja Maçônica do Estado de Sergipe established a new institutional framework within the state. The coexistence of these two governing bodies contributed to the consolidation of Freemasonry locally, a historical development that symbolically resonates with the monument’s triadic concept.
Architecturally, the structure reinforces this symbolism. Designed in a triangular form with three equal sides, it features a vertex oriented upward, suggesting the pursuit of knowledge and moral improvement. Prominently displayed are the Square, the Compass, and the letter “G,” traditional elements of Masonic iconography associated with moral rectitude, justice, and the Great Architect of the Universe. The inscription “Liberdade, Igualdade e Fraternidade” (“Liberty, Equality and Fraternity”) synthesizes values historically linked to the Masonic Order.','El Monumento Masónico, ubicado en la región de la Playa de Atalaia, en Aracaju, constituye una representación simbólica de los principios y fundamentos de la Masonería, con especial énfasis en la importancia del número tres en la tradición masónica. La tríada es un elemento recurrente en la filosofía simbólica de la Orden, que aparece en diversas dimensiones interpretativas y estructurales.
En la tradición masónica, así como en referencias culturales y religiosas más amplias, el número tres representa equilibrio, plenitud y armonía. Se observa su presencia en concepciones como Inicio, Medio y Fin; Nacimiento, Vida y Muerte; así como en la simbología cristiana de la Santísima Trinidad. En la alquimia, la tríada Sal, Azufre y Mercurio simbolizaba principios esenciales de la transformación. Estos referentes ayudan a comprender la centralidad del tres como expresión de una unidad construida a partir de la convergencia de fuerzas distintas.','En el contexto sergipano, la organización masónica se estructuró inicialmente bajo la jurisdicción del Gran Oriente de Brasil. Posteriormente, con la creación de la Gran Logia Masónica del Estado de Sergipe, se consolidó una nueva configuración institucional. La coexistencia de estas dos potencias contribuyó al fortalecimiento de la Masonería en el estado, formando simbólicamente una tercera fuerza representativa de la Masonería Sergipana, idea que dialoga directamente con el concepto de la tríada.','Arquitectónicamente, el monumento presenta forma triangular, con tres lados iguales, lo que refuerza visualmente esta simbología. Uno de sus vértices está orientado hacia lo alto, representando la búsqueda del Infinito y del conocimiento trascendente. Destaca también el conjunto simbólico tradicional compuesto por la Escuadra, el Compás y la letra “G”, elementos que remiten a la rectitud moral, la justicia y la creencia en el Gran Arquitecto del Universo. La base conceptual se complementa con las palabras Libertad, Igualdad y Fraternidad, principios que sintetizan los ideales de la Masonería a nivel mundial.
Así, el Monumento Masónico de la Orla de Atalaia no se configura solamente como un elemento paisajístico, sino como representación material de los fundamentos filosóficos e históricos de la Masonería en Sergipe, traduciendo en forma arquitectónica los valores y símbolos que estructuran la institución.
Elaboración propia con base en Novaes (2019).','cultura',-10.97923770,-37.04183960,'','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/41e7903b-2f96-4adb-9db7-6ec12403e5f5", "type": "gallery", "order": 0}, {"id": "gallery-1", "url": "/objects/uploads/cfaa0c15-6ac1-48c9-b8c6-e21a745b33f1", "type": "gallery", "order": 1}, {"id": "gallery-2", "url": "/objects/uploads/9b79fff9-5e81-412e-b75e-e0ebf199ed7e", "type": "gallery", "order": 2}, {"id": "gallery-3", "url": "/objects/uploads/67a9cc80-9686-4f50-9c1d-5262d5d146be", "type": "gallery", "order": 3}]'::jsonb,'/objects/uploads/450f1fa4-3fd1-4e20-9e29-d233866e5378','','qr-f793546c-1519-4da4-82db-4bf4ba5250f8','https://maps.app.goo.gl/esN6kA9UQmdx5hiL9',true,'',true,true,'','{}'::jsonb,'2025-11-25 12:16:06.124944+00','2026-03-03T12:48:22.858Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('2601af90-dd7b-4d36-81ac-b42a4e31ae92','Memorial de Sergipe','Memorial de Sergipe','Memorial de Sergipe','Atravessar as portas do Memorial de Sergipe é ingressar em um espaço onde passado e presente dialogam de forma permanente. Logo na entrada, fotografias, objetos e registros históricos conduzem o visitante por uma narrativa que evidencia tradições, transformações sociais e manifestações culturais que marcaram a formação do estado. O equipamento foi concebido para preservar, organizar e difundir referências fundamentais da identidade sergipana.
Idealizado pelo educador e reitor da Universidade Tiradentes, Jouberto Uchôa de Mendonça, o Memorial foi inaugurado em 20 de janeiro de 1998 com a missão de reunir, proteger e divulgar o patrimônio histórico-cultural de Sergipe. Em outubro de 2023, o espaço foi reinaugurado após um processo de modernização estrutural e museográfica, incorporando novos recursos expositivos e reforçando seu papel como centro de interpretação da história estadual.','Mantido como realização do Instituto de Tecnologia e Pesquisa (ITP), o Memorial abriga um acervo diversificado que inclui peças arqueológicas, fósseis, documentos raros, fotografias históricas e coleções vinculadas a artistas e personalidades relevantes para a cultura sergipana. A organização temática das exposições favorece a compreensão de diferentes períodos históricos e expressões identitárias, permitindo uma leitura estruturada da trajetória social, política e cultural do estado.
A proposta museológica articula a preservação patrimonial e recursos contemporâneos de comunicação, proporcionando uma experiência acessível e didática. O espaço cumpre função educativa ao atender estudantes, pesquisadores e visitantes em geral, contribuindo para a formação de consciência histórica e para a valorização do patrimônio material e imaterial.','Dessa forma, o Memorial de Sergipe consolida-se como referência cultural e educativa, integrando memória, pesquisa e difusão do conhecimento. Ao fortalecer a preservação e a interpretação do patrimônio estadual, o equipamento amplia a oferta cultural de Aracaju e contribui para a qualificação da experiência turística vinculada à história e à identidade sergipana.
Elaboração própria, com base em informações institucionais do Memorial de Sergipe, dados divulgados pelo Instituto de Tecnologia e Pesquisa (ITP) e registros oficiais de inauguração (1998) e reinauguração (2023).','Crossing the doors of the Memorial de Sergipe means entering a space where past and present are in constant dialogue. From the entrance, photographs, objects, and historical records guide visitors through a narrative that highlights traditions, social transformations, and cultural expressions that shaped the state’s formation. The institution was conceived to preserve, organize, and disseminate key references to Sergipe’s identity.
Conceived by educator and rector of Universidade Tiradentes, Jouberto Uchôa de Mendonça, the Memorial was inaugurated on January 20, 1998, with the mission of gathering, protecting, and promoting Sergipe’s historical and cultural heritage. In October 2023, the space was reopened following a structural and museographic modernization process, incorporating new exhibition resources and reinforcing its role as a center for interpreting the state’s history.','Maintained as an initiative of the Instituto de Tecnologia e Pesquisa (ITP), the Memorial houses a diverse collection that includes archaeological artifacts, fossils, rare documents, historical photographs, and collections linked to artists and personalities relevant to Sergipe’s cultural life. The thematic organization of the exhibitions enables visitors to understand different historical periods and identity expressions, providing a structured reading of the state’s social, political, and cultural trajectory.
The museological approach combines heritage preservation with contemporary communication resources, offering an accessible and educational experience. The institution fulfills an important educational role by serving students, researchers, and the general public, contributing to the development of historical awareness and appreciation of both tangible and intangible heritage.','In this context, the Memorial de Sergipe has established itself as a cultural and educational reference point, integrating memory, research, and knowledge dissemination. By strengthening the preservation and interpretation of state heritage, the institution expands Aracaju’s cultural offerings and enhances the tourism experience connected to Sergipe’s history and identity.
Prepared by the author based on Institutional information from the Memorial de Sergipe; data published by the Instituto de Tecnologia e Pesquisa (ITP); official records of inauguration (1998) and reopening (2023).','Atravesar las puertas del Memorial de Sergipe es ingresar en un espacio donde el pasado y el presente dialogan de manera permanente. Desde la entrada, fotografías, objetos y registros históricos conducen al visitante por una narrativa que evidencia tradiciones, transformaciones sociales y manifestaciones culturales que marcaron la formación del Estado. El equipamiento fue concebido con el fin de preservar, organizar y difundir referencias fundamentales de la identidad sergipana.
Ideado por el educador y rector de la Universidade Tiradentes, Jouberto Uchôa de Mendonça, el Memorial fue inaugurado el 20 de enero de 1998 con la misión de reunir, proteger y divulgar el patrimonio histórico-cultural de Sergipe. En octubre de 2023, el espacio fue reinaugurado tras un proceso de modernización estructural y museográfica, que incorporó nuevos recursos expositivos y reforzó su papel como centro de interpretación de la historia estadual.','Mantenido como una iniciativa del Instituto de Tecnología e Investigación (ITP), el Memorial alberga un acervo diversificado que incluye piezas arqueológicas, fósiles, documentos raros, fotografías históricas y colecciones vinculadas a artistas y personalidades relevantes para la cultura sergipana. La organización temática de las exposiciones facilita la comprensión de diferentes períodos históricos y expresiones identitarias, lo que permite una lectura estructurada de la trayectoria social, política y cultural del Estado.
La propuesta museológica articula la preservación patrimonial con recursos contemporáneos de comunicación, ofreciendo una experiencia accesible y didáctica. El espacio cumple una función educativa al atender a estudiantes, investigadores y al público en general, contribuyendo a la formación de conciencia histórica y a la valorización del patrimonio material e inmaterial.','De este modo, el Memorial de Sergipe se consolida como referencia cultural y educativa, integrando memoria, investigación y difusión del conocimiento. Al fortalecer la preservación y la interpretación del patrimonio estadual, el equipamiento amplía la oferta cultural de Aracaju y contribuye a cualificar la experiencia turística vinculada a la historia y la identidad sergipana.
Elaboración propia con base en información institucional del Memorial de Sergipe, datos divulgados por el Instituto de Tecnología e Investigación (ITP) y registros oficiales de inauguración (1998) y reinauguración (2023).','historico',-10.97500160,-37.03782750,'Av. Santos Dumont, 100 - Coroa do Meio, Aracaju - SE, 49037-475','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/45b759b6-cf10-48cd-a6ae-7de2a056ecf8", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/a02ad437-f72c-4865-bf30-11fcda1d6013", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "inline-2", "url": "/objects/uploads/d7c28f62-1a06-41f3-9f36-dbbc1b8a624e", "type": "inline", "order": 2, "inlinePosition": 3}, {"id": "gallery-0", "url": "/objects/uploads/84aba3c0-9861-4d80-886c-f7f3544f8396", "type": "gallery", "order": 3}, {"id": "gallery-1", "url": "/objects/uploads/d9e39248-dbcf-4582-b8ef-4c6b25f2b76c", "type": "gallery", "order": 4}, {"id": "gallery-2", "url": "/objects/uploads/7ae21543-64ff-4ba6-a682-0985a43cc1d0", "type": "gallery", "order": 5}, {"id": "gallery-3", "url": "/objects/uploads/76bd2831-d6e0-4c0d-9696-6eec142e94ca", "type": "gallery", "order": 6}, {"id": "gallery-4", "url": "/objects/uploads/56c536ed-c3b0-4ba9-9ec2-f96a2540f761", "type": "gallery", "order": 7}]'::jsonb,'/objects/uploads/13edd7df-9858-4a9d-bdbd-f86426159a61','','qr-7cff1dd9-1e8e-4698-9af8-3547860cabc6','https://maps.app.goo.gl/NkbfAagFhhCSVzN69',true,'Terça à Sábado:	10h às 16h ',false,false,'Inteira: R$30,00; Meia-entrada: R$15,00','{}'::jsonb,'2025-11-25 12:23:30.90205+00','2026-03-02T17:20:53.772Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('62ca0d1b-114a-4e2f-8178-1edad5abf23b','Monumento Maria Feliciana ','Maria Feliciana Monument','Monumento Maria Feliciana','Caminhar pela Praça Laudelino Graciliano Mateus ao final da tarde é vivenciar um espaço de convivência que articula lazer, memória e requalificação urbana. Crianças ocupam o parque, moradores utilizam os bancos sob a sombra das árvores e a iluminação pública começa a destacar o conjunto paisagístico. No centro desse ambiente renovado, sobressai o Monumento Maria Feliciana, homenagem à sergipana cuja altura extraordinária a tornou referência simbólica da identidade regional.
Natural do município de Amparo do São Francisco, Maria Feliciana alcançou notoriedade nacional ao se apresentar em circos e em programas de auditório. Na década de 1960, recebeu o título de “Rainha da Altura” no programa Hora da Buzina, apresentado por Chacrinha, o que ampliou sua projeção no cenário popular brasileiro. Nos anos 1970, seu nome passou a identificar informalmente o Edifício Estado de Sergipe, localizado no Centro de Aracaju, conhecido até hoje como “Maria Feliciana”, evidenciando a permanência de sua memória na cultura local.','A praça que abriga o monumento foi estruturada com enfoque multifuncional, incorporando infraestrutura voltada à permanência e ao uso cotidiano. O projeto contempla calçadas de concreto, equipamentos de ginástica ao ar livre, parque infantil com brinquedos tradicionais, além de mobiliário urbano, como bancos, mesas para jogos e lixeiras. Elementos como pergolados de eucalipto, espaço destinado a registros fotográficos, arborização planejada, iluminação em LED, rampas de acessibilidade e área de estacionamento ampliam a funcionalidade e a inclusão do espaço.
A escultura central atua como eixo simbólico do conjunto, articulando a arte pública e a narrativa histórica. Ao inserir a figura de Maria Feliciana no espaço urbano, o monumento ressignifica o território, transformando a praça em um local de reconhecimento identitário e de valorização da memória sergipana. A presença da homenagem contribui para fortalecer o sentimento de pertencimento da comunidade.','Dessa forma, a Praça Laudelino Graciliano Mateus consolida-se como espaço de lazer qualificado e de afirmação cultural. O monumento não apenas celebra uma personagem singular da história estadual, mas também integra memória, urbanismo e convivência social, ampliando a dimensão simbólica da paisagem urbana de Aracaju.
Elaboração própria, com base em informações institucionais do Governo do Estado de Sergipe, em registros públicos sobre a implantação do monumento e a requalificação da praça e em referências históricas sobre Maria Feliciana.','Walking through Laudelino Graciliano Mateus Square in the late afternoon means experiencing a space that brings together leisure, memory, and urban renewal. Children use the playground, residents gather on benches beneath the trees, and public lighting gradually highlights the landscaped setting. At the center of this renewed environment stands the Maria Feliciana Monument, a tribute to the Sergipe native whose extraordinary height became a symbol of regional identity.
Born in the municipality of Amparo do São Francisco, Maria Feliciana gained national recognition through performances in circuses and television variety shows. In the 1960s, she was dubbed the “Queen of Height” on the program Hora da Buzina, hosted by Chacrinha, which expanded her visibility across Brazil’s popular media landscape. In the 1970s, her name began to be informally associated with the Edifício Estado de Sergipe, located in downtown Aracaju and still widely known as “Maria Feliciana,” demonstrating the lasting cultural impact of her story.','The square that houses the monument was designed with a multifaceted approach, incorporating infrastructure for daily use and long-term durability. The project includes concrete walkways, outdoor fitness equipment, a children’s playground with traditional play structures, and urban furniture such as benches, game tables, and waste bins. Additional elements, including eucalyptus pergolas, a designated photo area, planned landscaping, LED lighting, accessibility ramps, and parking spaces, help make the area inclusive, functional, and welcoming.
The central sculpture serves as the symbolic axis of the space, connecting public art with historical narrative. By placing Maria Feliciana’s figure within the urban landscape, the monument redefines the square as a site of identity recognition and cultural appreciation. The tribute reinforces a sense of belonging to the community and highlights the relevance of local narratives in shaping collective memory.','In this context, Laudelino Graciliano Mateus Square has become both a qualified leisure area and a space of cultural affirmation. The monument not only honors a singular figure in Sergipe’s history but also integrates memory, urban planning, and social interaction, enriching the symbolic dimension of Aracaju’s urban landscape.
Prepared by the author, based on institutional information from the Government of the State of Sergipe, public records on the construction of the monument and renovation of the square, and historical references to Maria Feliciana.','Recorrer la Plaza Laudelino Graciliano Mateus al final de la tarde es experimentar un espacio que articula ocio, memoria y requalificación urbana. Los niños ocupan el parque infantil, los vecinos conversan en los bancos bajo la sombra de los árboles y la iluminación pública comienza a resaltar el paisaje. En el centro de este entorno renovado se erige el Monumento Maria Feliciana, homenaje a la sergipana cuya extraordinaria estatura la convirtió en símbolo de identidad regional.
Natural del municipio de Amparo do São Francisco, Maria Feliciana alcanzó notoriedad nacional al presentarse en circos y programas de entretenimiento televisivo. En la década de 1960, recibió el título de “Reina de la Altura” en el programa Hora da Buzina, conducido por Chacrinha, lo que amplió su proyección en el escenario popular brasileño. En los años 1970, su nombre pasó a identificar informalmente el Edifício Estado de Sergipe, ubicado en el centro de Aracaju y conocido hasta hoy como “Maria Feliciana”, lo que evidencia la permanencia cultural de su historia.','La plaza que alberga el monumento fue diseñada con un enfoque multifuncional, incorporando infraestructura orientada al uso cotidiano y a la permanencia. El proyecto incluye aceras de concreto, equipamientos de gimnasia al aire libre, parque infantil con juegos tradicionales y mobiliario urbano como bancos, mesas para juegos y papeleras. Elementos adicionales — como pérgolas de eucalipto, espacio destinado a registros fotográficos, arborización planificada, iluminación LED, rampas de accesibilidad y estacionamiento — completan el conjunto, convirtiendo el lugar en un espacio inclusivo y funcional.
La escultura central actúa como eje simbólico del conjunto, articulando el arte público y la narrativa histórica. Al integrar la figura de Maria Feliciana en el paisaje urbano, el monumento resignifica el espacio y lo convierte en punto de reconocimiento identitario y valorización de la memoria sergipana. La presencia del homenaje fortalece el sentido de pertenencia de la comunidad.','De este modo, la Plaza Laudelino Graciliano Mateus se consolida como un espacio de ocio cualificado y de afirmación cultural. El monumento no solo celebra a una figura singular de la historia estadual, sino que integra memoria, urbanismo y convivencia social, ampliando la dimensión simbólica del paisaje urbano de Aracaju.
Elaboración propia, basada en información institucional del Gobierno del Estado de Sergipe, en registros públicos sobre la implantación del monumento y la remodelación de la plaza, y en referencias históricas sobre Maria Feliciana.','cultura',-10.97084130,-37.03647020,'Av. Santos Dumont, 1891 - Coroa do Meio, Aracaju - SE, 49035-730','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/1e6123b6-193e-456e-9be0-77fc00f34859", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/bea0bc02-ad34-414d-ab4d-f68d185584ce", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "inline-2", "url": "/objects/uploads/3aad10ad-86e2-44d9-ade3-458a6d7a0b5d", "type": "inline", "order": 2, "inlinePosition": 3}, {"id": "gallery-0", "url": "/objects/uploads/d6945220-98ca-4409-9d67-6c97acae0b78", "type": "gallery", "order": 3}, {"id": "gallery-1", "url": "/objects/uploads/18ea484e-4705-4ec3-9707-c2029a419ebc", "type": "gallery", "order": 4}, {"id": "gallery-2", "url": "/objects/uploads/e4623f37-a7e3-429b-aca7-d96b49921953", "type": "gallery", "order": 5}, {"id": "gallery-3", "url": "/objects/uploads/ac995fbf-4c16-4083-9911-73ebc99abf7b", "type": "gallery", "order": 6}, {"id": "gallery-4", "url": "/objects/uploads/5f27f5ef-2dfe-4aed-bbfa-7dd01c6a9f5d", "type": "gallery", "order": 7}]'::jsonb,'/objects/uploads/7025065b-287c-40dc-9432-0e937f9838da','','qr-67f9d473-e851-489f-b0a0-333bbc8b1fa7','https://maps.app.goo.gl/rkPZ1TNXfGXG7mZr6',true,'',true,true,'','{}'::jsonb,'2025-11-25 12:27:53.427261+00','2026-03-03T12:28:08.184Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('3f709743-4659-4133-802d-da1329587a10','Farol da Coroa do Meio ','Coroa do Meio Lighthouse',' Farol da Marinha de Coroa do Meio','Ao caminhar pela Coroa do Meio no fim da tarde, quando o encontro entre o rio e o mar altera a tonalidade da paisagem e intensifica o movimento das águas, o Farol da Marinha se destaca no horizonte. A brisa proveniente da foz do Rio Sergipe atravessa a orla e reforça a percepção de um território moldado pela relação entre cidade e natureza.
Implantado nas proximidades da desembocadura do Rio Sergipe, rio que dá nome ao estado, o farol ocupa posição estratégica na configuração costeira de Aracaju. Sua localização favorece a conexão visual e territorial entre a Coroa do Meio, a Orla de Atalaia e outras áreas de interesse turístico, inserindo-se em um dos cenários mais representativos da capital.
','Originalmente concebido como instrumento de sinalização náutica, o equipamento ultrapassou sua função operacional e passou a integrar-se à paisagem urbana como marco simbólico. A partir de seu entorno, é possível observar o encontro das águas, a circulação de embarcações e os ecossistemas associados à foz, elementos que caracterizam a dinâmica ambiental da região.
Com o tempo, o Farol da Marinha consolidou-se como um ponto de referência espacial para moradores e visitantes. O local favorece a contemplação, a prática de caminhadas e a realização de registros fotográficos, integrando-se às experiências cotidianas e turísticas da cidade. Essa apropriação reforça o papel do equipamento na construção da identidade visual de Aracaju.','A Coroa do Meio, ao articular paisagem natural, infraestrutura urbana e circulação de visitantes, evidencia seu potencial como área estratégica para o desenvolvimento turístico sustentável da capital. Nesse contexto, o Farol da Marinha permanece como elemento de orientação, memória e conexão entre o território e a experiência urbana.
Elaboração própria, com base em informações institucionais do Governo do Estado de Sergipe.','In the late afternoon, Coroa do Meio reveals one of Aracaju’s most distinctive coastal scenes. As river and sea converge, the light shifts gradually across the horizon, and the movement of the waters becomes more pronounced. From this vantage point, the Farol da Marinha lighthouse stands out against the skyline. At the same time, a steady breeze from the mouth of the Rio Sergipe crosses the waterfront and reinforces the area’s close relationship with its natural setting.
The lighthouse occupies a strategic position near the point where the Rio Sergipe — the river that gives the state its name — meets the Atlantic Ocean. This location strengthens the spatial link between Coroa do Meio, the Orla de Atalaia waterfront, and other areas of visitor interest. Together, they form one of the capital’s most representative coastal landscapes.','Although originally conceived as nautical signaling infrastructure, the Farol da Marinha gradually assumed broader relevance within the city. Beyond its operational function, it serves today as a landscape marker and orientation point. From its surroundings, it is possible to observe the confluence of waters, boat traffic, and the ecosystems associated with the estuarine zone — elements that shape the environmental dynamics of this stretch of coast.
Over time, the site has been incorporated into everyday urban life. Residents use the area for walking and contemplation; visitors are drawn to its open views and photographic perspectives. This shared use reinforces its role in Aracaju’s visual identity and strengthens the connection between territory and lived experience.','By integrating coastal scenery, public space, and circulation, Coroa do Meio demonstrates its relevance to the sustainable development of tourism in the capital. Within this framework, the Farol da Marinha remains both a navigational structure and a symbol of the city’s relationship with water.
Prepared based on official information from the Government of the State of Sergipe.','Al final de la tarde, Coroa do Meio ofrece una de las escenas costeras más representativas de Aracaju. Cuando el río y el mar se encuentran, la luz cambia gradualmente y el movimiento del agua gana intensidad. En ese paisaje, el faro Farol da Marinha se destaca en el horizonte, mientras la brisa proveniente de la desembocadura del Rio Sergipe recorre el paseo marítimo y acentúa el vínculo entre ciudad y entorno natural.
La estructura se ubica en un punto estratégico, junto al lugar donde el Rio Sergipe — curso fluvial que da nombre al estado — desemboca en el océano Atlántico. Esa posición facilita la conexión territorial entre Coroa do Meio, la Orla de Atalaia y otros sectores frecuentados por los visitantes, lo que configura uno de los paisajes costeros más significativos de la capital.','Concebido originalmente como infraestructura de señalización náutica, el Farol da Marinha amplió su papel en el tejido urbano con el tiempo. Hoy funciona no solo como equipamiento técnico, sino también como hito paisajístico y referencia espacial. Desde su entorno se observan la confluencia de las aguas, el tránsito de embarcaciones y los ecosistemas asociados al estuario, componentes que definen la dinámica ambiental de la zona.
El espacio fue incorporándose progresivamente a la vida cotidiana de la ciudad. Los residentes lo utilizan para caminar y contemplar el paisaje; quienes visitan Aracaju encuentran allí un punto privilegiado para apreciar la geografía local. Esta apropiación compartida fortalece su papel en la identidad visual urbana.','Al integrar el paisaje costero, el espacio público y los flujos de visitantes, Coroa do Meio confirma su relevancia como área estratégica para el desarrollo sostenible del turismo en Aracaju. En ese contexto, el Farol da Marinha permanece como elemento de orientación y de expresión concreta de la relación histórica entre la ciudad y sus aguas.
Elaborado con base en la información institucional del Gobierno del Estado de Sergipe.','historico',-10.96959810,-37.03621080,'Coroa do Meio, Aracaju - SE, 49035-810','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/7a29f0dd-7e28-4bf6-8185-c6ff3c543a9a", "type": "gallery", "order": 0}, {"id": "gallery-1", "url": "/objects/uploads/17dbfeaa-d508-4772-8d05-0b25b176b7a2", "type": "gallery", "order": 1}]'::jsonb,'/objects/uploads/d46ee32d-4fe1-4b09-9b0a-8ef64565bc1c','','qr-5d2c719b-fd69-407d-a633-ee1e693cf158','https://maps.app.goo.gl/uethFNURGvsLdMEj7',true,'',false,true,'','{}'::jsonb,'2025-11-25 12:31:04.990507+00','2026-03-01T19:21:00.356Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('64d39754-64d7-4cf2-b7aa-84af348fcc1d','Parque Ecológico Poxim','','','Inaugurado em 9 de outubro de 2020, o Parque Ecológico do Poxim está localizado no bairro Inácio Barbosa, na zona sul de Aracaju, e representa uma das mais recentes iniciativas de preservação ambiental da capital. Implantado como contrapartida ambiental em parceria com a Energisa, o espaço foi concebido para proteger remanescentes de Mata Atlântica e áreas de manguezal às margens do Rio Poxim, ao mesmo tempo em que amplia as opções de lazer sustentável na cidade.','Com funcionamento diário, das 6h às 18h, e acesso gratuito, o parque oferece infraestrutura voltada à convivência e à educação ambiental. Entre seus equipamentos estão trilha ecológica sinalizada, píer com vista para o rio, anfiteatro, tirolesa infantil, parque recreativo, academia ao ar livre e chalés de apoio. Placas de identificação de espécies vegetais reforçam o caráter pedagógico do espaço, incentivando a conscientização sobre a biodiversidade local.','Além de área de lazer familiar, o parque desempenha papel estratégico como corredor ecológico de manguezal, contribuindo para a preservação da fauna e flora associadas ao ecossistema estuarino. No primeiro ano de funcionamento, recebeu mais de 30 mil visitantes, sendo utilizado para atividades escolares, práticas esportivas e encontros comunitários.
O Parque Ecológico do Poxim consolida-se, assim, como exemplo de integração entre preservação ambiental, responsabilidade socioambiental e qualidade de vida urbana, fortalecendo o compromisso de Aracaju com a sustentabilidade.
Elaboração própria, com base em informações da Prefeitura de Aracaju.','','','','','','','',-10.95324250,-37.05665070,'','{}'::text[],'[]'::jsonb,NULL,'','qr-00d5f450-92f2-40ff-a5d0-6da7e5c2d3dc','',true,'',false,false,'','{}'::jsonb,'2025-11-25 12:38:08.844024+00','2026-02-11T12:51:08.619Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('413e31fa-5006-47ba-8028-f0e2d4584c43','Espaço Energia','','','Localizado na Praça Theodorico do Prado Montes, no bairro Farolândia, o Espaço Energia de Aracaju amplia sua proposta educativa ao conduzir o visitante por uma linha do tempo que parte das origens do universo, com referências ao Big Bang e percorre os principais marcos científicos que possibilitaram o domínio da eletricidade, incluindo contribuições de inventores como Thomas Edison.
A experiência é totalmente guiada e estruturada para integrar conhecimento histórico, científico e lúdico, com duração média entre 45 e 60 minutos. O roteiro apresenta de forma didática o percurso da energia, desde sua geração até o consumo final nas residências, estimulando a compreensão sobre eficiência energética e uso consciente.','Entre os recursos tecnológicos, destacam-se o cinema 7D imersivo, o domo planetário e o piso piezoelétrico, capaz de gerar energia a partir do movimento humano, permitindo que o visitante experimente na prática conceitos relacionados à transformação e ao aproveitamento energético.','O próprio edifício funciona como ferramenta pedagógica, ao incorporar painéis fotovoltaicos e aerogeradores que contribuem para sua sustentabilidade, demonstrando, na prática, o funcionamento de fontes renováveis. Voltado para escolas, grupos organizados e público em geral, o espaço consolida-se como ambiente de educação científica e sensibilização ambiental em Sergipe.
Elaboração própria, com base em informações da Prefeitura de Aracaju e materiais institucionais.','','','','','','','',-10.97411760,-37.05552480,'','{}'::text[],'[]'::jsonb,NULL,'','qr-c96dadfb-0bf6-4144-9df9-5ce43ac79ac0','',true,'',false,false,'','{}'::jsonb,'2025-11-25 12:45:44.488049+00','2026-02-11T12:35:19.585Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('262e2e00-3675-4d89-b10e-8f99622ff3d9','Cajueiro (Confraria do Cajueiro) ','','','Localizada no bairro Inácio Barbosa, a Confraria do Cajueiro é um bar e restaurante construído ao redor de um cajueiro com mais de 70 anos, reconhecido como patrimônio histórico e ambiental de Aracaju. Situado na Avenida Cecília Meireles, nº 11, na Praça dos Nacionalistas, o espaço une gastronomia, cultura e identidade local sob a sombra de uma das árvores mais simbólicas da capital.
Tombado pela prefeitura desde 2017, o cajueiro tornou-se elemento central da proposta do estabelecimento, que valoriza a preservação ambiental e a memória paisagística da cidade. O ambiente, naturalmente sombreado pela copa da árvore, proporciona experiência singular aos visitantes, integrando natureza e convivência urbana.','A Confraria destaca-se pela culinária regional, com pratos tradicionais como o arrumadinho de charque, além de música ao vivo e programação cultural que reforçam o caráter de ponto de encontro comunitário. O local celebra não apenas a gastronomia sergipana, mas também o significado histórico do cajueiro para Aracaju.
A importância da árvore vai além do estabelecimento. O nome da cidade tem origem no tupi arákaîu, que significa “cajueiro das araras” ou “cajueiro dos papagaios”, referência à presença abundante dessas árvores na região. Em 2025, o cajueiro foi oficialmente declarado árvore símbolo de Aracaju, e seu fruto e castanha reconhecidos como patrimônios culturais materiais. Outro exemplar emblemático, localizado na Praça Monteiro Lobato, também recebeu proteção no mesmo período.','Assim, a Confraria do Cajueiro representa mais do que um espaço gastronômico: é expressão viva da identidade cultural e ambiental da capital sergipana, reafirmando o cajueiro como elemento central da história e da paisagem de Aracaju.
Elaboração própria, com base em informações de redes sociais oficiais e registros municipais.','','','','','','','cultura',-10.95453260,-37.06196360,'','{}'::text[],'[]'::jsonb,NULL,'','qr-2d135b17-c973-411a-8631-58c44b874b89','',true,'',false,false,'','{}'::jsonb,'2025-11-25 12:50:51.485717+00','2026-02-11T12:19:44.658Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('60ca6ec9-904b-4bd0-b4c9-c10303d66b4e','Parque da Sementeira','','','Criado em 1980, o Parque Governador Augusto Franco, popularmente conhecido como Parque da Sementeira, é um dos principais patrimônios naturais de Aracaju. Localizado no bairro Jardins, ocupa uma área de aproximadamente 363 mil m² e representa o maior “pulmão verde” da capital sergipana.
Antes de se tornar parque municipal, a área funcionava como campo experimental da Embrapa, voltado principalmente ao cultivo e pesquisa de mudas de coqueiro, origem do apelido “Sementeira”. Na década de 1970, o local abrigava inclusive técnicos que atuavam nas pesquisas agrícolas. Com a desapropriação e transformação em parque público, o espaço passou a integrar preservação ambiental, lazer e produção de mudas para a cidade.','Atualmente, o parque abriga o horto municipal, responsável por quase 100% das plantas utilizadas nos espaços públicos de Aracaju, além da sede da Emsurb, da Guarda Municipal e do CCTECA (Centro de Criatividade e Tecnologia Educacional de Aracaju), onde funciona o planetário da capital. Trilhas, lago, áreas esportivas e espaços para convivência completam a estrutura.','Em 2025, o parque passou por ampla revitalização, com investimentos superiores a R$ 30 milhões, recebendo novos quiosques, melhorias na iluminação, requalificação das áreas verdes e a implantação da “Arena Delas”, voltada ao incentivo da prática esportiva feminina.
Além de espaço de lazer, o Parque da Sementeira cumpre papel fundamental na preservação da fauna e flora locais, funcionando como refúgio ecológico e polo de educação socioambiental. Sua trajetória reflete o compromisso de Aracaju com a sustentabilidade, a qualidade de vida e a valorização dos recursos naturais.
Elaboração própria, com base em informações da Prefeitura de Aracaju e do Instituto Marcelo Déda.','','','','','','','',-10.94433740,-37.05333890,'','{}'::text[],'[]'::jsonb,NULL,'','qr-8ffe3458-9d61-4364-a00c-523629a204df','',true,'',false,true,'','{}'::jsonb,'2025-11-25 12:56:21.401172+00','2026-02-11T12:15:36.611Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('7dd172e9-4d18-4289-9c29-82564ec524f9','Monumento do Caju ','The Cashew Monument','Monumento al Anacardo ','Às margens da Ponte Godofredo Diniz, na entrada do bairro Coroa do Meio, o Monumento do Caju destaca-se como uma das referências visuais mais reconhecidas da paisagem urbana de Aracaju. Com cerca de oito metros de altura e executada em concreto aparente, a escultura remete à própria origem do nome da cidade, associado ao termo indígena que significa “cajueiro das araras”.
A obra foi criada pelo artista plástico Eurico Luiz e integra o conjunto de intervenções que contribuíram para inserir a arte no espaço público da capital sergipana. Ao longo do tempo, consolidou-se como ponto de identificação territorial, cenário recorrente de registros fotográficos e marco simbólico para moradores e visitantes.','Em 2025, o monumento passou por um processo completo de restauração, com foco na preservação de suas características originais. A intervenção recuperou cores e elementos estruturais, assegurando a conservação de um dos marcos artísticos da cidade. A iniciativa reafirma a importância da manutenção do patrimônio urbano como componente da identidade local.','Natural de Araçatuba (SP) e sergipano por opção, Eurico Luiz viveu mais de duas décadas em Sergipe e deixou obras em diferentes pontos da capital. Entre elas estão o Monumento Tropical, na Avenida Ivo do Prado, e as esculturas no entorno do Iate Clube de Aracaju. Formado pela Escola de Belas Artes da Bahia, o artista desenvolveu trabalhos que dialogam com referências culturais regionais e com o sentimento de pertencimento ao território sergipano. Faleceu em 9 de dezembro de 2014, deixando uma contribuição relevante para a arte pública do estado.
A restauração do Monumento do Caju reforça seu papel como marco identitário e elemento de acolhimento urbano, evidenciando o compromisso com a preservação cultural e com a valorização da memória coletiva de Aracaju.','The Cashew Monument is one of the most recognizable landmarks in Aracaju''s urban landscape. It is located next to the Godofredo Diniz Bridge, at the entrance to the Coroa do Meio neighborhood. The sculpture stands approximately eight meters tall and is made of exposed concrete. It references the origin of the city’s name, which comes from an Indigenous term meaning “cashew tree of the macaws.”
Created by visual artist Eurico Luiz, the monument is part of a larger initiative to integrate artistic expression into the city’s public spaces. It has become a significant point of identification for the area, frequently serving as a backdrop for photographs and acting as a symbolic marker for both residents and visitors.','In 2025, the monument underwent a comprehensive restoration to preserve its original features. This process restored its colors and reinforced structural elements, ensuring the conservation of one of the city''s key artistic landmarks. The initiative highlights the importance of preserving urban heritage to strengthen local identity.
Eurico Luiz was born in Araçatuba, São Paulo State, but chose to make Sergipe his home. He lived in Sergipe for more than two decades, working in various locations around the capital. His projects include the Tropical Monument on Ivo do Prado Avenue and sculptures surrounding the Aracaju Yacht Club. A graduate of the School of Fine Arts of Bahia, Eurico developed creations that reflected regional cultural references and fostered a sense of belonging to Sergipe’s territory. He passed away on December 9, 2014, leaving an indelible mark on the state’s public art.','The restoration of the Cashew Monument is a clear demonstration of Aracaju’s commitment to cultural preservation and the safeguarding of collective memory.
This summary is based on data from the Municipality of Aracaju (2025).','El Monumento al Anacardo es uno de los hitos más reconocibles del paisaje urbano de Aracaju. Se encuentra junto al puente Godofredo Diniz, a la entrada del barrio de Coroa do Meio. La escultura mide aproximadamente ocho metros de altura y está hecha de hormigón visto. Hace referencia al origen del nombre de la ciudad, que proviene de un término indígena que significa «árbol de anacardo de los guacamayos».
Creado por el artista visual Eurico Luiz, el monumento forma parte de una iniciativa más amplia para integrar la expresión artística en los espacios públicos de la ciudad. Se ha convertido en un importante punto de identificación para la zona, sirviendo con frecuencia como telón de fondo para fotografías y actuando como un marcador simbólico tanto para los residentes como para los visitantes.','Eurico Luiz nació en Araçatuba, en el estado de São Paulo, pero decidió establecer su hogar en Sergipe. Vivió en Sergipe durante más de dos décadas, trabajando en diversos lugares de la capital. Entre sus proyectos se encuentran el Monumento Tropical de la avenida Ivo do Prado y las esculturas que rodean el Club Náutico de Aracaju.
Graduado de la Escuela de Bellas Artes de Bahía, Eurico desarrolló creaciones que incorporaban referencias culturales regionales y fomentaban un sentido de pertenencia al territorio de Sergipe. Falleció el 9 de diciembre de 2014, dejando una huella indeleble en el arte público del estado.
','La restauración del Monumento al Anacardo es una clara demostración del compromiso de Aracaju con la preservación cultural y la salvaguarda de la memoria colectiva.
Esta información se basa en datos del Ayuntamiento de Aracaju (2025).','cultura',-10.94147240,-37.05016400,'','{}'::text[],'[]'::jsonb,NULL,'','qr-a20722db-8fda-468b-beb8-216225b68729','https://maps.app.goo.gl/US4FtU5nJrrsRV2Q6',true,'',true,true,'','{}'::jsonb,'2025-11-25 13:04:06.869724+00','2026-03-01T01:19:26.960Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('ac9ea806-76af-4bbf-82f6-2f8d2b0200c6','Mirante da 13 de Julho','13th of July Overlook','Mirador del barrio 13 de Julho','Com 27 anos de história, o Mirante do Bairro 13 de Julho consolidou-se como um dos principais pontos de contemplação de Aracaju. De sua elevada estrutura, o visitante observa o Rio Sergipe, o calçadão da 13 de Julho, áreas de manguezal e parte do Centro Histórico, compondo um panorama que articula natureza, urbanização e patrimônio cultural.
Recentemente reativado pela Prefeitura de Aracaju, por meio da Secretaria Municipal do Turismo (Setur), o espaço passou a abrigar também um Centro de Atendimento ao Turista (CAT). Com essa iniciativa, o mirante amplia sua função original e assume um papel estratégico no acolhimento e na orientação de visitantes. A equipe técnica disponibiliza informações sobre atrativos, roteiros e serviços turísticos, contribuindo para a qualificação da experiência na cidade.','No âmbito da dinamização do equipamento, a gestão instituiu o projeto mensal “Mirando as Artes”, que promove exposições, feiras de artesanato, sessões de cinema, lançamentos literários, aulas de dança e apresentações musicais. A programação estimula a ocupação ativa do espaço público, valoriza a produção cultural sergipana e fortalece a convivência comunitária.','Além do “Mirando as Artes”, a administração municipal mantém outras iniciativas culturais permanentes, desenvolvidas em parceria com instituições locais, com foco na ativação dos fins de semana e na ampliação do acesso à arte e à cultura para moradores e visitantes. Nesse contexto, o Mirante da 13 de Julho consolida-se como um equipamento multifuncional, integrando turismo, cultura e experiência urbana em um mesmo território.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2025).','With 27 years of history, the 13 de Julho Neighborhood Overlook has established itself as one of Aracaju’s main scenic viewpoints. From its elevated structure, visitors can observe the Sergipe River, the 13 de Julho promenade, surrounding mangrove areas, and part of the Historic Center, forming a landscape that connects nature, urban development, and cultural heritage.
Recently reactivated by the Municipality of Aracaju through the Municipal Tourism Department (Setur), the site now also houses a Tourist Information Center (TIC). This addition expands the overlook´s original function and positions it as a strategic point for visitor reception and guidance. A trained team provides information on attractions, itineraries, and tourism services, contributing to a more structured and informed visitor experience.','As part of its activation strategy, the municipal administration launched the monthly cultural program “Mirando as Artes” (Overlooking the Arts). The initiative features art exhibitions, craft fairs, film screenings, book launches, dance classes, and musical performances. By encouraging regular cultural programming, the project promotes active use of public space, supports local artistic production, and strengthens community engagement.','In parallel, the city maintains other permanent cultural initiatives developed in partnership with local institutions. These actions aim to energize weekends in the capital and broaden access to arts and culture for both residents and visitors. Within this framework, the 13 de Julho Lookout functions as a multifunctional urban facility, integrating tourism services, cultural programming, and public life in a single setting.
This summary is based on information from the Municipality of Aracaju (2025).','Con 27 años de trayectoria, el Mirador del barrio 13 de Julho se ha consolidado como uno de los principales puntos de observación de Aracaju. Desde su estructura elevada se observan el río Sergipe, el paseo de la 13 de Julho, áreas de manglar y parte del Centro Histórico, lo que conforma un paisaje que integra naturaleza, urbanización y patrimonio cultural.
Recientemente reactivado por la Municipalidad de Aracaju, a través de la Secretaría Municipal de Turismo (Setur), el espacio también alberga un Centro de Atención al Turista (CAT). Esta incorporación amplía su función original y lo posiciona como un punto estratégico de acogida y orientación para visitantes. Un equipo capacitado ofrece información sobre atractivos, rutas y servicios turísticos, lo que contribuye a una experiencia más organizada y cualificada en la ciudad.','Como parte de la estrategia de dinamización, la administración municipal implementó el programa cultural mensual “Mirando as Artes” (Mirando las Artes). La agenda incluye exposiciones, ferias de artesanía, proyecciones de cine, presentaciones literarias, clases de danza y conciertos. Con una programación continua, la iniciativa fomenta el uso activo del espacio público, pone en valor la producción cultural sergipana y fortalece la convivencia comunitaria.','De manera complementaria, el municipio desarrolla otros proyectos culturales permanentes en articulación con instituciones locales. Estas acciones buscan dinamizar los fines de semana en la capital y ampliar el acceso al arte y la cultura tanto para residentes como para visitantes. En este contexto, el Mirador de la 13 de Julho opera como un equipamiento multifuncional que integra turismo, cultura y experiencia urbana en un mismo espacio.
Elaboración propia, con base en información de la Municipalidad de Aracaju (2025).','cultura',-10.93467080,-37.04969350,'Av. Gov. Paulo Barreto de Menezes - 13 de Julho, Aracaju - SE, 49020-240','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/22019e25-2faf-4f49-bca9-d569801d9162", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/862c8904-53e7-4cc6-8253-48f7687fb587", "type": "inline", "order": 1, "inlinePosition": 2}, {"id": "inline-2", "url": "/objects/uploads/2dcb52ac-90a0-4de7-ab0f-50ad829a04b5", "type": "inline", "order": 2, "inlinePosition": 3}, {"id": "gallery-0", "url": "/objects/uploads/807d6ee7-9edd-4145-81a2-b9918a248486", "type": "gallery", "order": 3}, {"id": "gallery-1", "url": "/objects/uploads/584c05f7-377b-4fa2-bf96-d897790318d7", "type": "gallery", "order": 4}, {"id": "gallery-2", "url": "/objects/uploads/a95c35c1-9fae-4a47-9344-6ca4e6444843", "type": "gallery", "order": 5}, {"id": "gallery-3", "url": "/objects/uploads/57280c8c-85e1-4126-b4ff-7462e6832312", "type": "gallery", "order": 6}, {"id": "gallery-4", "url": "/objects/uploads/89895e18-b83c-4f75-898f-62cbf78dc2c2", "type": "gallery", "order": 7}, {"id": "gallery-5", "url": "/objects/uploads/82db89a2-d120-42bd-aee4-302cc23af270", "type": "gallery", "order": 8}]'::jsonb,'/objects/uploads/f491d956-6632-41a8-a428-a424f6a764a3','','qr-6e161245-2934-4dd1-94d1-fa07315abe05','https://maps.app.goo.gl/v35wCLihFykzovXD9',true,'Seg a sex: 09h às 19h; Sáb e Domingo: 09h às 13h',false,true,'','{}'::jsonb,'2025-11-25 13:49:37.817705+00','2026-03-01T01:18:42.169Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('a4d5ace9-53d2-4a04-b05c-a5c700e72cd3','Calçadão Praia Formosa','Formosa Beach Waterfront ','Paseo marítimo Praia Formosa','A história da antiga Praia Formosa, hoje integrada ao bairro 13 de Julho, reflete o processo de transformação urbana de Aracaju. O que no século XIX era conhecido como Ilha dos Bois, reduto de pescadores e área de águas limpas e areias claras, tornou-se um dos endereços mais valorizados da capital sergipana.
A denominação “Praia Formosa” surgiu da beleza natural do encontro do Rio Sergipe com o riacho Tramandaí, cenário que, ao longo do início do século XX, consolidou-se como principal balneário da cidade. Até a década de 1950, era o espaço de lazer mais frequentado pela sociedade aracajuana, antes da expansão urbana rumo à Orla de Atalaia. A fundação do Iate Clube de Aracaju, em 1953, reforçou esse perfil de ponto de encontro social e esportivo.','A região também tem relevância histórica. Em 13 de julho de 1924, foi palco de um confronto ligado aos movimentos tenentistas, episódio que marcou a política local. Em 1930, o nome do bairro foi oficialmente alterado para “13 de Julho”, em referência à data do conflito.
Com o avanço da urbanização, a construção da Avenida Beira-Mar e o aterramento de áreas de manguezal transformaram o antigo balneário em um espaço urbano estruturado. Em 2016, foi inaugurado o Calçadão da Praia Formosa, obra de revitalização que combinou contenção do avanço das marés com a criação de áreas de convivência, mirantes e fontes luminosas, integrando lazer e paisagismo à orla ribeirinha.','Atualmente, o bairro 13 de Julho reúne equipamentos culturais, espaços de prática esportiva e áreas de contemplação, mantendo-se um dos principais polos residenciais e turísticos da capital. A antiga Praia Formosa permanece, assim, como símbolo da evolução histórica e urbana de Aracaju.
Fonte: Elaboração própria, com base em informações do Globoplay e em registros históricos locais.','The history of the former Praia Formosa (Formosa Beach) — now integrated into the 13 de Julho neighborhood — reflects the process of urban transformation in Aracaju. What was known in the 19th century as Ilha dos Bois (Island of the Oxen), a fishermen’s enclave characterized by clean waters and light-colored sands, became one of the most highly valued areas of the Sergipe state capital.
The name “Praia Formosa” emerged from the natural beauty of the meeting point between the Sergipe River and the Tramandaí stream, a landscape that, throughout the early decades of the 20th century, consolidated its status as the city’s main seaside resort. Until the 1950s, it was the most frequented leisure area in Aracaju, before urban expansion shifted toward the Orla de Atalaia (Atalaia Waterfront). The founding of the Iate Clube de Aracaju (Aracaju Yacht Club) in 1953 reinforced its role as a social and sporting gathering place.','The area also holds historical significance. On July 13th, 1924, it was the site of a confrontation linked to the tenentista movements, an episode that left its mark on local politics. In 1930, the neighborhood was officially renamed “13 de Julho” (July 13th), in reference to the date of the conflict.
With advancing urbanization, the construction of Avenida Beira-Mar (Beira-Mar Avenue) and the land reclamation of mangrove areas transformed the former seaside resort into a structured urban space. In 2016, the Calçadão da Praia Formosa (Praia Formosa Waterfront) was inaugurated — a revitalization project that combined tidal containment measures with the creation of public gathering areas, viewpoints, and illuminated fountains, integrating leisure and landscape design along the riverfront.','Today, the 13 de Julho neighborhood (July 13th Neighborhood) brings together cultural facilities, sports areas, and contemplative spaces, remaining one of the capital’s main residential and tourism hubs. The former Praia Formosa thus endures as a symbol of Aracaju’s historical and urban evolution.
This summary is based on information from Globoplay and local historical records.','La historia de la antigua Praia Formosa (Playa Formosa) —hoy integrada al barrio 13 de Julho (13 de Julio)— permite comprender el proceso de transformación urbana de Aracaju. En el siglo XIX, el área era conocida como Ilha dos Bois (Isla de los Bueyes), un enclave de pescadores con aguas limpias y arenas claras. Con el tiempo, ese paisaje ribereño se incorporó a la dinámica urbana y pasó a figurar entre los sectores más valorizados de la capital sergipana.
El nombre Praia Formosa surgió del encuentro natural entre el río Sergipe y el arroyo Tramandaí. Durante las primeras décadas del siglo XX, ese entorno se consolidó como el principal balneario de la ciudad. Hasta los años cincuenta concentró la vida social y recreativa de Aracaju, antes de que la expansión urbana se orientara hacia la Orla de Atalaia (Paseo Marítimo de Atalaia). La creación del Iate Clube de Aracaju (Club Náutico de Aracaju) en 1953 reforzó su función como espacio de convivencia y de práctica deportiva, vinculada al uso recreativo del río.','El lugar también ocupa un lugar en la historia política local. El 13 de julio de 1924 se registró allí un enfrentamiento relacionado con los movimientos tenentistas, corriente que influyó en la vida institucional brasileña durante la Primera República. Años más tarde, en 1930, el barrio adoptó oficialmente el nombre de 13 de Julho, en alusión a esa fecha.
La urbanización modificó significativamente el territorio. La apertura de la Avenida Beira-Mar y el relleno de áreas de manglar redefinieron el antiguo balneario e integraron este a la estructura urbana consolidada. En 2016 se inauguró el Calçadão da Praia Formosa (Paseo Marítimo de Playa Formosa), un proyecto que combinó obras de contención frente al avance de las mareas con nuevos espacios públicos: áreas de estancia, miradores y fuentes luminosas. La intervención articuló la protección ambiental, el paisaje y el uso ciudadano del frente fluvial.','En la actualidad, el barrio 13 de Julho reúne equipamientos culturales, espacios para la práctica deportiva y áreas de contemplación junto al río. Funciona como polo residencial y de visita, donde la memoria histórica convive con la experiencia urbana contemporánea. La antigua Praia Formosa permanece como una referencia clave para entender la evolución territorial y simbólica de Aracaju.
Elaboración propia, con base en información de Globoplay y en registros históricos locales.
','praia',-10.92938480,-37.04473200,' Av. Gov. Paulo Barreto de Menezes, 13 - de Julho, Aracaju - SE, 49020-010','{}'::text[],'[]'::jsonb,NULL,'','qr-659c3e02-6eff-4a5c-a063-0a9003f314f3','https://maps.app.goo.gl/YMKXJDmGMyNJ6BgdA',true,'',true,true,'','{}'::jsonb,'2025-11-25 13:54:38.083217+00','2026-03-01T01:16:52.323Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('c8e9366a-0ab7-4636-ab6f-24e041f3ff42','Iate Clube de Aracaju','','','O Iate Clube de Aracaju nasceu do sonho de incentivar e fortalecer a prática dos esportes náuticos na capital sergipana. A iniciativa partiu de um grupo de entusiastas da vela que, em 19 de agosto de 1953, reuniram-se na sede do Clube Sportivo Sergipe para formalizar a fundação da instituição. Na ocasião, foi assinada a ata inaugural e empossado como primeiro Comodoro Alcebíades Vilas Boas. Em 1º de dezembro de 1954, a entidade foi oficialmente consolidada com a regularização dos sócios fundadores e a composição definitiva da diretoria.','Cinco anos depois, em 25 de agosto de 1958, foi inaugurada a sede do clube, resultado da colaboração de associados, apoiadores e dos governos estadual e federal. A cerimônia contou com a presença do então governador Leandro Maciel, marcando um momento significativo para o desenvolvimento do esporte náutico em Sergipe.
Em 1971, o clube ampliou sua estrutura com a inauguração do Salão Tennyson Freire, espaço destinado à realização de eventos sociais e culturais. O local rapidamente tornou-se referência para encontros e celebrações, sendo palco de grandes festividades, como o tradicional réveillon daquele ano.','Posteriormente, em 26 de abril de 1987, foi inaugurada a sede náutica do Mosqueiro, ampliando as possibilidades para a prática da vela e oferecendo melhores condições aos sócios proprietários de embarcações. A iniciativa fortaleceu ainda mais a vocação do clube para o esporte e o lazer.
Ao longo de sua trajetória, o Iate Clube de Aracaju consolidou-se como importante instituição esportiva e social da capital, contribuindo para a difusão da cultura náutica e para o fortalecimento da vida associativa em Sergipe.
Elaboração própria, com base em informações do Iate Clube de Aracaju.','','','','','','','historico',-10.92616820,-37.04304580,'','{}'::text[],'[]'::jsonb,NULL,'','qr-642391b7-3e04-4db8-86ab-9bf149cff57c','',true,'',false,false,'','{}'::jsonb,'2025-11-25 13:59:04.784396+00','2026-02-10T14:30:30.115Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('18117e0b-1c7b-46d7-b111-4f47cc8f9a22','Monumento Ser Feliz Aracaju','Be Happy Monument Aracaju','Monumento Ser Feliz Aracaju','Paulista de nascimento e sergipano por escolha, Eurico Luiz deixou uma marca duradoura na paisagem urbana de Aracaju ao incorporar a arte ao cotidiano da cidade. Formado pela Escola de Belas Artes da Bahia, desenvolveu uma linguagem própria, combinando formas expressivas e cores intensas em diálogo com referências culturais e elementos da natureza local.','Entre as obras mais reconhecidas estão o Caju da Ponte da Coroa do Meio, a Arara da Praça do Iate e o Peixe do Calçadão da Beira-Mar. Ao longo do tempo, essas esculturas passaram a funcionar como marcos visuais e pontos de encontro, integrando-se à dinâmica urbana e à experiência de moradores e visitantes.
Outro trabalho de destaque é o monumento Ser Feliz Aracaju, que remete à origem do nome da cidade — associado ao termo tupi frequentemente interpretado como “cajueiro das araras”. A obra articula linguagem simbólica e identidade cultural, traços recorrentes na trajetória do artista.','Mesmo após seu falecimento, em 2004, a presença de Eurico Luiz permanece perceptível nos espaços públicos da capital. Seu conjunto de obras contribuiu para consolidar a arte urbana como componente estruturante da paisagem de Aracaju e para ampliar a valorização estética do ambiente urbano.
Elaboração própria, com base nas informações do Catálogo das Artes e do Infonet.','Born in São Paulo and later rooted in Sergipe, Eurico Luiz left a lasting mark on Aracaju’s urban landscape by integrating art into the city’s everyday spaces. A graduate of the School of Fine Arts of Bahia, he developed a distinctive visual language that combined expressive forms and bold colors, engaging with local cultural references and elements of the natural environment.','Among his most recognized works are the Caju at the Coroa do Meio Bridge, the Arara at Iate Square, and the Peixe along the Beira-Mar Promenade. Over time, these sculptures have come to function as visual landmarks and informal meeting points, embedded in the daily life of the city and in the experience of residents and visitors alike.
Another significant work is the monument Ser Feliz Aracaju, which refers to the origin of the city’s name—commonly linked to a Tupi expression interpreted as “cashew tree of the macaws.” Through symbolic language, the piece engages with themes of cultural identity that are central to the artist’s trajectory.','Since his passing in 2004, Eurico Luiz’s contribution remains visible across Aracaju’s public spaces. His body of work helped consolidate urban art as a defining component of the city’s landscape and strengthened the recognition of its cultural and built environment.
Prepared based on information from the Catálogo das Artes and Infonet.','Nacido en São Paulo y posteriormente radicado en Sergipe, Eurico Luiz dejó una huella duradera en el paisaje urbano de Aracaju al integrar el arte en los espacios cotidianos de la ciudad. Graduado por la Escuela de Bellas Artes de Bahía, desarrolló un lenguaje visual propio, combinando formas expresivas y colores intensos en diálogo con referencias culturales locales y con elementos del entorno natural.','Entre sus obras más reconocidas se encuentran el Caju en el Puente de la Coroa do Meio, la Arara en la Plaza del Iate y el Peixe en el Paseo Beira-Mar. Con el tiempo, estas esculturas pasaron a funcionar como hitos visuales y puntos de encuentro informales, incorporados a la dinámica diaria y a la experiencia tanto de residentes como de visitantes.
Otra obra significativa es el monumento Ser Feliz Aracaju, que remite al origen del nombre de la ciudad, comúnmente vinculado a una expresión de raíz tupí interpretada como “cajueiro de las guacamayas”. A través de un lenguaje simbólico, la pieza aborda temas de identidad cultural recurrentes en la trayectoria del artista.','Desde su fallecimiento en 2004, la contribución de Eurico Luiz sigue siendo visible en los espacios públicos de Aracaju. Su conjunto de obras ayudó a consolidar el arte urbano como componente estructurante del paisaje de la ciudad y a reforzar el reconocimiento de su entorno cultural y construido.
Elaboración propia, con base en la información del Catálogo das Artes y de Infonet.','cultura',-10.92525630,-37.04399230,'','{}'::text[],'[]'::jsonb,NULL,'','qr-d4f4c81c-1846-4482-b6b9-8e363705d935','',true,'',true,true,'','{}'::jsonb,'2025-11-25 14:01:41.935263+00','2026-02-28T23:16:44.872Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('7f414add-4ba5-4f70-890f-684de2741fea','Cotinguiba Esporte Clube','','','Fundado em 10 de outubro de 1909, o Cotinguiba Esporte Clube é o clube em atividade mais antigo de Sergipe e um dos mais tradicionais do estado. Localizado no bairro São José, em Aracaju, consolidou-se ao longo do século XX como importante referência esportiva, social e cultural da capital sergipana.
No futebol, o clube construiu trajetória marcante, conquistando seis títulos do Campeonato Sergipano da primeira divisão e também o título da Série A2. No remo, tornou-se o maior campeão estadual, somando 38 conquistas e fortalecendo a tradição náutica vinculada aos rios da região. No basquete, destacou-se nas décadas de 1930 e 1940, com títulos relevantes nos anos de 1938 e 1947.','Além das vitórias esportivas, o Cotinguiba desempenhou papel central na vida social de Aracaju, sendo palco de eventos culturais, festas carnavalescas e desfiles cívicos. Sua sede transformou-se em espaço de encontro e convivência para gerações de aracajuanos, integrando esporte e sociabilidade.
Em reconhecimento à sua relevância histórica, o clube foi declarado patrimônio histórico e cultural de Aracaju em 2018, por meio de legislação municipal. Atualmente, mantém instalações voltadas à prática esportiva e atividades de lazer, preservando sua tradição e identidade.','O nome “Cotinguiba” também possui forte significado regional, estando presente em referências geográficas como o Rio Cotinguiba e o Vale do Cotinguiba, elementos que reforçam a ligação histórica entre o clube e a identidade sergipana.
Elaboração própria, com base em informações de Sergipe, História do Futebol e Infonet.','','','','','','','historico',-10.92503980,-37.04468120,'','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/0e5a2edc-c022-4507-aebf-ff5dd86fd564.jpg','','qr-263eedc5-0de0-48e8-b24a-95c7834e105a','',true,'',false,false,'','{}'::jsonb,'2025-11-25 14:04:30.096598+00','2026-02-13T21:03:57.073Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('09fce838-96fe-40c3-835c-763dd7bf61f1','Praça Tobias Barreto','','','A Praça Tobias Barreto, situada no bairro São José, é um dos espaços públicos mais tradicionais de Aracaju, destacando-se por sua relevância histórica e cultural. Construída no início do século XX, acompanhou o desenvolvimento urbano da capital sergipana e consolidou-se como importante área de convivência da cidade. Em 2014, passou por ampla revitalização, recebendo novo paisagismo, parque infantil, aparelhos de ginástica, espaço de leitura, lago artificial e melhorias estruturais voltadas à segurança e acessibilidade.
Um dos grandes marcos do local é a Feirinha da Praça Tobias Barreto, realizada aos domingos, das 10h às 22h. O evento reúne artesãos e empreendedores locais que comercializam bordados, cerâmicas, artigos em palha, roupas pintadas à mão e diversas expressões do artesanato sergipano, além de comidas típicas e doces regionais. A feirinha tornou-se referência de cultura popular, promovendo o turismo de experiência e fortalecendo a economia criativa.','Em 2025, a programação cultural foi ampliada com a implementação do projeto “Descubra Aracaju: edição Praça Tobias Barreto”, realizado todos os domingos, às 16h. A iniciativa inclui apresentações musicais de artistas locais e o quadro “Revelação da Praça”, espaço destinado a cantores amadores, reforçando o caráter participativo e democrático do ambiente.','A praça homenageia o jurista, escritor e filósofo sergipano Tobias Barreto de Menezes, figura de destaque no pensamento jurídico e cultural brasileiro. Assim, a Praça Tobias Barreto reafirma-se como ponto de encontro que integra lazer, arte, memória e valorização da identidade sergipana.
Elaboração própria, com base em informações de Turismo Sergipe, Governo de Sergipe e Universidade Tiradentes (UNIT).','','','','','','','cultura',-10.92418030,-37.05100350,'','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/09b0f594-7478-4661-ac9a-86503b6818ca.jpg','','qr-1d5ea99f-3167-4ee8-aa45-44fa1ea9a6da','',true,'',false,true,'','{}'::jsonb,'2025-11-25 14:07:15.307716+00','2026-02-10T14:22:09.425Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('a0e794cd-c3a0-4ccb-9aa9-ba514c2b1dd6','Monumento "Dança: Um Apelo à Natureza"','Monument “Dance: An Appeal to Nature”','Monumento «Danza: un llamamiento a la naturaleza»','Ao percorrer a Orla de Atalaia, a paisagem litorânea e o fluxo de visitantes convivem com intervenções artísticas que dialogam com o ambiente costeiro. Entre áreas de lazer e espaços de convivência, a arte pública também desempenha uma função educativa, estimulando a reflexão sobre a relação entre a sociedade e a natureza. Nesse contexto, integra-se ao conjunto artístico-cultural da orla a escultura “Dança: Um Apelo à Natureza”.
De autoria do artista sergipano Deolando Vieira, a obra foi concebida para estimular a consciência ecológica por meio de uma linguagem simbólica inspirada na dança. A composição remete à ideia de harmonia e interdependência entre seres humanos e meio ambiente, destacando a importância da preservação ambiental. O enfoque recai especialmente sobre a proteção dos ecossistemas marinhos e da vegetação associada à zona costeira, tema relevante em um espaço de ampla circulação pública.','Instalada em um dos principais polos turísticos de Aracaju, a escultura amplia o papel da arte urbana como instrumento de sensibilização socioambiental. Ao articular expressão estética e mensagem educativa, contribui para consolidar a orla não apenas como área de lazer, mas também como espaço de educação ambiental e de valorização do patrimônio natural.','Mais do que um elemento paisagístico, Dança: Um Apelo à Natureza insere a pauta da sustentabilidade no cotidiano urbano. A presença da obra reforça a integração entre cultura, turismo e meio ambiente, alinhando a fruição artística à responsabilidade coletiva no espaço público.
Elaboração própria, com base em informações institucionais do Estado de Sergipe.','Along the Atalaia Waterfront, the coastal landscape and the steady flow of visitors coexist with artistic interventions that engage directly with the surrounding environment. Amid leisure facilities and public gathering areas, art also serves an educational purpose, encouraging reflection on the relationship between society and nature. Within this setting stands the sculpture Dança: Um Apelo à Natureza (“Dance: An Appeal to Nature”), part of the waterfront’s broader cultural ensemble.
Created by Sergipe-born artist Deolando Vieira, the work was conceived to foster ecological awareness through a symbolic language inspired by dance. Its composition evokes harmony and interdependence between human life and the natural world, underscoring the importance of environmental stewardship. Particular emphasis is placed on protecting marine ecosystems and coastal vegetation — an especially relevant message in a high-visibility public space.','Established in one of Aracaju’s main tourism corridors, the sculpture expands the role of public art as a tool for environmental awareness. By bringing together aesthetic expression and social messaging, it reinforces the waterfront’s function not only as a leisure area but also as a space for environmental education and appreciation of natural heritage.','More than a landscape feature, Dança: Um Apelo à Natureza introduces sustainability into the city’s everyday experience. Its presence strengthens the connection between culture, tourism, and environmental responsibility, aligning artistic expression with collective stewardship in Aracaju’s urban setting.
Prepared based on institutional information from the State of Sergipe.','A lo largo de la Orla de Atalaia, el paisaje costero y el flujo constante de visitantes conviven con intervenciones artísticas que dialogan con el entorno natural. Entre las áreas de ocio y los espacios de convivencia, el arte público también cumple una función educativa al promover la reflexión sobre la relación entre la sociedad y la naturaleza. En este contexto, se integra la escultura Dança: Um Apelo à Natureza («Danza: un llamamiento a la naturaleza») como parte del conjunto artístico-cultural del frente marítimo.
La obra, creada por el artista sergipano Deolando Vieira, fue concebida para estimular la conciencia ecológica mediante un lenguaje simbólico inspirado en la danza. Su composición alude a la armonía y la interdependencia entre los seres humanos y el medio ambiente, subrayando la importancia de la preservación ambiental. El mensaje pone especial énfasis en la protección de los ecosistemas marinos y de la vegetación asociada al litoral, una temática especialmente pertinente en un espacio público de amplia circulación.','Ubicada en uno de los principales polos turísticos de Aracaju, la escultura amplía el papel del arte urbano como herramienta de sensibilización socioambiental. Al articular la expresión estética y el contenido educativo, contribuye a consolidar la orla no solo como área de recreación, sino también como espacio de educación ambiental y de valorización del patrimonio natural.','Más que un elemento paisajístico, Dança: Um Apelo à Natureza incorpora la sostenibilidad al cotidiano urbano. Su presencia refuerza la integración entre la cultura, el turismo y el medio ambiente, vinculando la experiencia artística con la responsabilidad colectiva en el espacio público.
Elaboración propia, con base en información institucional del Estado de Sergipe.','cultura',-10.98245710,-37.04430050,'Orla De Atalaia - Atalaia, Aracaju - SE, 49035-253','{}'::text[],'[{"id": "gallery-0", "url": "/objects/uploads/dbad3554-98a7-4f3a-98eb-ee4841eef5b0", "type": "gallery", "order": 0}, {"id": "gallery-1", "url": "/objects/uploads/22900874-ed13-42aa-9b34-39f29cc201d8", "type": "gallery", "order": 1}]'::jsonb,'/objects/uploads/ee72a60f-2417-438f-b5bc-4389a1a0481c','','qr-fa03c3d5-4745-4276-8c22-b732ce2963f7','https://maps.app.goo.gl/FFHTVdtqqApEMyjz5',true,'',true,true,'','{}'::jsonb,'2025-11-25 14:11:58.170741+00','2026-03-01T17:09:57.547Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('bff12ff0-1b0d-4fac-a715-2c05ca37fe6c','Praça Inácio Barbosa ','','','Na área conhecida como Praça do Mini Golf, atrás do monumento principal, um detalhe chama a atenção de quem observa com mais cuidado: o mapa de Aracaju desenhado em alto relevo no piso da praça. A representação funciona como convite simbólico para que moradores e visitantes descubram as histórias e curiosidades que moldaram a capital sergipana.
A Praça Doutor Inácio Joaquim Barbosa está localizada às margens do Rio Sergipe, entre os bairros 13 de Julho e São José, marcando também o início da Avenida Ivo do Prado, uma das vias mais tradicionais da cidade, que conecta essa área ao centro histórico. Sua posição estratégica reforça o papel da praça como elo entre paisagem natural, mobilidade urbana e memória histórica.','Entre as décadas de 1960 e 1970, o espaço abrigou um campo de mini-golf, modalidade esportiva de origem europeia que, apesar da estrutura instalada, não se consolidou entre os aracajuanos. Posteriormente, a área passou por reformulação completa, mas o apelido “Praça do Mini Golf” permaneceu no imaginário popular e segue sendo utilizado até hoje.','Assim, a praça reúne passado e presente em um mesmo cenário: um espaço de convivência à beira-rio que preserva marcas da história urbana de Aracaju e continua sendo ponto de referência para quem circula pela região.
Elaboração própria, com base em informações adaptadas da Prefeitura de Aracaju (2025).','','','','','','','historico',-10.92421900,-37.04421090,'','{}'::text[],'[]'::jsonb,NULL,'','qr-eda42e43-db3f-4a67-a0c3-15dc6feab2cd','',true,'',false,false,'','{}'::jsonb,'2025-11-25 14:21:41.026302+00','2026-02-13T20:54:22.979Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('86da4480-665e-441f-9f28-4b6b8b713d54','Praça Getúlio Vargas (antiga praça mini-golfe)','','','A Praça Getúlio Vargas, popularmente conhecida como Praça do Mini Golf, é um dos marcos históricos do bairro São José, em Aracaju. Inaugurada em 10 de novembro de 1938, o espaço preserva elementos significativos do processo de urbanização da capital e mantém viva parte importante da memória coletiva da cidade.
Entre seus destaques está o primeiro abrigo de passageiros de Aracaju, que funcionava como ponto de bonde na década de 1930, símbolo do desenvolvimento dos transportes urbanos no início do século XX. A praça também abriga um busto em homenagem ao ex-presidente Getúlio Vargas, além de um memorial com painéis fotográficos que registram momentos marcantes da história aracajuana.','Localizada ao lado da sede da OAB Sergipe e próxima à Avenida Augusto Maynard, a praça está inserida em área de relevância histórica. Nas proximidades situava-se a antiga Praia Formosa, cenário de acontecimentos ligados ao movimento tenentista em Sergipe, em 1924, reforçando o valor histórico do entorno.
Por sua posição estratégica, a visita pode ser combinada com outros atrativos próximos, como o Mirante do Bairro 13 de Julho, que oferece vista panorâmica do Rio Sergipe; o Museu da Gente Sergipana, referência cultural e tecnológica no Nordeste; o Largo da Gente Sergipana, com esculturas que representam personagens do folclore local; e o tradicional Calçadão da 13 de Julho, ideal para caminhadas e atividades ao','De acesso público e funcionamento contínuo, a Praça Getúlio Vargas conta com iluminação cênica e acessibilidade, permanecendo como espaço de convivência, memória e lazer no coração histórico de Aracaju.
Elaboração própria, com base em informações do IBGE, Cohab e da Prefeitura de Aracaju.','','','','','','','historico',-10.92351460,-37.04506720,'','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/a11477a3-20e1-49b8-8386-de26e38861f3.jpg','','qr-df630b2f-445c-4840-ae3d-4361ebad23b5','',true,'',false,true,'','{}'::jsonb,'2025-11-25 14:25:18.006364+00','2026-03-01T01:07:04.728Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('9227d1ba-a6fc-42a2-9bac-898d45dad4cb','Casa de Zé Peixe','','','José Martins Ribeiro Nunes, conhecido como Zé Peixe, nasceu em 5 de janeiro de 1927, em Aracaju, às margens do Rio Sergipe. Filho de Nicanor Ribeiro Nunes e Vetúria Martins Ribeiro Nunes, cresceu em contato direto com as águas do rio, onde aprendeu a nadar ainda na infância. O rio não era apenas cenário de suas brincadeiras juvenis, mas o espaço onde desenvolveu habilidades que marcariam sua trajetória de vida.
Aos 20 anos, após aprovação em concurso, iniciou suas atividades como prático da Capitania dos Portos de Sergipe, função que exerceu por quase cinco décadas. Tornou-se conhecido nacional e internacionalmente por sua forma singular de trabalho: dispensava embarcações de apoio e nadava até os navios para conduzi-los com segurança. Após guiar as embarcações ao mar aberto, saltava de alturas que chegavam a 17 metros, retornando à praia a nado, percursos que podiam alcançar até 10 quilômetros e, muitas vezes, ainda seguia longas distâncias a pé até a sede da Capitania. Em algumas ocasiões utilizava apenas uma prancha para se deslocar até embarcações mais distantes.','Essa relação intensa com o rio e o mar transformou Zé Peixe em figura lendária no imaginário sergipano. Mesmo já em idade avançada, manteve-se ativo na profissão, surpreendendo tripulações e comandantes com sua resistência física e coragem. Somente aos 82 anos, enfrentando problemas de saúde, solicitou afastamento das atividades junto à Marinha.
Ao longo da vida, recebeu diversas homenagens e condecorações, entre elas a Medalha do Mérito Serigy e a Medalha Almirante Tamandaré. Sua trajetória foi registrada em livros, reportagens e documentários, destacando-se a biografia Amigo das Águas, publicada pelo Instituto Banese. Em Aracaju, sua memória permanece viva por meio de monumentos e espaços dedicados à sua história, como a escultura “O Prático”, instalada no Museu da Gente Sergipana, além de homenagens na Capitania dos Portos e no Espaço Zé Peixe, localizado no antigo Terminal Hidroviário.','Zé Peixe faleceu em 2012, deixando legado de coragem, dedicação e profundo vínculo com o Rio Sergipe. Sua história ultrapassa os limites da profissão e se insere no patrimônio cultural de Sergipe, consolidando-o como símbolo de bravura e identidade para Aracaju.
Elaboração própria, com base em informações do Prof. Rony Silva e registros da Universidade Tiradentes (UNIT).','','','','','','','cultura',-10.91999380,-37.04628530,'Av. Ivo do Prado, 25 - Centro, Aracaju - SE, 49010-540','{}'::text[],'[]'::jsonb,NULL,'','qr-5ec0c888-9ecc-4c4a-be94-060f423a5472','https://maps.app.goo.gl/GvBUos71vzwsMXGW8',true,'Seg a domingo: 09h às 17h; ',false,true,'','{}'::jsonb,'2025-11-25 14:30:05.315805+00','2026-03-01T01:11:30.402Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('5cfb05b4-66e4-4282-87d2-5dd18f2b4025','Praça Camerino','','','Localizada no centro de Aracaju, a Praça Camerino é um tradicional espaço de convivência urbana criado em 1951 e vinculado à memória histórica sergipana. O nome homenageia Francisco Camerino (1841–1866), natural de Estância, voluntário na Guerra do Paraguai, reconhecido por sua bravura e falecido na Batalha de Curupaiti. Embora a denominação tenha sido consolidada na década de 1910, foi a partir de meados do século XX que a praça passou a desempenhar papel relevante como ponto de passagem, encontro e lazer na capital.
O conjunto simbólico do espaço reúne referências culturais e históricas distintas. O monumento central é dedicado a Silvio Romero, instalado em 1951 por ocasião do centenário de nascimento do poeta e crítico literário lagartense. Em 2014, foi incorporada ao local uma escultura em homenagem a Francisco Camerino, reforçando a identidade histórica associada ao nome da praça.
Entre 2013 e 2014, a Praça Camerino passou por processo de revitalização no âmbito do PAC Cidades Históricas, recebendo nova pavimentação, áreas de leitura, quiosques e espaços voltados ao lazer e à permanência. O projeto buscou qualificar o ambiente urbano e preservar seu valor patrimonial, mantendo-o integrado ao cotidiano do centro da cidade.
A praça abriga ainda a sede da Superintendência do Instituto do Patrimônio Histórico e Artístico Nacional em Sergipe, instalada na antiga residência do Dr. Leonardo Gomes de Carvalho Leite, reforçando o caráter institucional e histórico do espaço.
Tradicionalmente associada a festas, encontros e manifestações culturais, a Praça Camerino permanece como importante espaço público de convivência no centro de Aracaju, articulando memória, cultura e vida urbana em um mesmo cenário.
Elaboração própria, com base em informações da Prefeitura de Aracaju.','Instalada desde 2006 na chamada Casa de Aracaju, na Praça Camerino, nº 225, no Centro Histórico, a sede da Superintendência do Instituto do Patrimônio Histórico e Artístico Nacional (IPHAN) em Sergipe ocupa um dos palacetes mais emblemáticos do início do século XX na capital. O imóvel é um raro exemplar da arquitetura que dialoga com referências da Belle Époque e do art déco, estilos que marcaram o período de modernização urbana de Aracaju, quando a cidade começava a consolidar sua identidade arquitetônica e institucional.
A aquisição do prédio pelo IPHAN teve como objetivo preservar um dos poucos remanescentes desse momento histórico, caracterizado por fachadas ornamentadas, elementos decorativos como festões e uma composição arquitetônica que refletia a influência europeia nas construções urbanas da época. O palacete simboliza a transição econômica vivenciada por Sergipe no início do século XX, período em que o capitalismo industrial passou a influenciar a organização urbana e os investimentos públicos.
Mais do que uma sede administrativa, a Casa de Aracaju funciona como “Casa do Patrimônio”, espaço voltado à salvaguarda da memória e da identidade cultural sergipana. O local também abriga exposições temporárias e ações educativas, como mostras relacionadas ao patrimônio histórico estadual e ao conjunto arquitetônico de São Cristóvão, reconhecido como Patrimônio Mundial.
A atuação do IPHAN em Sergipe vai além do prédio-sede. A superintendência acompanha e fiscaliza bens materiais e imateriais, supervisiona intervenções em igrejas históricas, conjuntos urbanos e estruturas ferroviárias, além de monitorar áreas de relevância histórica no Centro de Aracaju. Assim, a Casa de Aracaju não representa apenas um imóvel preservado, mas um núcleo ativo de proteção e valorização do patrimônio cultural sergipano.
Fonte: Elaboração própria baseada em informações do IPHAN
','','','','','','','','',-10.91837250,-37.04915570,'','{}'::text[],'[]'::jsonb,NULL,'','qr-48913865-e8fe-45a9-8ce2-a0059bccbf75','',true,'',false,false,'','{}'::jsonb,'2025-11-25 14:34:04.678602+00','2026-02-13T14:07:35.995Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('aab2c234-3ee0-4caf-a3ff-899d6184730c','Praça Almirante Barroso','','','A Praça Almirante Barroso, anteriormente denominada Praça Guilherme Campos, é a menor das três praças que compõem o núcleo histórico central de Aracaju. Apesar de sua dimensão reduzida, destaca-se por concentrar importante conjunto de monumentos arquitetônicos que representam diferentes fases da organização política e administrativa do estado.
Entre os principais edifícios situados na praça está o Palácio Olímpio Campos, atual sede do Governo do Estado. Durante o processo de modernização urbana no início do século XX, o prédio passou por significativa reforma estética conduzida pela chamada Missão Italiana, em 1918, substituindo o estilo neoclássico original, de influência imperial, por características ecléticas associadas ao período republicano. Atualmente, o palácio também abriga espaço museológico dedicado à memória da República em Sergipe.
No mesmo conjunto arquitetônico encontra-se o Palácio Fausto Cardoso, sede histórica da Assembleia Legislativa, que também foi reformado nesse período para incorporar a nova linguagem arquitetônica republicana. Hoje, o edifício funciona como Escola Superior do Legislativo, mantendo sua relevância institucional.
Completa o conjunto o antigo prédio da Intendência, à época responsável pelo tesouro estadual, que atualmente abriga a Câmara Municipal de Aracaju.
Assim, a Praça Almirante Barroso configura-se como espaço simbólico do poder público em Sergipe, reunindo edificações que traduzem a transição entre o período imperial e a consolidação da República, além de representar um dos mais expressivos conjuntos da arquitetura civil urbana da capital.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).
','Palmeiras Imperiais:
As palmeiras imperiais que compõem o eixo paisagístico entre a Ponte do Imperador e a Catedral Metropolitana de Aracaju constituem um dos mais expressivos símbolos do período monárquico na capital sergipana. O plantio dessas árvores no século XIX está associado à visita de Dom Pedro II a Sergipe, em 1860, funcionando como homenagem e marco visual da presença imperial na cidade.
Da espécie Roystonea oleracea, as palmeiras imperiais foram introduzidas no Brasil em 1809, durante o reinado de Dom João VI, e passaram a representar poder, distinção e vínculo com a monarquia. Suas sementes eram distribuídas a figuras influentes, o que contribuiu para sua disseminação em espaços públicos e propriedades de destaque.
Em Aracaju, essas árvores passaram a integrar a paisagem do centro histórico, especialmente em áreas como a Praça Almirante Barroso, reforçando o caráter simbólico e monumental do espaço urbano. Com crescimento rápido e podendo atingir até 40 metros de altura, as palmeiras destacam-se pela imponência e elegância, contribuindo para a composição arquitetônica e paisagística do entorno.
Mais do que elementos decorativos, as palmeiras imperiais em Aracaju representam marcos históricos vivos do período imperial brasileiro, mantendo na paisagem urbana a memória da relação de Sergipe com a monarquia no século XIX.
Elaboração própria, com base em informações da Prefeitura de Aracaju e fontes especializadas.
','','','','','','','','',-10.91325630,-37.04974730,'','{}'::text[],'[]'::jsonb,NULL,'','qr-dbfa5557-23ca-4f7f-bdf5-e67df8b33ad5','',true,'',false,false,'','{}'::jsonb,'2025-11-25 14:38:58.89778+00','2026-02-12T18:38:01.355Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('6ae72f85-b089-403f-9be8-869428de4d75','Praça Olímpio Campos ','','','A Praça Olímpio Campos ocupa posição central na história política e urbana de Aracaju. Seu nome homenageia Olímpio Campos, que governou Sergipe entre 1899 e 1902 e exerceu mandato de senador de 1903 a 1906, período marcado pelo chamado coronelismo, contexto em que lideranças estaduais mantinham alianças estratégicas com o governo federal para fortalecimento político. Considerado uma das principais lideranças conservadoras do estado à época, Olímpio Campos consolidou influência por meio da articulação entre interesses políticos e religiosos.
No coração da praça está a Catedral Metropolitana de Aracaju, onde se encontram os restos mortais de Olímpio Campos. O espaço urbano ao redor tornou-se ponto de convivência e referência histórica da capital. Atualmente, a praça abriga o Parque Teófilo Dantas e tradicional feira de artesanato, que movimenta o centro com produtos regionais e expressões culturais.
O entorno imediato reúne importantes edificações institucionais: ao lado da Catedral localiza-se o prédio da Arquidiocese de Aracaju e a antiga sede da Prefeitura; ao fundo está o Memorial do Judiciário; e, à esquerda, a conhecida Rua do Turista, que integra o circuito comercial e cultural da região central.
Assim, a Praça Olímpio Campos reúne política, religião, cultura e lazer em um mesmo espaço, configurando-se como um dos núcleos históricos mais significativos de Aracaju.
Elaboração própria, com base em informações do Circuito Histórico de Aracaju e da Prefeitura de Aracaju (2018).
','Prédio do Cacique Chá:
Inaugurado em 1940, o Cacique Chá tornou-se um dos espaços mais emblemáticos da vida cultural e intelectual de Aracaju. Durante décadas, foi ponto de encontro de jornalistas, artistas, políticos e formadores de opinião, consolidando-se como ambiente de debates, encontros sociais e efervescência cultural, especialmente nas décadas de 1960 e 1970.
Com o encerramento de suas atividades, o prédio permaneceu abandonado por um período, colocando em risco um de seus maiores patrimônios artísticos: os afrescos do pintor sergipano Jenner Augusto. Os painéis, pintados nas paredes internas, retratam a diversidade cultural e o cotidiano do povo sergipano, constituindo importante registro artístico e identitário.
A reinauguração do espaço marcou não apenas sua recuperação física, mas também a valorização da memória cultural da cidade. Na ocasião, foi realizado tributo a Jenner Augusto, e o local passou a abrigar permanentemente um memorial em sua homenagem. Além da função cultural, o prédio também passou a receber cursos profissionalizantes, como os da área de gastronomia, ampliando seu papel social e educativo.
O Cacique Chá, portanto, permanece como símbolo da história cultural de Aracaju, reunindo arte, memória e formação cidadã em um mesmo espaço.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2015).
','','','','','','','','historico',-10.91389870,-37.05159890,'','{}'::text[],'[]'::jsonb,NULL,'','qr-83db37af-ebff-4917-b2fc-26bdf62d37d6','',true,'',false,false,'','{}'::jsonb,'2025-11-25 14:59:54.485114+00','2026-02-12T16:05:11.782Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('9ef320ba-0769-4089-9556-5176dd0b4888','Catedral Metropolitana de Aracaju','','','Localizada na Praça Olímpio Campos, no centro histórico da capital, a Catedral Metropolitana de Aracaju,oficialmente Igreja Matriz de Nossa Senhora da Conceição, é um dos principais marcos religiosos e arquitetônicos da cidade. Sua construção teve início em 1862, sendo inaugurada em 1875, período em que Aracaju consolidava sua estrutura urbana após a transferência da capital.
Em 1910, com a criação da Diocese de Aracaju, o templo foi elevado à condição de Catedral, passando a sediar oficialmente a administração eclesiástica a partir de 1911. Décadas depois, em 1960, com a instituição da Arquidiocese, tornou-se Sede Metropolitana, assumindo posição de destaque na organização religiosa do estado.','O edifício passou por importante reforma geral em 1936, sendo reinaugurado em 1946 já com características do estilo neogótico, perceptíveis nas linhas verticais acentuadas, nos elementos decorativos e na composição arquitetônica que valoriza a imponência da fachada. A transformação consolidou sua identidade visual atual e reforçou sua presença como referência estética no centro da cidade.','Além de seu valor religioso, a Catedral integra o conjunto histórico da capital e desempenha papel central nas celebrações litúrgicas e eventos tradicionais de Aracaju. Sua localização estratégica e relevância simbólica fazem dela ponto essencial para compreender a formação histórica, cultural e espiritual da cidade.
Elaboração própria, com base em registros históricos sobre a Catedral de Aracaju.','','','','','','','',-10.91337780,-37.05179830,'','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/c0a03b37-6a9e-4fce-9907-986ac29ca1c5.jpg','','qr-e6c4abfa-0e22-422c-aa89-1ec4ea55de50','',true,'',false,false,'','{}'::jsonb,'2025-11-25 15:05:28.193665+00','2026-02-09T19:34:18.991Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('3408fa8e-6352-423c-bed5-ba419cc44df7','Igreja São Salvador','Church of Saint Saviour','Iglesia de San Salvador','A Igreja São Salvador foi o primeiro templo católico de Aracaju, inaugurado em 23 de outubro de 1857, poucos anos após a criação da nova capital sergipana. Seu nome homenageia o então presidente da Província, Salvador Correia de Sá e Benevides, que incentivou sua construção. Desde então, o edifício consolidou-se como um dos principais marcos religiosos e históricos do processo de estruturação urbana de Aracaju, integrando o conjunto de referências que testemunham a formação institucional da cidade.
Inicialmente concebida como capela, a edificação foi ampliada em razão do rápido crescimento populacional da capital, passando a exercer a função de Igreja Matriz até a conclusão da Catedral Metropolitana de Aracaju. Ao longo do século XIX, o templo assumiu papel central na vida social e religiosa, sediando celebrações dedicadas a São Benedito, ao Bom Jesus dos Navegantes e a outras festividades que estruturavam o calendário comunitário da época.','Em 1858, foi construído, nos fundos da igreja, um túmulo de mármore para abrigar os restos mortais de Joaquim Inácio Barbosa, responsável pela fundação de Aracaju. Transferidos da cidade de Estância, seus despojos chegaram em cortejo solene pelas ruas centrais da capital e ali permaneceram até 1917, quando foram levados ao obelisco erguido na atual Praça Dr. Joaquim Inácio Barbosa, na Avenida Ivo do Prado. A igreja também foi cenário da visita do imperador Dom Pedro II e da imperatriz Teresa Cristina, em 1860, ocasião em que participaram de um Te Deum — celebração litúrgica solene em ação de graças — marcando a passagem oficial da comitiva imperial por Sergipe.','Mais do que um espaço de culto, a Igreja São Salvador constitui um dos marcos fundacionais de Aracaju. Sua presença no centro histórico sintetiza o processo de consolidação da capital e preserva dimensões relevantes da memória política, social e religiosa do estado, integrando o patrimônio cultural que contribui para a compreensão da trajetória urbana sergipana.
Elaboração própria, com base em Andrade e Filho (2012).','São Salvador Church was the first Catholic temple in Aracaju, inaugurated on October 23, 1857, just a few years after the establishment of the new capital of Sergipe. Its name honors the then President of the Province, Salvador Correia de Sá e Benevides, who encouraged its construction. Since then, the building has become one of the main religious and historical landmarks in Aracaju’s urban development, forming part of the set of references that bear witness to the city’s institutional formation.
Originally conceived as a chapel, the structure was expanded due to the rapid population growth of the capital and went on to serve as the Mother Church until the completion of the Metropolitan Cathedral of Aracaju. Throughout the 19th century, the temple played a central role in social and religious life, hosting celebrations dedicated to Saint Benedict, Bom Jesus dos Navegantes, and other festivities that shaped the community calendar.','In 1858, a marble tomb was built at the rear of the church to house the remains of Joaquim Inácio Barbosa, founder of Aracaju. Transferred from the city of Estância, his remains arrived in a solemn procession through the central streets of the capital. It remained there until 1917, when it was moved to the obelisk erected in what is now Dr. Joaquim Inácio Barbosa Square, on Ivo do Prado Avenue.
The church was also the setting for the visit of Emperor Dom Pedro II and Empress Teresa Cristina in 1860, when they attended a Te Deum — a solemn liturgical celebration of thanksgiving — marking the official passage of the imperial entourage through Sergipe.','More than a place of worship, São Salvador Church constitutes one of the foundational landmarks of Aracaju. Its presence in the historic center symbolizes the consolidation of the capital and preserves significant dimensions of the state’s political, social, and religious memory, forming part of the cultural heritage that helps understand Sergipe’s urban trajectory.
Prepared by the author, based on Andrade and Filho (2012).','La Iglesia São Salvador fue el primer templo católico de Aracaju, inaugurado el 23 de octubre de 1857, pocos años después de la creación de la nueva capital sergipana. Su nombre rinde homenaje al entonces presidente de la Provincia, Salvador Correia de Sá e Benevides, quien impulsó su construcción. Desde entonces, el edificio se consolidó como uno de los principales hitos religiosos e históricos en el proceso de estructuración urbana de Aracaju, integrando el conjunto de referencias que testimonian la formación institucional de la ciudad.
Concebida inicialmente como capilla, la edificación fue ampliada debido al rápido crecimiento poblacional de la capital y pasó a ejercer la función de Iglesia Matriz hasta la finalización de la Catedral Metropolitana de Aracaju. A lo largo del siglo XIX, el templo desempeñó un papel central en la vida social y religiosa, acogiendo celebraciones dedicadas a San Benito, al Buen Jesús de los Navegantes y a otras festividades que estructuraban el calendario comunitario de la época.','En 1858 se construyó, en la parte posterior de la iglesia, un mausoleo de mármol destinado a albergar los restos mortales de Joaquim Inácio Barbosa, fundador de Aracaju. Trasladados desde la ciudad de Estância, sus restos llegaron en solemne procesión por las calles centrales de la capital y permanecieron allí hasta 1917, cuando fueron trasladados al obelisco erigido en la actual Plaza Dr. Joaquim Inácio Barbosa, en la Avenida Ivo do Prado.
La iglesia también fue escenario de la visita del emperador Dom Pedro II y de la emperatriz Teresa Cristina en 1860, ocasión en la que participaron en un Te Deum, celebración litúrgica solemne de acción de gracias, que marcó el paso oficial de la comitiva imperial por la provincia de Sergipe.','Más que un espacio de culto, la Iglesia São Salvador es uno de los hitos fundacionales de Aracaju. Su presencia en el centro histórico simboliza el proceso de consolidación de la capital y preserva dimensiones relevantes de la memoria política, social y religiosa del estado, integrando el patrimonio cultural que contribuye a la comprensión de la trayectoria urbana sergipana.
Elaboración propia, con base en Andrade y Filho (2012).','historico',-10.91157200,-37.04908400,'R. Laranjeiras, 110 - Centro, Aracaju - SE, 49010-000','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/16906b05-c700-42fb-9599-abea89148fa7.jpg','','qr-8511e398-5b31-49ea-9b76-b63f9ac12618','https://maps.app.goo.gl/fZbwTH41pTRTwAXUA',true,'Seg a sex: 08h às 17h; Sábado: 09h às 13h e Domingo: 07h às 09h',false,true,'','{}'::jsonb,'2025-11-25 15:16:39.519019+00','2026-03-02T18:06:56.092Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('db48ac94-c77b-45ef-9cc2-a216bbfe3bc0','Mercados Municipais Centrais de Aracaju','Municipal Markets','Mercados Municipales','Mergulhar nos Mercados Municipais Centrais de Aracaju é compreender a cidade por meio de seus sabores, cores e tradições. O complexo é composto pelo Mercado Municipal Antônio Franco, Mercado Thales Ferraz, Mercado Albano Franco e pelo espaço dedicado ao artesanato, o Mercado Maria Virgínia Leite Franco. Localizados na região central da capital, nas proximidades do Rio Sergipe, os mercados constituem um dos principais polos culturais, gastronômicos e comerciais do município.
O Mercado Antônio Franco, inaugurado no início do século XX e identificado pelo relógio instalado em 1926, preserva características arquitetônicas históricas e concentra bancas de frutas regionais, castanhas, queijos, temperos e frutos do mar. O espaço reúne ingredientes tradicionais da culinária sergipana e permite ao visitante conhecer preparações típicas como moqueca, camarão, tapioca e cuscuz, além de frutas características da região, como caju, mangaba e fruta-pão.','O Mercado Thales Ferraz complementa o conjunto ao integrar o comércio tradicional e a alimentação popular, funcionando como extensão do cotidiano urbano. O Mercado Albano Franco, por sua vez, passou por um processo de revitalização concluído em 2000, incorporando uma estrutura mais contemporânea e ampliando a capacidade de atendimento a comerciantes e visitantes, o que contribuiu para consolidar o complexo como ambiente que articula tradição e modernização.
No Mercado Maria Virgínia Leite Franco, o foco recai sobre o artesanato regional. Rendas, bordados, cerâmicas e peças decorativas evidenciam saberes tradicionais e reforçam o papel do mercado como vitrine da produção cultural sergipana, estimulando a economia criativa local.','Mais do que meros espaços de comercialização, os mercados municipais constituem ambientes de sociabilidade e de memória coletiva. Cada banca representa práticas transmitidas entre gerações, e cada produto traduz referências culturais que dialogam com a história e o modo de vida da capital. O complexo integra, assim, o conjunto de equipamentos culturais que contribuem para a preservação da identidade local e para a qualificação da experiência turística em Aracaju.
Elaboração própria, com base em informações institucionais do site do Mercado Municipal de Aracaju.','Exploring the Central Municipal Markets of Aracaju offers insight into the city through its flavors, colors, and traditions. The complex comprises the Mercado Municipal Antônio Franco, Mercado Thales Ferraz, Mercado Albano Franco, and the handicraft-dedicated Mercado Maria Virgínia Leite Franco. Located in the city center, near the Sergipe River, the markets form one of the municipality’s main cultural, gastronomic, and commercial hubs.
The Antônio Franco Market, inaugurated in the early 20th century and known for its 1926 clock, preserves historical architectural features and houses stalls selling regional fruits, nuts, cheeses, spices, and fresh seafood. The site brings together traditional ingredients of Sergipe’s cuisine. It allows visitors to experience typical dishes such as moqueca, shrimp preparations, tapioca, and couscous, as well as regional fruits including cashew, mangaba, and breadfruit.','The Thales Ferraz Market complements the complex by integrating traditional commerce with popular dining, functioning as an extension of everyday urban life. The Albano Franco Market underwent a revitalization process completed in the 2000´s, incorporating a more contemporary structure and expanding capacity for vendors and visitors, thereby consolidating the complex as a space that balances tradition and modernization.
At the Maria Virgínia Leite Franco Market, the focus is on regional handicrafts. Lacework, embroidery, ceramics, and decorative pieces reflect traditional knowledge and reinforce the market’s role as a showcase for Sergipe’s cultural production, supporting the local creative economy.','Municipal markets do more than serve as commercial spaces; they also provide environments for social interaction and create a collective memory. Each stall reflects practices passed down through generations, and every product carries cultural significance tied to the city’s history and way of life. As a result, these markets are integral to the cultural infrastructure that preserves local identity and enriches the tourism experience in Aracaju.
','Recorrer los Mercados Municipales Centrales de Aracaju permite comprender la ciudad a través de sus sabores, colores y tradiciones. El complejo está compuesto por el Mercado Municipal Antônio Franco, el Mercado Thales Ferraz, el Mercado Albano Franco y el Mercado Maria Virgínia Leite Franco, dedicado a la artesanía. Ubicados en la región central de la capital, próximos al río Sergipe, los mercados constituyen uno de los principales polos culturales, gastronómicos y comerciales del municipio.
El Mercado Antônio Franco, inaugurado a comienzos del siglo XX y reconocido por su reloj instalado en 1926, conserva características arquitectónicas históricas y alberga puestos de frutas regionales, frutos secos, quesos, especias y mariscos frescos. El espacio reúne ingredientes tradicionales de la cocina sergipana y permite a los visitantes conocer preparaciones típicas como la moqueca, platos de camarón, tapioca y cuscús, así como frutas regionales como el anacardo, la mangaba y el fruto del pan.','El Mercado Thales Ferraz complementa el conjunto al integrar el comercio tradicional y la gastronomía popular, funcionando como una extensión de la vida cotidiana urbana. El Mercado Albano Franco, por su parte, pasó por un proceso de revitalización concluido en 2000, que incorporó una estructura más contemporánea y amplió la capacidad para comerciantes y visitantes, lo que consolidó el complejo como un espacio que equilibra tradición y modernización.
En el Mercado Maria Virgínia Leite Franco, el protagonismo es de la artesanía regional. Encajes, bordados, cerámicas y piezas decorativas expresan saberes tradicionales y refuerzan el papel del mercado como vitrina de la producción cultural de Sergipe, impulsando la economía creativa local.','Más que espacios comerciales, los mercados municipales constituyen entornos de convivencia y de memoria colectiva. Cada puesto representa prácticas transmitidas de generación en generación y cada producto refleja referencias culturales vinculadas a la historia y al modo de vida de la capital. El complejo forma parte, así, de la infraestructura cultural que contribuye a preservar la identidad local y a cualificar la experiencia turística en Aracaju.
Elaboración propia, basada en información institucional del sitio web del Mercado Municipal de Aracaju.','cultura',-10.90652440,-37.04885840,'Av. Ivo do Prado, 534 - Centro, Aracaju - SE, 49010-110','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/17929346-74c6-4337-930e-47aa8e9a6769.jpg','','qr-7abcfa48-2bae-48d7-b3b8-8350ec8ecc5d','https://maps.app.goo.gl/pR6c6cvX44qNjpa59',true,'Segunda a sábado: 06h às 16h45; Domingo: 06h às 12h',false,true,'','{}'::jsonb,'2025-11-25 15:21:14.330879+00','2026-03-02T17:14:40.426Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('2f4ab15c-e2e1-49ef-af5a-232c45f81d0f','Orla do Bairro Industrial','Industrial District Waterfront','Orla del Barrio Industrial','Localizado às margens do Rio Sergipe, o Centro de Artesanato Chica Chaves integra um dos cenários urbanos mais representativos da capital: a Orlinha do Bairro Industrial, em Aracaju. A área combina vista privilegiada do rio, espaços de convivência e percurso para caminhadas, consolidando-se como ponto de encontro para moradores e visitantes que buscam lazer ao ar livre e contato com a paisagem ribeirinha.
Inaugurado em março de 2005, o Centro de Artesanato foi concebido como um equipamento voltado à valorização e à comercialização da produção artesanal sergipana. O espaço reúne exposição permanente e a venda de peças elaboradas por artesãs locais, promovendo a geração de renda e o fortalecimento da identidade cultural regional. A iniciativa contribui para a salvaguarda de saberes tradicionais e para a inserção do artesanato no circuito turístico da cidade.','Entre as técnicas representadas destacam-se bordado à mão, renda irlandesa, crochê, vagonite, pintura em tecido, trabalhos em biscuit, cerâmica, confecção de bonecas de pano e esculturas temáticas. As peças incorporam elementos simbólicos da cultura sergipana, como o caju e a arara, além de referências a personagens históricos do Nordeste, a exemplo de Lampião e Maria Bonita. Cada criação expressa, por meio de formas, cores e materiais, aspectos da memória social e dos costumes locais.
A Orlinha do Bairro Industrial complementa essa experiência cultural ao oferecer infraestrutura para lazer e contemplação. O espaço dispõe de áreas para caminhada, pontos de observação do pôr do sol sobre o Rio Sergipe e estabelecimentos gastronômicos nas proximidades. Inserida em região historicamente associada ao distrito industrial, a orla ribeirinha configura-se como contraponto paisagístico e ambiental, funcionando como área de convivência e qualificação do espaço público.','A visita ao Centro de Artesanato pode, assim, integrar-se a um roteiro pela Orlinha, articulando cultura, natureza e lazer em um mesmo percurso. O conjunto reforça a valorização dos espaços públicos, o estímulo à economia criativa e a promoção de experiências autênticas às margens do Rio Sergipe, contribuindo para o fortalecimento da imagem cultural da capital sergipana.
Elaboração própria, com base em informações institucionais da Prefeitura de Aracaju e Sergipe Turismo.','The Centro de Artesanato Chica Chaves is situated along the banks of the Sergipe River, in one of Aracaju’s most distinctive urban areas: the Orlinha of the Industrial District. This location is known for its beautiful river views, public gathering spaces, and walking paths, making it a popular meeting point for both residents and visitors seeking outdoor leisure activities and the riverside landscape.
Inaugurated in March 2005, the Craft Center was established to promote and market Sergipe’s artisanal production. It features permanent exhibitions and sales of handcrafted items created by local artisans, helping to generate income and strengthen the region’s cultural identity. This initiative plays a vital role in preserving traditional knowledge and incorporating handicrafts into the city’s tourism circuit.','The collection showcases various techniques, including hand embroidery, Irish lace, crochet, vagonite embroidery, fabric painting, biscuit craft, ceramics, handmade cloth dolls, and thematic sculptures. Each piece incorporates symbolic elements of Sergipe’s culture, such as the cashew fruit and the macaw, as well as references to historical figures from Brazil’s Northeast, like Lampião and Maria Bonita. Through their shapes, colors, and materials, these creations express important aspects of local memory and traditions.
The Orlinha of the Industrial District enhances this cultural experience by providing infrastructure for leisure and contemplation. The area features walking paths, sunset viewpoints overlooking the Sergipe River, and nearby dining establishments. Although located in a region historically associated with the industrial district, the riverside promenade serves as a landscape and environmental counterpoint, functioning as a public space for social interaction and urban enhancement.','A visit to the Craft Center can therefore be combined with a stroll along the Orlinha, bringing together culture, nature, and leisure within a single itinerary. The complex reinforces the value of public spaces, supports the creative economy, and promotes authentic experiences along the banks of the Sergipe River, thereby strengthening the capital’s cultural image.','Ubicado a orillas del río Sergipe, el Centro de Artesanato Chica Chaves forma parte de uno de los escenarios urbanos más representativos de la capital: la Orlinha del Barrio Industrial, en Aracaju. El área combina vistas privilegiadas del río, espacios de convivencia y senderos para caminatas, y se ha consolidado como punto de encuentro para residentes y visitantes que buscan ocio al aire libre y contacto con el paisaje ribereño.
Inaugurado en marzo de 2005, el Centro de Artesanía fue concebido como un equipamiento destinado a promover y comercializar la producción artesanal de Sergipe. El espacio reúne una exposición permanente y la venta de piezas elaboradas por artesanas locales, fomentando la generación de ingresos y el fortalecimiento de la identidad cultural regional. La iniciativa contribuye a la preservación de saberes tradicionales y a la inserción de la artesanía en el circuito turístico de la ciudad.','Entre las técnicas representadas se destacan el bordado a mano, el encaje irlandés, el crochet, el bordado vagonite, la pintura en tela, los trabajos en biscuit, la cerámica, las muñecas de tela y las esculturas temáticas. Las piezas incorporan elementos simbólicos de la cultura sergipana, como el anacardo y la guacamaya, así como referencias a figuras históricas del Nordeste brasileño, como Lampião y Maria Bonita. A través de formas, colores y materiales, cada creación expresa aspectos de la memoria y de las tradiciones locales.
La Orlinha del Barrio Industrial amplía esta experiencia cultural al ofrecer infraestructura para el ocio y la contemplación. El espacio dispone de senderos para caminar, puntos de observación del atardecer sobre el río Sergipe y establecimientos gastronómicos en las cercanías. Aunque se encuentra en una región históricamente asociada al distrito industrial, el paseo ribereño funciona como contrapunto paisajístico y ambiental, consolidándose como un espacio público de convivencia y valorización urbana.','La visita al Centro de Artesanía puede integrarse a un recorrido por la Orlinha, articulando cultura, naturaleza y ocio en un mismo itinerario. El conjunto refuerza la valorización de los espacios públicos, impulsa la economía creativa y promueve experiencias auténticas a orillas del río Sergipe, contribuyendo al fortalecimiento de la imagen cultural de la capital sergipana.','cultura',-10.89752180,-37.04875350,'Av. Gen. Calazans, 351-365 - Industrial, Aracaju - SE, 49065-510','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/eb688813-c30a-425d-846f-0ce8f6ec21fa.jpg','','qr-9b631f88-281d-4b01-826f-f3998aa063d9','https://maps.app.goo.gl/snHJ5iGxEBwXKXwp6',true,'',true,true,'','{}'::jsonb,'2025-11-25 15:27:33.351525+00','2026-03-02T16:57:19.679Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('5c504d72-1ee1-494b-967b-9ad789954db2','Parque da Cidade','City Park','Parque de la Ciudad','Inaugurado em 1979, o Parque da Cidade, oficialmente denominado Parque José Rollemberg Leite, constitui um dos principais espaços públicos de lazer, de natureza e de turismo de Aracaju. Localizado no bairro Industrial, o equipamento ocupa aproximadamente 600 mil m² de área verde e integra preservação ambiental, educação ecológica e infraestrutura de convivência em um único complexo. Inserido em área remanescente de Mata Atlântica, o parque desempenha função estratégica na proteção de um dos biomas mais biodiversos do país. Ao longo das décadas, passou por intervenções de revitalização que ampliaram suas estruturas e consolidaram sua relevância como referência ambiental da capital sergipana.
Entre seus principais atrativos destaca-se o teleférico, com cerca de 600 metros de extensão, que conecta a base à área mais elevada do parque. O percurso proporciona uma vista panorâmica da cidade, do Rio Sergipe e da vegetação nativa, agregando valor paisagístico à experiência de visitação. A atividade é acessível a diferentes faixas etárias e integra o conjunto de elementos que qualificam o parque como um ponto de contemplação e observação urbana.','O parque dispõe ainda de trilhas ecológicas sinalizadas, com aproximadamente 2 km (ida e volta), adequadas para leves caminhadas, observação de aves e contato direto com a natureza. O trajeto, com duração média entre 30 e 45 minutos, percorre áreas sombreadas e mirantes naturais, permitindo ao visitante conhecer aspectos da flora e da fauna associadas à Mata Atlântica. Entre as espécies vegetais observáveis estão ipês, bromélias e ingazeiras, enquanto a avifauna inclui sabiás, bem-te-vis e beija-flores.
A estrutura também contempla um minizoológico que abriga animais resgatados, desempenhando uma função educativa ao aproximar o público da biodiversidade regional. Complementam o conjunto de equipamentos, como playground infantil, jardins, áreas de convivência, praça de eventos e quiosques. O espaço recebe escolas e grupos organizados para atividades de educação ambiental, reforçando seu papel formativo e de sensibilização ecológica.','Inserido em um contexto climático tropical, com temperaturas médias anuais entre 24 °C e 30 °C, o período de agosto a fevereiro tende a apresentar menor incidência de chuvas, o que favorece a visitação. Próximo à região central e de fácil acesso, o parque configura-se como um importante refúgio verde na área urbana, articulando lazer, preservação ambiental e valorização paisagística no território municipal.
Elaboração própria, com base em informações institucionais do Parque da Cidade.','Inaugurated in 1979, the Parque da Cidade (City Park), officially named José Rollemberg Leite Park, is one of the main public spaces for leisure, nature, and tourism in Aracaju. Located in the Industrial neighborhood, the park covers approximately 600,000 square meters of green area and integrates environmental preservation, ecological education, and public-use infrastructure within a single complex. Situated in a remnant area of the Atlantic Forest, it plays a strategic role in protecting one of Brazil’s most biodiverse biomes. Over the decades, revitalization initiatives have expanded its facilities and consolidated its position as an environmental landmark in the state capital.
One of its main attractions is the cable car system, approximately 600 meters long, which connects the base to the park’s highest area. The ride offers panoramic views of the city, the Sergipe River, and native vegetation, enhancing the scenic experience for visitors. The activity is accessible to people of different ages and contributes to the park’s role as a space for contemplation and urban observation.','The park also features marked ecological trails totaling approximately 2 kilometers (round trip), suitable for light hiking, birdwatching, and direct contact with nature. The route, which takes an average of 30 to 45 minutes, passes through shaded areas and natural viewpoints, allowing visitors to observe elements of the flora and fauna associated with the Atlantic Forest. Plant species include ipê trees, bromeliads, and ingá trees, while commonly sighted birds include thrushes, great kiskadees, and hummingbirds.
In addition, the park includes a small zoo that shelters rescued animals and fulfills an educational function by bringing visitors closer to regional biodiversity. Complementary facilities include a children’s playground, gardens, social areas, an event square, and kiosks. The park regularly hosts schools and organized groups for environmental education activities, reinforcing its formative and awareness-raising role.','Located in a tropical climate zone, with average annual temperatures ranging from 24°C to 30°C, the period from August to February generally experiences lower rainfall, favoring visitation. Close to the city center and easily accessible, the park serves as an important green refuge within the urban area, combining leisure, environmental preservation, and landscape appreciation within the municipal territory.
Prepared by the author, based on institutional information from Parque da Cidade.','Inaugurado en 1979, el Parque da Cidade, oficialmente denominado Parque José Rollemberg Leite, es uno de los principales espacios públicos de ocio, naturaleza y turismo de Aracaju. Ubicado en el barrio Industrial, el parque ocupa aproximadamente 600.000 m² de área verde e integra preservación ambiental, educación ecológica e infraestructura de uso público en un mismo complejo. Situado en un área remanente de la Mata Atlántica, desempeña un papel estratégico en la protección de uno de los biomas más biodiversos de Brasil. A lo largo de las décadas, las intervenciones de revitalización ampliaron sus equipamientos y consolidaron su relevancia como referencia ambiental de la capital sergipana.
Entre sus principales atractivos se encuentra el teleférico, con cerca de 600 metros de extensión, que conecta la base con la zona más elevada del parque. El recorrido ofrece una vista panorámica de la ciudad, del río Sergipe y de la vegetación nativa, aportando valor paisajístico a la experiencia de visita. La actividad es accesible a distintos grupos etarios y refuerza el carácter del parque como espacio de contemplación y observación urbana.','El parque también cuenta con senderos ecológicos señalizados que suman aproximadamente 2 kilómetros (ida y vuelta), adecuados para caminatas leves, la observación de aves y el contacto directo con la naturaleza. El trayecto, con una duración promedio de 30 a 45 minutos, atraviesa áreas sombreadas y miradores naturales, lo que permite conocer elementos de la flora y fauna propias de la Mata Atlántica. Entre las especies vegetales se encuentran ipês, bromelias e ingazeiras, y entre las aves más frecuentes se observan zorzales, benteveos y colibríes.
Asimismo, el parque dispone de un pequeño zoológico que alberga animales rescatados y cumple una función educativa al acercar al público a la biodiversidad regional. El conjunto se complementa con parque infantil, jardines, áreas de convivencia, plaza de eventos y quioscos. El espacio recibe escuelas y grupos organizados para actividades de educación ambiental, reforzando su papel formativo y de sensibilización ecológica.','Insertado en una zona de clima tropical, con temperaturas medias anuales entre 24 °C y 30 °C, el período de agosto a febrero suele presentar una menor incidencia de lluvias, lo que favorece la visita. Próximo al centro y de fácil acceso, el parque se configura como un importante refugio verde en el área urbana, articulando ocio, preservación ambiental y valorización paisajística en el territorio municipal.
Elaboración propia, basada en información institucional del Parque da Cidade.','historico',-10.89016390,-37.05394310,'Parque Gov. José Rolemberg Leite IV - Porto D''antas, Aracaju - SE, 49065-410','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/442c77e8-2ca7-4691-a640-ca3cf470dca6.jpeg','','qr-a497ba0c-c4c5-4799-9acc-f0baeb8ad3e9','https://maps.app.goo.gl/EjsaNi4GSWs9eQGw9',true,'Atualmente está fechado para reformas',false,false,'','{}'::jsonb,'2025-11-25 15:31:17.87009+00','2026-03-02T16:40:40.419Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('94eb97fe-a125-4283-ab64-47bc0eba0286','Colina do Santo Antônio','Santo Antônio Hill','La Colina de Santo Antônio','A Colina do Santo Antônio constitui o primeiro núcleo de ocupação urbana que deu origem à cidade de Aracaju. Situada em área elevada, com ampla visualização do território e proximidade ao rio Sergipe, a região apresentava condições estratégicas que favoreceram sua escolha no contexto da transferência da capital provincial. À época, já existia o povoado de Santo Antônio, pertencente ao município de Socorro, elevado à categoria de cidade por meio da Resolução nº 413, de 17 de março de 1855.
Foi nesse cenário que ocorreu a reunião da Assembleia Provincial responsável por deliberar sobre a mudança da capital de São Cristóvão para Aracaju, decisão que marcou a reorganização político-administrativa do estado. A escolha da nova sede esteve associada, entre outros fatores, à busca por melhores condições portuárias e à possibilidade de expansão urbana planejada, elementos que fundamentaram o projeto da nova capital.','No período inicial, a Colina do Santo Antônio era composta por poucas edificações, predominantemente casas simples de pescadores, e por uma capela de taipa dedicada a Santo Antônio. Com o passar do tempo, a estrutura original foi substituída pela atual Igreja de Santo Antônio, que se consolidou como referência religiosa, histórica e cultural da cidade. Anualmente, em 13 de junho, o local recebe celebrações dedicadas ao padroeiro, reunindo fiéis e visitantes em manifestações de fé e de tradição popular.','Atualmente, a igreja permanece em pleno funcionamento e a colina configura-se como um ponto turístico de relevância histórica e paisagística. Além de seu valor simbólico como berço da capital sergipana, o espaço oferece vista panorâmica da cidade, permitindo, a partir de sua elevação, compreender o processo de expansão urbana que transformou o antigo povoado em capital planejada do estado.
Elaboração própria, com base em registros históricos da Prefeitura de Aracaju.','Santo Antônio Hill is the site of the first urban settlement that led to the founding of the city of Aracaju. Situated on elevated ground, it offers a broad view of the surrounding area and is located close to the Sergipe River. This advantageous location played a crucial role during the transfer of the provincial capital. At that time, the village of Santo Antônio already existed, then part of the municipality of Socorro, and it was elevated to city status through Resolution No. 413 on March 17, 1855.
In this context, the Provincial Assembly convened to discuss the transfer of the capital from São Cristóvão to Aracaju. This decision marked a significant reorganization of the state’s political and administrative structure. The choice of the new capital was influenced by several factors, including the need for better port conditions and the potential for planned urban expansion—elements that guided the development of the emerging city.','In its early days, Santo Antônio Hill had only a few structures, primarily simple fishermen’s houses and a wattle-and-daub chapel dedicated to Saint Anthony. Over time, this original building was replaced by the current Igreja de Santo Antônio, which has become a significant religious, historical, and cultural landmark in the city. Every year, on June 13, the site hosts celebrations in honor of the saint, drawing together residents and visitors to express their faith and participate in popular traditions.','Today, the church remains fully active, and the hill stands as a site of historical and scenic significance. Beyond its symbolic value as the birthplace of the state capital, the location offers a privileged panoramic view of the city, allowing visitors to observe, from its elevated position, the process of urban expansion that transformed a small settlement into a planned capital.
Prepared by the author, based on historical records from the City of Aracaju.','La Colina de Santo Antônio constituye el primer núcleo de ocupación urbana que dio origen a la ciudad de Aracaju. Ubicada en un área elevada, con amplia visibilidad del territorio y proximidad al río Sergipe, la región presentaba condiciones estratégicas que favorecían su relevancia en el contexto del traslado de la capital provincial. En ese período ya existía el poblado de Santo Antônio, perteneciente al municipio de Socorro, elevado a la categoría de ciudad mediante la Resolución nº 413, del 17 de marzo de 1855.
Fue en este escenario donde se reunió la Asamblea Provincial para deliberar sobre el traslado de la capital de São Cristóvão a Aracaju, decisión que marcó una reorganización significativa de la estructura político-administrativa del estado. La elección de la nueva capital estuvo asociada, entre otros factores, a la búsqueda de mejores condiciones portuarias y a la posibilidad de una expansión urbana planificada, elementos que orientaron el desarrollo de la entonces naciente ciudad.','En su período inicial, la Colina de Santo Antônio contaba con pocas edificaciones, básicamente casas sencillas de pescadores y una capilla de tapia dedicada a San Antonio. Con el paso del tiempo, la estructura original fue sustituida por la actual Igreja de Santo Antônio, consolidada como referencia religiosa, histórica y cultural de la ciudad. Cada año, el 13 de junio, el lugar acoge celebraciones en honor al santo, que reúnen a fieles y visitantes en manifestaciones de fe y tradición popular.','Actualmente, la iglesia permanece en pleno funcionamiento y la colina se configura como un punto turístico de relevancia histórica y paisajística. Además de su valor simbólico como cuna de la capital sergipana, el sitio ofrece una vista panorámica privilegiada de la ciudad, lo que permite comprender, desde su elevación, el proceso de expansión urbana que transformó el antiguo poblado en una capital planificada del estado.
Elaboración propia, basada en registros históricos de la Prefeitura de Aracaju.','historico',-10.89712840,-37.05904770,'R. Cláudio Batista, 11 - Santo Antônio, Aracaju - SE, 49060-108','{}'::text[],'[]'::jsonb,'/uploads/tourist-images/05992ed2-4efd-44a3-a75a-08eed89429a2.jpg','','qr-8d203752-0a8b-4f94-9f26-645c84896c04','https://maps.app.goo.gl/aq8P8hyhAdnfZUSq5',true,'',false,true,'','{}'::jsonb,'2025-11-25 15:35:49.15894+00','2026-03-02T15:19:47.203Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('ebb9e16b-ce39-4600-a317-ca601ff52587','Igreja dos Capuchinhos','Capuchin Church ','Iglesia de los Capuchinos','A Praça Frei Miguel Serafini, popularmente conhecida como Praça dos Capuchinhos, no bairro América, passou por ampla requalificação urbana e foi reinaugurada em 2025, apresentando nova configuração estética e funcional. Espaço historicamente vinculado à memória afetiva da comunidade, a praça assume agora um papel ainda mais estratégico como área de convivência, expressão cultural e valorização da identidade religiosa local.
A intervenção contemplou a reurbanização completa, com reorganização do paisagismo, recuperação estrutural, implantação de novos equipamentos de lazer e adequações voltadas à acessibilidade. O espaço passou a integrar elementos de arte urbana, áreas de permanência, parque infantil e melhorias na iluminação, criando um ambiente mais seguro, acolhedor e funcional para moradores e visitantes.','Um dos principais destaques da revitalização é o diálogo direto entre a praça e a religiosidade que marca o entorno, especialmente pela proximidade com o Santuário São Judas Tadeu, conhecido como Igreja dos Capuchinhos. O projeto incorporou intervenções artísticas que fazem referência à espiritualidade e à história local, integrando arte, fé e uso urbano em uma mesma paisagem. O anfiteatro e a arquibancada, tradicionalmente utilizados em celebrações e encenações religiosas, como a Paixão de Cristo, foram reorganizados para fortalecer essa vocação cultural e comunitária.
A escadaria que conecta a praça ao santuário tornou-se símbolo da transformação. Além de receber tratamento artístico, foi adaptada para garantir acessibilidade, ampliando o uso democrático do espaço. As cores aplicadas no conjunto arquitetônico foram escolhidas para proporcionar uma sensação de acolhimento e bem-estar, equilibrando tons que remetem à serenidade, espiritualidade e vitalidade, especialmente nas áreas destinadas às crianças.','A história da praça está intrinsecamente ligada à presença dos Franciscanos Capuchinhos em Sergipe. O Santuário São Judas Tadeu teve sua construção iniciada na década de 1960 e consolidou-se como um importante centro de fé e ação social no estado. Fundado por Frei Miguelângelo Serafini de Cingoli, o templo tornou-se referência religiosa e comunitária, atraindo fiéis de diversas regiões e mantendo uma atuação social significativa por meio de iniciativas assistenciais.
Assim, a Praça dos Capuchinhos reafirma-se como um espaço que transcende a função urbanística. Mais do que área de lazer, constitui território de memória, espiritualidade e convivência social, fortalecendo o sentimento de pertencimento no bairro América e consolidando-se como novo ponto de referência cultural e paisagística de Aracaju.
Elaboração própria, com base em informações da Prefeitura de Aracaju (2026).','Praça Frei Miguel Serafini, popularly known as Praça dos Capuchinhos, located in the América neighborhood, underwent a comprehensive urban redevelopment and was reopened in 2025 with a renewed aesthetic and functional configuration. Historically connected to the community’s collective memory, the square now assumes an even more strategic role as a space for social interaction, cultural expression, and the appreciation of local religious identity.
The intervention included complete urban renewal, with redesigned landscaping, structural restoration, installation of new leisure equipment, and accessibility improvements. The space now integrates elements of urban art, gathering areas, a children’s playground, and enhanced lighting, creating a safer, more welcoming, and functional environment for residents and visitors.','One of the highlights of the revitalization is the direct dialogue between the square and the religious character of its surroundings, particularly due to its proximity to the São Judas Tadeu Sanctuary, known as the Capuchin Church. The project incorporated artistic interventions referencing spirituality and local history, blending art, faith, and urban use into a unified landscape. The amphitheater and bleachers, traditionally used for religious celebrations and performances such as the Passion of Christ, were reorganized to strengthen this cultural and community-oriented vocation.
The staircase connecting the square to the sanctuary became a symbol of transformation. In addition to receiving artistic treatment, it was adapted to ensure accessibility, broadening the democratic use of the space. The colors applied to the architectural ensemble were carefully selected to evoke warmth and well-being, balancing tones associated with serenity, spirituality, and vitality, especially in areas designed for children.','The history of the square is intrinsically linked to the presence of the Franciscan Capuchins in Sergipe. The São Judas Tadeu Sanctuary began construction in the 1960s and consolidated itself as an important center of faith and social action in the state. Founded by Frei Miguelângelo Serafini de Cingoli, the temple became a religious and community reference point, attracting worshippers from different regions and sustaining significant social outreach initiatives.
Thus, Praça dos Capuchinhos reaffirms itself as a space that transcends its urban function. More than a leisure area, it represents a territory of memory, spirituality, and social coexistence, strengthening the sense of belonging in the América neighborhood and establishing itself as a new cultural and landscape landmark of Aracaju.
Prepared by the author, based on information from the City of Aracaju (2026).','La Praça Frei Miguel Serafini, popularmente conocida como Praça dos Capuchinhos, en el barrio América, pasó por una amplia requalificación urbana y fue reinaugurada en 2025 con una nueva configuración estética y funcional. Espacio históricamente vinculado a la memoria afectiva de la comunidad, la plaza asume ahora un papel aún más estratégico como área de convivencia, de expresión cultural y de valorización de la identidad religiosa local.
La intervención contempló una reurbanización completa, con la reorganización del paisajismo, la recuperación estructural, la instalación de nuevos equipamientos de ocio y las adecuaciones orientadas a la accesibilidad. El espacio pasó a integrar elementos de arte urbano, áreas de permanencia, un parque infantil y mejoras en la iluminación, creando un ambiente más seguro, acogedor y funcional para residentes y visitantes.','Uno de los principales destaques de la revitalización es el diálogo directo entre la plaza y la religiosidad que caracteriza su entorno, especialmente por su proximidad al Santuario São Judas Tadeu, conocido como Iglesia de los Capuchinos. El proyecto incorporó intervenciones artísticas que aluden a la espiritualidad y a la historia local, integrando arte, fe y uso urbano en un mismo paisaje. El anfiteatro y las graderías, tradicionalmente utilizados en celebraciones y representaciones religiosas como la Pasión de Cristo, fueron reorganizados para fortalecer esta vocación cultural y comunitaria.
La escalinata que conecta la plaza con el santuario se convirtió en un símbolo de la transformación. Además de recibir tratamiento artístico, fue adaptada para garantizar la accesibilidad y ampliar el uso democrático del espacio. Los colores aplicados al conjunto arquitectónico fueron seleccionados para proporcionar una sensación de acogida y bienestar, equilibrando tonos que remiten a la serenidad, la espiritualidad y la vitalidad, especialmente en las áreas destinadas a los niños.','La historia de la plaza está intrínsecamente ligada a la presencia de los Franciscanos Capuchinos en Sergipe. El Santuario São Judas Tadeu comenzó su construcción en la década de 1960 y se consolidó como un importante centro de fe y de acción social en el estado. Fundado por Frei Miguelângelo Serafini de Cingoli, el templo se convirtió en una referencia religiosa y comunitaria, atrayendo fieles de diversas regiones y manteniendo una significativa actuación social mediante iniciativas asistenciales.
Así, la Praça dos Capuchinhos se reafirma como un espacio que trasciende su función urbanística. Más que un área de ocio, constituye un territorio de memoria, espiritualidad y convivencia social, fortaleciendo el sentimiento de pertenencia en el barrio América y consolidándose como un nuevo punto de referencia cultural y paisajística de Aracaju.
Elaboración propia, basada en información de la Prefeitura de Aracaju (2026).','cultura',-10.91476830,-37.08111870,'','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/36d29ee2-1194-4166-9c56-381fa628c237", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "inline-1", "url": "/objects/uploads/22bc0ff1-151c-4f07-9e06-5f957724166a", "type": "inline", "order": 1, "inlinePosition": 2}]'::jsonb,'/objects/uploads/8968c264-b23b-48b9-8fee-ffd19b04599f','','qr-0a0d9690-1f32-4d16-9a3b-07cde5d7673a','',true,'',false,true,'','{}'::jsonb,'2025-11-25 15:44:33.720193+00','2026-03-02T15:19:03.342Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO tourist_spots (id,name_pt,name_en,name_es,description_pt,description_pt_2,description_pt_3,description_en,description_en_2,description_en_3,description_es,description_es_2,description_es_3,category,latitude,longitude,address,images,image_gallery,cover_image,video_url,qr_code,google_maps_link,is_active,opening_hours,is_24_hours,is_free,entry_fee,features,created_at,updated_at) VALUES ('37d281a8-8b33-49b1-9c73-827e248f2c37','Escultura Formas e Cores','Sculpture Shapes and Colors','Escultura Formas y Colores','Ao caminhar pela Orla de Atalaia no fim da tarde, o som do mar e a brisa constante acompanham quem percorre a avenida para observar o pôr do sol. Entre ciclistas, famílias e visitantes que registram o momento, a arte também ocupa lugar no percurso e passa a integrar a experiência urbana.
É nesse ambiente que se encontra a escultura Formas e Cores, instalada na região da Cinelândia, na Avenida Santos Dumont. Criada pelo artista sergipano Joubert Moraes, a obra integra o conjunto de intervenções artísticas permanentes da orla. Sua estrutura vazada, combinada a um sistema de iluminação, convida o público a circular ao redor da peça, explorar diferentes ângulos e utilizá-la como ponto de referência visual, especialmente à noite.
','A instalação foi viabilizada com recursos da Lei Aldir Blanc, no contexto das políticas públicas de fomento cultural implementadas para ampliar a presença da arte no espaço urbano. A iniciativa permitiu incorporar novas obras à Orla de Atalaia, fortalecendo o acesso da população e dos visitantes à produção artística contemporânea.
Com trajetória consolidada nas artes visuais de Sergipe, Joubert Moraes desenvolve trabalhos que dialogam com o território e a paisagem locais. Em Formas e Cores, esse diálogo se materializa em uma proposta que aproxima a arte do cotidiano, inserindo a escultura na dinâmica diária da cidade.','Mais do que um elemento decorativo, a obra contribui para qualificar o espaço público e para diversificar os atrativos culturais da orla. Ao integrar cultura, paisagem e convivência, a Orla de Atalaia reafirma seu papel como ambiente de lazer, circulação e fruição artística, acessível a moradores, visitantes nacionais, turistas internacionais e ao público interessado na produção cultural contemporânea.
Elaboração própria, com base em informações institucionais e em registros sobre a obra e o artista.
','Late afternoon along Atalaia Waterfront unfolds at an unhurried pace. The sound of the waves and the steady sea breeze frame the experience as people walk, cycle, pause for the sunset, and capture the light over the ocean. In this setting, public art becomes part of the landscape, adding another layer to the city’s experience.
In the Cinelândia area, on Avenida Santos Dumont, the sculpture Formas e Cores stands among the permanent artworks installed along the waterfront. Created by Sergipe-born visual artist Joubert Moraes, the piece was designed to invite direct engagement. Its open structure and integrated lighting encourage visitors to move around it, explore shifting perspectives, and use it as a visual landmark—particularly striking after dark.
','The installation was made possible through cultural funding provided under Brazil’s Aldir Blanc Law, part of broader public policies aimed at expanding access to the arts and strengthening cultural production. Through initiatives like this, new public artworks have been incorporated into Atalaia Waterfront, reinforcing the presence of contemporary art in everyday urban life.
With decades of experience in Sergipe’s visual arts scene, Joubert Moraes is known for works that engage with local identity and territory. In Formas e Cores, that dialogue takes shape in the open-air environment of the waterfront, where art naturally intersects with daily routines.
','More than a standalone monument, the sculpture contributes to the area’s cultural fabric. By bringing together landscape, public space, and artistic expression, Atalaia Waterfront continues to affirm its role as a place for leisure, circulation, and cultural experience—welcoming residents, national visitors, international travelers, and those interested in Brazil’s contemporary artistic landscape.
Prepared based on institutional information and documented records about the artwork and the artist.
','Al final de la tarde, la Orla de Atalaia adquiere un ritmo propio. El sonido del mar y la brisa constante acompañan a quienes caminan, pedalean o se detienen para contemplar el atardecer y registrar la luz sobre el océano. En ese entorno, el arte público se integra de manera natural al paisaje y amplía la forma en que se vive la ciudad.
En la zona de la Cinelândia, sobre la Avenida Santos Dumont, se encuentra la escultura Formas e Cores, parte del conjunto de obras permanentes instaladas a lo largo de la orla. Creada por el artista visual sergipano Joubert Moraes, la pieza fue concebida para propiciar la interacción directa con el público. Su estructura abierta y el sistema de iluminación incorporado invitan a recorrerla desde distintos ángulos y la convierten en un punto de referencia visual, especialmente durante la noche.','La escultura Formas y Colores, del artista plástico sergipano Joubert Moraes, se encuentra en la región de Cinelândia, en la Avenida Santos Dumont. La obra fue concebida para promover la interacción directa con el público, presentando características intuitivas e interactivas. Su estructura cuenta con espacios abiertos y un sistema de iluminación, lo que permite que los visitantes exploren visualmente la pieza y utilicen el monumento como escenario para fotografías, especialmente durante la noche. La escultura fue inaugurada en el marco de políticas públicas de fomento cultural, viabilizadas con recursos de la Ley Aldir Blanc, que posibilitaron la instalación de nuevas obras de arte público en la Orla de Atalaia.
La obra también forma parte de la trayectoria artística de Joubert Moraes, artista con décadas de presencia en las artes visuales sergipanas, reconocido por su contribución a la cultura local a través de pinturas, esculturas y otras expresiones artísticas. La instalación de la escultura en la orla refuerza la presencia del arte en el espacio urbano y amplía el acceso de la población a la producción cultural contemporánea.','Visitar la escultura Formas y Colores es vivir la propuesta de acercamiento entre el arte y la vida cotidiana. El monumento refuerza el carácter democrático del espacio público, transformando la orla no solo en un área de ocio y turismo, sino también en un espacio de disfrute artístico, de contemplación y de experiencia estética. En este sentido, la obra contribuye a fortalecer la identidad cultural local y amplía la diversidad de atractivos disponibles para residentes y visitantes, consolidando la Orla de Atalaia como un territorio donde cultura, paisaje y convivencia urbana se conectan de manera orgánica.
Elaboración propia, basada en información institucional y en registros sobre la obra y el artista.','cultura',-10.99745520,-37.05491860,'Av. Santos Dumont - Atalaia, Aracaju - SE, 49035-785','{}'::text[],'[{"id": "inline-0", "url": "/objects/uploads/15e1b685-b9f3-4c42-9a43-0eda15bf95a1", "type": "inline", "order": 0, "inlinePosition": 1}, {"id": "gallery-0", "url": "/objects/uploads/9e2644a4-cecc-47d1-a5c3-47cfd00dcd0e", "type": "gallery", "order": 1}]'::jsonb,'/objects/uploads/923184f3-bcff-4cc0-946e-f752cfefcad1','','qr-5b04c214-02c6-4a60-888a-b01506cee5f1','https://share.google/bsqtfQ0bT16nvi9rU',true,'',true,true,'','{}'::jsonb,'2025-11-25 15:54:25.157838+00','2026-02-28T23:12:06.022Z') ON CONFLICT (id) DO NOTHING;

